    public static String getFormattedSignification(int[] sig) {
        String result = "";
        for (int i = 0; i < sig.length; i++) {
            if (sig[i] != 0)
                result += String.valueOf(sig[i]) + " ";
        }
        return result.trim();
    }

    public static String getFormattedShodashAndAshtak(int[] shodashOrAshtak) {
        String result = "";
        for (int i = 0; i < shodashOrAshtak.length; i++) {
            result += String.valueOf(shodashOrAshtak[i]) + ",";
        }
        return result.trim();
    }

    /**
     * This function convert double value in to degree-minute format string.
     *
     * @param _fDeg
     * @return String
     */
    public static String FormatDegreeInDDMM(double _fDeg) {
        String strFormattedDeg = null;
        String sDeg = null;
        String sMin = null;

        double fDeg = _fDeg;
        fDeg = (fDeg % 30.00);
        sDeg = String.valueOf((int) (fDeg));
        if (sDeg.trim().length() < 2)
            strFormattedDeg = "0" + sDeg;
        else
            strFormattedDeg = sDeg;
        // strFormattedDeg=strFormattedDeg+"?";
        strFormattedDeg = strFormattedDeg + getDegreeSign();

        fDeg = fDeg - (int) fDeg;
        fDeg *= 60.00;
        sMin = String.valueOf((int) (fDeg));

        if (sMin.trim().length() < 2)
            strFormattedDeg = strFormattedDeg + "0" + sMin;
        else
            strFormattedDeg = strFormattedDeg + sMin;
        // strFormattedDeg=strFormattedDeg+"."+String.valueOf((int)(fDeg))
        // strFormattedDeg=strFormattedDeg+"'";

        return strFormattedDeg;
    }

