    /**
     * This function is used to return formatted deg,min ,sec according to
     * passed language.
     *
     * @param _fDeg
     * @param LANGUAGE_CODE
     * @return 07-May-2015
     */
    public static String FormatDegreeInDDMMSS(double _fDeg, int LANGUAGE_CODE) {
        String strFormattedDeg = null;
        String sDeg = null;
        String sMin = null;
        String sSec = null;
        double temp = (_fDeg - (double) ((int) _fDeg));
        double fDeg = _fDeg;
        fDeg = (fDeg % 30.00);
        sDeg = String.valueOf((int) (fDeg));
        if (sDeg.trim().length() < 2)
            strFormattedDeg = "0" + sDeg;
        else
            strFormattedDeg = sDeg;
        // strFormattedDeg=strFormattedDeg+"?";
        strFormattedDeg = strFormattedDeg + getDegreeSign();

        fDeg = fDeg - (int) fDeg;
        fDeg *= 60.00;
        sMin = String.valueOf((int) (fDeg));

        if (sMin.trim().length() < 2)
            strFormattedDeg = strFormattedDeg + "0" + sMin;
        else
            strFormattedDeg = strFormattedDeg + sMin;

        strFormattedDeg = strFormattedDeg + getMinuteSign(LANGUAGE_CODE);
        // strFormattedDeg=strFormattedDeg+"."+String.valueOf((int)(fDeg))
        // strFormattedDeg=strFormattedDeg+"'";

        temp = temp * 60;
        temp = (temp - (double) ((int) temp));
        temp = (int) (temp * 60);
        sSec = String.valueOf((int) (temp));

        if (sSec.trim().length() < 2)
            strFormattedDeg = strFormattedDeg + "0" + sSec;
        else
            strFormattedDeg = strFormattedDeg + sSec;

        strFormattedDeg = strFormattedDeg + getSecondSign(LANGUAGE_CODE);

        return strFormattedDeg.trim();
    }

