    /**
     * This function convert degree-minute-second(double) with sign in to
     * formatted string.
     *
     * @param _fDeg
     * @return String
     */
    // ADDED BY BIJENDRA
    public static String FormatDMSInStringWithSign(double _fDeg,
                                                   String DegSign, String MinSign, String SecSign) {
        String strFormattedDeg = null;
        String sDeg = null;
        String sMin = null;
        String sSec = null;
        int _min = 0, _sec = 0;
        double temp = 0;
        double fDeg = _fDeg;
        // fDeg =(float) (fDeg%30.00);
        sDeg = String.valueOf((int) (fDeg));
        switch (sDeg.trim().length()) {
            case 0:
                strFormattedDeg = "000" + sDeg;
                break;
            case 1:
                strFormattedDeg = "00" + sDeg;
                break;
            case 2:
                strFormattedDeg = "0" + sDeg;
                break;
            default:
                strFormattedDeg = sDeg;
                break;
        }

        // strFormattedDeg=strFormattedDeg+getDegreeSign();
        strFormattedDeg = strFormattedDeg + DegSign;
        temp = (_fDeg - (double) ((int) _fDeg));
        _min = (int) (temp * 60);
        sMin = String.valueOf(_min);

        // fDeg=fDeg-(int)fDeg;
        // fDeg *=60.00;
        // sMin=String.valueOf((int)(fDeg));

        if (sMin.trim().length() < 2)
            strFormattedDeg = strFormattedDeg + "0" + sMin;
        else
            strFormattedDeg = strFormattedDeg + sMin;

        // strFormattedDeg=strFormattedDeg+"'";
        // strFormattedDeg=strFormattedDeg+CGlobalVariables.MINUTE_SIGN;
        strFormattedDeg = strFormattedDeg + MinSign;

        temp = temp * 60;
        temp = (temp - (double) ((int) temp));
        _sec = (int) (temp * 60);
        // fDeg=fDeg-(int)fDeg;
        // fDeg *=60.00;
        sSec = String.valueOf(_sec);

        if (sSec.trim().length() < 2)
            strFormattedDeg = strFormattedDeg + "0" + sSec;
        else
            strFormattedDeg = strFormattedDeg + sSec;

        // strFormattedDeg=strFormattedDeg+"''";
        // strFormattedDeg=strFormattedDeg+CGlobalVariables.SECOND_SIGN;
        strFormattedDeg = strFormattedDeg + SecSign;

        return strFormattedDeg.trim();
    }

    /**
     * This function return the planet in which it is in RasiNakSubSub in
     * formatted string according to passed value(planet degree in double).
     *
     * @param d
     * @return String
     */
    public static String getRasiNakSubSub(double d, String[] RasiLord,
                                          String[] NakLord) {
        StringBuilder sb = new StringBuilder();
        int a, b, c, f, i = 0;
        /*
         * if(d<0) d *=-1;
         */

        f = (int) (d / 30.0);
        a = (int) (d / 120.0);
        d -= a * 120.0;
        a = (int) (d * 3.0 / 40.0);
        d -= a * 40.0 / 3.0;
        d *= 9;
        for (b = 0; b < 9; b++) {
            i = a + b;
            if (i >= 9)
                i -= 9;
            if (y1[i] <= d)
                d -= y1[i];
            else
                break;
        }
        b = i;
        d = d / y1[b] * (40.0 / 3.0);
        d *= 9;
        for (c = 0; c < 9; c++) {
            i = b + c;
            if (i >= 9)
                i -= 9;
            if (y1[i] <= d)
                d -= y1[i];
            else
                break;
        }
        c = i;
        /*
         * sb.append(CGlobalVariables.rasiLord[f] + "-");
         * sb.append(CGlobalVariables.nakLord[a] + "-");
         * sb.append(CGlobalVariables.nakLord[b] + "-");
         * sb.append(CGlobalVariables.nakLord[c]);
         */
        sb.append(RasiLord[f] + "-");
        sb.append(NakLord[a] + "-");
        sb.append(NakLord[b] + "-");
        sb.append(NakLord[c]);

        return sb.toString().trim();
    }

