    /**
     * This function return SubLord number for a passed degree.
     *
     * @param d
     * @return int
     */
    public static int getSubLordNumber(double d) {
        int a, b, i = 0;

        // f = (int) (d / 30.0);
        a = (int) (d / 120.0);
        d -= a * 120.0;
        a = (int) (d * 3.0 / 40.0);
        d -= a * 40.0 / 3.0;
        d *= 9;
        for (b = 0; b < 9; b++) {
            i = a + b;
            if (i >= 9)
                i -= 9;
            if (y1[i] <= d)
                d -= y1[i];
            else
                break;
        }
        b = i;

        return b;
    }

    /**
     * @param array
     * @return int[]
     * @author Bijendra 20-march-2013 This function is used to remove duplicate
     * values from array
     */
    public static int[] removeUpdatedDuplicates(int[] array) {

        if (array == null)
            return null;
        Arrays.sort(array);
        boolean hasDuplicate = false;
        ArrayList<Integer> list = new ArrayList<Integer>();

        for (int i = 0; i < array.length; i++) {
            hasDuplicate = false;
            for (int j = i + 1; j < array.length; j++)
                if (array[i] == array[j])
                    hasDuplicate = true;

            if (!hasDuplicate)
                list.add(array[i]);

        }

        int[] p = new int[list.size()];
        for (int k = 0; k < list.size(); k++)
            p[k] = list.get(k);

        return p;
    }

