    /**
     * This function return the charan number for a passed value(Planet degree)
     *
     * @param pl
     * @return int
     */
    public static int getPlntCharan(double pl) {
        double aa, a, b;
        int charan;
        aa = pl;
        a = aa / 30;
        b = aa * 3 / 40;
        charan = (int) (4 * fract(aa * 3.0 / 40)) + 1;
        return charan;

    }

    /**
     * This function convert year,month and day into formatted DDMMYYY string.
     *
     * @param iYear
     * @param iMonth
     * @param iDay
     * @return String
     */
    public static String FormatDateDDMMYYYY(int iYear, int iMonth, int iDay) {
        String strFormattedDate = null;

        if (iDay < 10)
            strFormattedDate = "0" + String.valueOf(iDay);
        else
            strFormattedDate = String.valueOf(iDay);

        if (iMonth < 10)
            strFormattedDate += "/" + "0" + String.valueOf(iMonth);
        else
            strFormattedDate += "/" + String.valueOf(iMonth);

        strFormattedDate += "/" + String.valueOf(iYear);

        return strFormattedDate;
    }

    /**
     * This function append 0 in the passed int value and return new value as a
     * string.
     *
     * @param c
     * @return String
     */
    public static String pad(int c) {
        if (c >= 10)
            return String.valueOf(c);
        else
            return "0" + String.valueOf(c);
    }

    /**
     * This function return date difference in days
     *
     * @param fYear
     * @param fMonth
     * @param fDay
     * @param tYear
     * @param tMonth
     * @param tDay
     * @return date difference in double(days)
     * @author Bijendra (20-june-13)
     */
    public static double getDateDifferencInDays(int fYear, int fMonth/* 1-12 */,
                                                int fDay, int tYear, int tMonth/* 1-12 */, int tDay) {
        double fDate = fYear + fMonth / 12.0 + fDay / 365.0;
        double tDate = tYear + tMonth / 12.0 + tDay / 365.0;
        double diff = tDate - fDate;
        return diff;
    }

    /**
     * This function
     *
     * @param bod
     * @return
     */
    public static int[] getDateFromDoubleToYMD(double bod) {
        int[] ymd = new int[3];
        ymd[2] = (int) (bod);// year
        ymd[1] = (int) (fract(bod) * 12);// month
        ymd[0] = (int) ((fract(fract(bod) * 12)) * 31);// day
        if (ymd[0] == 0)
            ymd[0] = 1;
        return ymd;
    }

    /**
     * This function change First letter into upper case for the passed string.
     *
     * @param str
     * @return String
     */

    public static String makeFirstLatterInCapitalInString(String str,
                                                          int LANGUAGE_CODE) {
        String _return = str;
        if (LANGUAGE_CODE == CGlobalVariables.ENGLISH) {
            String _fLetter = str.substring(0, 1);
            String _restString = str.substring(1, str.length());
            _fLetter = _fLetter.toUpperCase();

            _return = _fLetter + _restString.toLowerCase();
        }

        return _return;

    }

