    /**
     * This function is used to check that screen is book marked or not
     *
     * @param moduleId
     * @param screenId
     * @return boolean
     * @author Hukum
     */
    public static boolean isScreenBookMarked(Context context, int moduleId,
                                             int screenId) throws Exception {
        boolean _isBookMarked = false;
        int index = CBookMarkItemCollection.getBookMarkItemCollection(context).UserBookMarkedScreen
                .size();

        for (int i = 0; i < index; i++)
            if (moduleId == CBookMarkItemCollection
                    .getBookMarkItemCollection(context).UserBookMarkedScreen
                    .get(i).ModuleId
                    && screenId == CBookMarkItemCollection
                    .getBookMarkItemCollection(context).UserBookMarkedScreen
                    .get(i).ScreenId)
                _isBookMarked = true;
        return _isBookMarked;
    }

    /**
     * This function is used to add screen into book mark object
     *
     * @param activity
     * @param moduleId
     * @param screenId
     * @return addedToBookMarkList : if screen added to bookmark list, it return
     * true else false.
     * @throws IOException
     */
    public static boolean bookMarkOrUnBookMarkScreen(Activity activity,
                                                     int moduleId, int screenId) throws IOException, Exception {
        boolean addedToBookMarkList = false;
        MyCustomToast mct = new MyCustomToast(activity,
                activity.getLayoutInflater(), activity,
                getRobotoFont(activity
                                .getApplicationContext(),
                        getLanguageCodeFromPreference(activity
                                .getApplicationContext()), CGlobalVariables.regular));
        // IF BOOK MARKED
        if (isScreenBookMarked(activity, moduleId, screenId)) {
            removeBookMarkScreen(activity, moduleId, screenId);
            mct.show(activity.getResources().getString(
                    R.string.removed_from_bookmark));
            addedToBookMarkList = false;
        } else {// IF NOT BOOK MARKED
            addBookMarkScreen(activity, moduleId, screenId);
            mct.show(activity.getResources()
                    .getString(R.string.book_mark_saved));
            addedToBookMarkList = true;
        }
        // save Article Collection in file system
        SerializeAndDeserializeBeans.saveSerializedBeanObject(activity,
                CGlobalVariables.BOOKMARK_COLLECTION_FILE_NAME,
                CBookMarkItemCollection.getBookMarkItemCollection(activity));

        return addedToBookMarkList;
    }

    /**
     * This function is used to check that screen is book marked or not
     *
     * @param moduleId
     * @param screenId
     * @return boolean
     * @author Hukum
     */
    public static boolean isScreenBookMarked(Activity activity, int moduleId,
                                             int screenId) throws Exception {
        boolean _isBookMarked = false;
        int index = CBookMarkItemCollection.getBookMarkItemCollection(activity).UserBookMarkedScreen
                .size();

        for (int i = 0; i < index; i++)
            if (moduleId == CBookMarkItemCollection
                    .getBookMarkItemCollection(activity).UserBookMarkedScreen
                    .get(i).ModuleId
                    && screenId == CBookMarkItemCollection
                    .getBookMarkItemCollection(activity).UserBookMarkedScreen
                    .get(i).ScreenId)
                _isBookMarked = true;
        return _isBookMarked;
    }

    /**
     * This function is used to remove book marked screen from collection
     *
     * @param moduleId
     * @param screenId
     * @author Hukum
     */
    public static void removeBookMarkScreen(Context activity, int moduleId,
                                            int screenId) throws Exception {
        int deleteIndex = -1;
        int index = CBookMarkItemCollection.getBookMarkItemCollection(activity).UserBookMarkedScreen
                .size();

        for (int i = 0; i < index; i++)
            if (moduleId == CBookMarkItemCollection
                    .getBookMarkItemCollection(activity).UserBookMarkedScreen
                    .get(i).ModuleId
                    && screenId == CBookMarkItemCollection
                    .getBookMarkItemCollection(activity).UserBookMarkedScreen
                    .get(i).ScreenId)
                deleteIndex = i;

        if (deleteIndex > -1)
            CBookMarkItemCollection.getBookMarkItemCollection(activity).UserBookMarkedScreen
                    .remove(deleteIndex);
    }

