    public static void addBookMarkScreen(Activity activity, int moduleId,
                                         int screenId) throws Exception {
        CBookMarkItem bMark = new CBookMarkItem(moduleId, screenId);
        CBookMarkItemCollection.getBookMarkItemCollection(activity).UserBookMarkedScreen
                .add(bMark);
    }

    public static boolean isScreenInHistoryQueue(Context context, int moduleId,
                                                 int screenId) throws Exception {
        boolean isInHistory = false;
        int index = CScreenHistoryItemCollection
                .getScreenHistoryItemCollection(context).getHistory().size();

        for (int i = 0; i < index; i++)
            if (moduleId == CScreenHistoryItemCollection
                    .getScreenHistoryItemCollection(context).getHistory()
                    .get(i).ModuleId
                    && screenId == CScreenHistoryItemCollection
                    .getScreenHistoryItemCollection(context)
                    .getHistory().get(i).ScreenId)
                isInHistory = true;
        return isInHistory;
    }

    public static void gotoUserSelectedScreen(int group, int child,
                                              Activity activity) throws Exception {
        if (group == 0) {
            goToUserBookMarkHistoryScreen(CBookMarkItemCollection
                    .getBookMarkItemCollection(activity).UserBookMarkedScreen
                    .get(child).ModuleId, CBookMarkItemCollection
                    .getBookMarkItemCollection(activity).UserBookMarkedScreen
                    .get(child).ScreenId, activity);
        } else if (group == 1) {
            goToUserBookMarkHistoryScreen(
                    CScreenHistoryItemCollection
                            .getScreenHistoryItemCollection(activity)
                            .getHistory().get(child).ModuleId,
                    CScreenHistoryItemCollection
                            .getScreenHistoryItemCollection(activity)
                            .getHistory().get(child).ScreenId, activity);
        }
    }

    public static void goToUserBookMarkHistoryScreen(int myModuleIndex,
                                                     int myScreenIndex, Activity activity) {
        try {
            Intent intent = new Intent(activity, OutputMasterActivity.class);
            SharedPreferences sharedPreferences = activity
                    .getSharedPreferences(CGlobalVariables.APP_PREFS_NAME,
                            Context.MODE_PRIVATE);
            SharedPreferences sharedPreferencesForLang = activity
                    .getSharedPreferences(
                            CGlobalVariables.MYKUNDLI_LANGUAGE_PREFS_NAME,
                            Context.MODE_PRIVATE);
            intent.putExtra(CGlobalVariables.LANGUAGE_CODE,
                    sharedPreferencesForLang.getInt(
                            CGlobalVariables.APP_PREFS_AppLanguage,
                            CGlobalVariables.ENGLISH));
            intent.putExtra(CGlobalVariables.MODULE_TYPE_KEY, myModuleIndex);
            intent.putExtra(CGlobalVariables.SUB_MODULE_TYPE_KEY, myScreenIndex);
            intent.putExtra(CGlobalVariables.IS_NORTH_INDIAN, sharedPreferences
                    .getInt(CGlobalVariables.APP_PREFS_ChartStyle,
                            CGlobalVariables.CHART_NORTH_STYLE));
            ((Activity) activity).startActivity(intent);
            // //Log.e("Bijendra Here 1", "HashCodeSingleton");

            // ((Activity) activity).finish();
        } catch (Exception e) {
            // //Log.e("goToUserBookMarkScreen",e.getMessage());
        }
    }

