    /**
     * This function used to save image on SD card.
     *
     * @param conext
     * @param view
     * @param screenName
     * @param isShowAlert
     * @return String
     */
    public static String saveScreenImageInSD(Context conext, View view,
                                             String screenName, boolean isShowAlert) {
        String retURL = null;
        try {
            /*
             * String imageNameWithUserName =
             * CGlobalVariables._PersonInfo.getName() + "_" + screenName;
             */
            String imageNameWithUserName = CUtils.getRandomImageID();
            int quality = 100;

            // Toast.makeText(conext, imageNameWithUserName,
            // Toast.LENGTH_LONG).show();
            // Toast.makeText(conext,
            // String.valueOf(view.getWidth())+"<>"+String.valueOf(
            // view.getHeight()), Toast.LENGTH_LONG).show();

            Bitmap bm = Bitmap.createBitmap(view.getWidth(), view.getHeight(),
                    Bitmap.Config.RGB_565);
            // Canvas canvas = new Canvas(bm);
            Canvas canvas = new Canvas(bm);
            canvas.drawColor(Color.WHITE);
            // Toast.makeText(conext,
            // String.valueOf(bm.getWidth())+"<>"+String.valueOf(
            // bm.getHeight()), Toast.LENGTH_LONG).show();
            view.draw(canvas);
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            bm.compress(Bitmap.CompressFormat.PNG, 100, baos); // bm is the
            // bitmap
            // object
            byte[] b = baos.toByteArray();

            checkUserDirectoryToSaveScreen(conext);
            retURL = StoreByteImage(conext, b, quality, imageNameWithUserName,
                    isShowAlert);
            applyAstroSageWatermark(conext, retURL, quality);
        } catch (Exception e) {
            // Toast.makeText(conext,"Bijendra>"+
            // e.getMessage(),Toast.LENGTH_LONG).show();
        }

        return retURL;

    }

    /**
     * This function is used to add AstroSage watermark on share image
     *
     * @param context
     * @param imgUrl
     * @param quality
     * @author Bijendra(1 - 05 - 14)
     */

    private static void applyAstroSageWatermark(Context context, String imgUrl,
                                                int quality) throws Exception {
        FileOutputStream fileOutputStreamWm = null;
        BufferedOutputStream bosWm = null;
        Paint wmTextColor = new Paint(Color.BLACK);
        wmTextColor.setTextSize(35);

        try {
            Bitmap image = BitmapFactory.decodeFile(imgUrl);
            Bitmap result = Bitmap.createBitmap(image.getWidth(),
                    image.getHeight(), Config.ARGB_8888);
            Canvas canvas = new Canvas(result);
            canvas.drawBitmap(image, 0, 0, null);
            // Bitmap watermark =
            // BitmapFactory.decodeResource(context.getResources(),
            // R.drawable.astrosage_logo);
            /*
             * canvas.drawBitmap(watermark, image.getWidth()/2 -
             * watermark.getWidth()/2, image.getHeight()/2 -
             * watermark.getHeight()/2, null);
             */
            // canvas.drawText("Get free chart (kundli) at http://www.AstroSage.com",
            // 5, 15,wmTextColor);
            // canvas.drawText("https://www.astrosage.com", 5, 15,wmTextColor);
            canvas.drawText(CGlobalVariables.ASTROSAGE_BASE_URL, 16,
                    image.getHeight() - 40, wmTextColor);

            fileOutputStreamWm = new FileOutputStream(imgUrl);

            bosWm = new BufferedOutputStream(fileOutputStreamWm);

            result.compress(CompressFormat.JPEG, quality, bosWm);
        } catch (Exception e) {
            throw e;
        } finally {
            bosWm.flush();
            bosWm.close();
        }

    }

