    /**
     * This function is used to check that directory exist or not ,where images
     * is to saved.
     *
     * @param context
     * @return
     */
    private static void checkUserDirectoryToSaveScreen(Context context) {
        String root = "";
        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.R) {
            root = context.getExternalFilesDir(null).toString();
        } else {
            root = Environment.getExternalStorageDirectory().toString();
        }

        File myNewFolder = new File(root, CGlobalVariables.myKundliDirectoryInSDCard);
        if (!myNewFolder.exists()) {
            myNewFolder.mkdir();
        }

    }

    /**
     * This function is used to convert image into byte and store it on SD card.
     *
     * @param mContext
     * @param imageData
     * @param quality
     * @param expName
     * @param isShowAlert
     * @return String
     */
    private static String StoreByteImage(Context mContext, byte[] imageData,
                                         int quality, String expName, boolean isShowAlert) {

        // File sdImageMainDirectory = new File("/sdcard/myImages");
        // File sdImageMainDirectory = new
        // File(CGlobalVariables.myKundliDirectoryInSDCard+"/"+CGlobalVariables.horoDirectoryName);

        String root = "";
        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.R) {
            root = mContext.getExternalFilesDir(null).toString();
        } else {
            root = Environment.getExternalStorageDirectory().toString();
        }

        File sdImageMainDirectory = new File(root, CGlobalVariables.myKundliDirectoryInSDCard);
        FileOutputStream fileOutputStream = null;
        String nameFile;
        String imageURL = null;

        try {

            BitmapFactory.Options options = new BitmapFactory.Options();
            // options.inSampleSize = 5;

            Bitmap myImage = BitmapFactory.decodeByteArray(imageData, 0,
                    imageData.length, options);

            // fileOutputStream = new FileOutputStream(
            // sdImageMainDirectory.toString() +"/" + nameFile + ".jpg");
            expName = expName.trim().replace(' ', '_').replace('-', '_')
                    .replace(':', '_').replace('.', '_');
            imageURL = sdImageMainDirectory.toString() + "/" + expName + ".png";
            // imageURL = sdImageMainDirectory.toString() + "/Bij"+ ".png";
            fileOutputStream = new FileOutputStream(imageURL);

            BufferedOutputStream bos = new BufferedOutputStream(
                    fileOutputStream);

            myImage.compress(CompressFormat.JPEG, quality, bos);

            bos.flush();
            bos.close();
            /*
             * if (isShowAlert) showAlertAfterSendMail(mContext,
             * mContext.getResources()
             * .getString(R.string.MsgSaveScreenForPrint));
             */

        } catch (Exception e) {
            // TODO Auto-generated catch block
            // e.printStackTrace();
            Toast.makeText(mContext, e.getMessage(), Toast.LENGTH_LONG).show();
        }

        return imageURL;
    }

    /**
     * This function is used to send mSSSail.
     *
     * @param context
     * @param imageTextURL
     * @param filetype
     */
    public static void sendMailOfUserScreen(Context context,
                                            String imageTextURL, CGlobalVariables.enuFileType filetype) {
        try {
            Intent picMessageIntent = new Intent(
                    android.content.Intent.ACTION_SEND);

            if (filetype == enuFileType.IMAGE)
                picMessageIntent.setType("image/png");
            // picMessageIntent.setType("image/jpeg");

            if (filetype == enuFileType.TEXT)
                picMessageIntent.setType("plain/text");

            File downloadedPic = new File(imageTextURL);

            Uri uri = null;
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                picMessageIntent.setFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION);
                uri = FileProvider.getUriForFile(context, "com.ojassoft.astrosage", downloadedPic);
            } else {
                uri = Uri.fromFile(downloadedPic);
            }


            //Uri uri = Uri.fromFile(downloadedPic);
            //Log.e("Uri", uri.toString());
            picMessageIntent.putExtra(Intent.EXTRA_STREAM, uri);
            picMessageIntent.putExtra(android.content.Intent.EXTRA_EMAIL,
                    "Email-is");

            picMessageIntent.putExtra(android.content.Intent.EXTRA_SUBJECT,
                    "Write subject");

            picMessageIntent.putExtra(android.content.Intent.EXTRA_TEXT,
                    "Message");

            context.startActivity(Intent.createChooser(picMessageIntent,
                    "Send mail..."));

        } catch (Exception e) {
            //Log.e("Msg", "sendPictureMessage() failed to start activity.",e);
            // Toast.makeText(context, "No handler", Toast.LENGTH_LONG).show();
        }
        return;
    }

