    public static void rateAppication(Context context, boolean redirect) {
        try {
            CUtils.googleAnalyticSendWitPlayServie((Activity) context,
                    CGlobalVariables.GOOGLE_ANALYTIC_EVENT,
                    CGlobalVariables.GOOGLE_ANALYTIC_ACTION_RATE_APP, ((Activity) context).getLocalClassName());
            CUtils.fcmAnalyticsEvents(CGlobalVariables.GOOGLE_ANALYTIC_ACTION_RATE_APP, CGlobalVariables.FIREBASE_EVENT_ITEM_CLICK, ((Activity) context).getLocalClassName());

            if (redirect) {
                redirectToPlayStore(context);
            } else {
                /*
                 * in-app review added by shreyans
                 * */
                ReviewManager manager = ReviewManagerFactory.create(context);
                Task<ReviewInfo> request = manager.requestReviewFlow();
                request.addOnCompleteListener(task -> {
                    if (task.isSuccessful()) {
                        // We can get the ReviewInfo object
                        ReviewInfo reviewInfo = task.getResult();
                        Task<Void> flow = manager.launchReviewFlow((Activity) context, reviewInfo);
                        flow.addOnCompleteListener(task1 -> {
                            // The flow has finished. The API does not indicate whether the user
                            // reviewed or not, or even whether the review dialog was shown. Thus, no
                            // matter the result, we continue our app flow.
                        });
                    }
                });
            }
        } catch (Exception e) {
            //
        }
    }

    public static void redirectToPlayStore(Context context) {
        final Uri marketUri = Uri.parse(CGlobalVariables.RATE_APP_URL);
        Intent intent = new Intent(Intent.ACTION_VIEW, marketUri);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK);
        context.startActivity(intent);
    }

