    public static void googleAnalyticSendWitPlayServie(Activity activity,
                                                       String action, String label, String screenName) {
        try {
            // Get tracker.
            /*Tracker t = ((AstrosageKundliApplication) activity.getApplication())
                    .getTracker(TrackerName.APP_TRACKER);

            // CUtil.showLogMessage("analytic", "call");
            t.setScreenName(screenName);

            // GoogleAnalytics.getInstance(activity).getLogger()
            // .setLogLevel(LogLevel.VERBOSE);
            t.send(new HitBuilders.EventBuilder().setCategory("UX")
                    .setAction(action).setLabel(label).build());*/

            /*
             * //Firebase Analytics
             * Added by Monika
             * */
            if (action.toLowerCase().equals(CGlobalVariables.GOOGLE_ANALYTIC_DEEPLINK_EVENT.toLowerCase())) {
                CUtils.fcmAnalyticsEvents(label.toLowerCase(), CGlobalVariables.FIREBASE_EVENT_DEEPLINK_CLICK, "");

            } else if (action.toLowerCase().equals(CGlobalVariables.GOOGLE_ANALYTIC_SCREEN.toLowerCase())) {

                if (screenName != null && screenName.length() > 0) {
                    CUtils.fcmAnalyticsEvents(screenName.toLowerCase(), CGlobalVariables.FIREBASE_EVENT_OPEN_SCREEN, "");
                }
            }
            if (screenName != null && screenName.toLowerCase().equals(LibCGlobalVariables.CAT_SCREEN.toLowerCase())) {
                String labell = action + "_" + label;
                CUtils.fcmAnalyticsEvents(labell, CGlobalVariables.FIREBASE_EVENT_ITEM_CLICK, "");
            }
        } catch (Exception e) {
            // Log.e("Tracker ", e.getMessage());
        }

    }

