    /**
     * This method format string by replacing some special character with
     * appropriate char. This replacement happen only in hindi string case.
     *
     * @param str
     * @return
     */
    public static String returnFormattedString(int LANGUAGE_CODE, String str) {
        String strReturn = str;
        if (LANGUAGE_CODE == CGlobalVariables.HINDI) {
            strReturn = strReturn.replace(CGlobalVariables.CHAR_PIPE,
                    CGlobalVariables.CHAR_AMPERSENT);
            strReturn = strReturn.replace(CGlobalVariables.CHAR_NINE,
                    CGlobalVariables.CHAR_LESS_THEN);
        }

        return strReturn;
    }

