    public static SharedPreferences getWeeklyPreference(Context context, int LANGUAGE_CODE) {
        SharedPreferences weeklyHoroscopePref = context.getSharedPreferences(CGlobalVariables.weeklyHoroscopePrefName, Context.MODE_PRIVATE);
        if (CUtils.isSupportUnicodeHindi() && LANGUAGE_CODE == CGlobalVariables.HINDI) {
            weeklyHoroscopePref = context.getSharedPreferences(CGlobalVariables.weeklyHoroscopePrefHindiName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.TAMIL) {
            weeklyHoroscopePref = context.getSharedPreferences(CGlobalVariables.weeklyHoroscopePrefTamilName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.MARATHI) {
            weeklyHoroscopePref = context.getSharedPreferences(CGlobalVariables.weeklyHoroscopePrefMarathiName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.BANGALI) {
            weeklyHoroscopePref = context.getSharedPreferences(CGlobalVariables.weeklyHoroscopePrefBangaliName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.KANNADA) {
            weeklyHoroscopePref = context.getSharedPreferences(CGlobalVariables.weeklyHoroscopePrefKannadName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.TELUGU) {
            weeklyHoroscopePref = context.getSharedPreferences(CGlobalVariables.weeklyHoroscopePrefTelguName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.GUJARATI) {
            weeklyHoroscopePref = context.getSharedPreferences(CGlobalVariables.weeklyHoroscopePrefGujaratiName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.MALAYALAM) {
            weeklyHoroscopePref = context.getSharedPreferences(CGlobalVariables.weeklyHoroscopePrefMalayalamName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == ASAMMESSE) {
            weeklyHoroscopePref = context.getSharedPreferences(CGlobalVariables.weeklyHoroscopePrefAssammeseName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.ODIA) {
            weeklyHoroscopePref = context.getSharedPreferences(CGlobalVariables.weeklyHoroscopePrefOdiaName, Context.MODE_PRIVATE);
        }
        return weeklyHoroscopePref;
    }

    /*
     * @date : 9 feb 2016
     * @desc : This method is use to get week and every week will starts from monday
     */
    public static int getWeekOfYear(Calendar calendar) {

        //Calendar calendar = Calendar.getInstance();
        int weekOfYear = calendar.get(Calendar.WEEK_OF_YEAR);
        int dayOfWeek = calendar.get(Calendar.DAY_OF_WEEK);

        //On Sunday Week Should Be Same and it should not be first week of the year
        if (dayOfWeek == Calendar.SUNDAY && weekOfYear != 1) {
            weekOfYear = weekOfYear - 1;
        }

        return weekOfYear;
    }
