    public static String[] getYearlyHoroscopeDetail(SharedPreferences nextYearlyHoroscope, int LANGUAGE_CODE) {
        String[] yearlyHoroscopeDetail = getYearlyRasiPrediction(nextYearlyHoroscope, 1);
        if (LANGUAGE_CODE == CGlobalVariables.TAMIL) {
            yearlyHoroscopeDetail = getYearlyRasiPredictionTamil(nextYearlyHoroscope, 1);
        } else if (LANGUAGE_CODE == CGlobalVariables.BANGALI) {
            yearlyHoroscopeDetail = getYearlyRasiPredictionBangla(nextYearlyHoroscope, 1);
        } else if (LANGUAGE_CODE == CGlobalVariables.GUJARATI) {
            yearlyHoroscopeDetail = getYearlyRasiPredictionGujrati(nextYearlyHoroscope, 1);
        } else if (LANGUAGE_CODE == CGlobalVariables.MALAYALAM) {
            yearlyHoroscopeDetail = getYearlyRasiPredictionMalayalam(nextYearlyHoroscope, 1);
        } else if (LANGUAGE_CODE == CGlobalVariables.MARATHI) {
            yearlyHoroscopeDetail = getYearlyRasiPredictionMarathi(nextYearlyHoroscope, 1);
        } else if (LANGUAGE_CODE == CGlobalVariables.HINDI) {
            yearlyHoroscopeDetail = getYearlyRasiPredictionMarathi(nextYearlyHoroscope, 1);
        }
        return yearlyHoroscopeDetail;
    }

