    public static void saveNextYearPridictionPreferences(Context context, String key, boolean value) {
        SharedPreferences sharedPreferences = PreferenceManager
                .getDefaultSharedPreferences(context);
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putBoolean(key, value);
        editor.commit();
    }

    public static boolean getNextYearPridictionPreferences(Context context, String key) {
        SharedPreferences sharedPreferences = PreferenceManager
                .getDefaultSharedPreferences(context);

        return sharedPreferences.getBoolean(
                CGlobalVariables.YEARLY_HOROSCEOPE_PREF_KEYFOR_NEXTYEAR_FOR_BOOLEAN, false);
    }

    public static String getCurrentYear() {
        Date date = new Date();
        SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy",
                Locale.ENGLISH);
        String year = dateFormat.format(date.getTime());
        return year;

    }

    public static boolean getCurrentYearPreferenceCheck(Context context, String key) {
        SharedPreferences sharedPreferences = PreferenceManager
                .getDefaultSharedPreferences(context);

        return sharedPreferences.getBoolean(
                key, false);
    }

    public static void saveCurrentYearPreferenceCheck(Context context, String key, boolean value) {
        SharedPreferences sharedPreferences = PreferenceManager
                .getDefaultSharedPreferences(context);
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putBoolean(key, value);
        editor.commit();
    }

