    public static String[] getYearlyPredictionData(SharedPreferences horoscopePrefType, int SELECTED_MOON_SIGN, int langCode) {
        if (langCode == CGlobalVariables.ENGLISH || langCode == CGlobalVariables.HINDI) {
            return getYearlyRasiPrediction(horoscopePrefType,
                    SELECTED_MOON_SIGN);
        } else {
            return getYearlyRasiPredictionForOtherLAng(horoscopePrefType, SELECTED_MOON_SIGN);
        }
    }

