    @SuppressLint("NewApi")
    public static void copyTextToClipBoard(String stringYouExtracted,
                                           Activity con) {
        if (android.os.Build.VERSION.SDK_INT < android.os.Build.VERSION_CODES.HONEYCOMB) {
            android.text.ClipboardManager clipboard = (android.text.ClipboardManager) con
                    .getSystemService(Context.CLIPBOARD_SERVICE);
            clipboard.setText(stringYouExtracted);
        } else {
            android.content.ClipboardManager clipboard = (android.content.ClipboardManager) con
                    .getSystemService(Context.CLIPBOARD_SERVICE);
            android.content.ClipData clip = android.content.ClipData
                    .newPlainText("Copied Text", stringYouExtracted);
            clipboard.setPrimaryClip(clip);
        }
        MyCustomToast mct2 = new MyCustomToast(con, con.getLayoutInflater(),
                con, Typeface.DEFAULT);
        mct2.show(con.getResources().getString(R.string.copied));
    }

    /**
     * This method sends prediction email.
     *
     * @param context
     */
    public static void sharePrediction(Context context, String subject,
                                       String textToShare) {

        Intent intent = new Intent(Intent.ACTION_SEND);
        intent.setType("text/plain");
        //intent.putExtra(Intent.EXTRA_SUBJECT, subject);
        intent.putExtra(Intent.EXTRA_TEXT, Html.fromHtml(textToShare));
        try {
            intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK);
            intent.setFlags(Intent.FLAG_ACTIVITY_MULTIPLE_TASK);

            context.startActivity(Intent.createChooser(intent, "Share Data..."));
        } catch (android.content.ActivityNotFoundException ex) {

        }

    }

