    /**
     * This method return detailed prediction to user.
     *
     * @param context
     * @param rashiIndex
     * @param categoryIndex
     * @return String- prediction according to passed arguments.
     */
    public static String getPredictinDetail(Context context,
                                            int rashiIndex /* 0 - 11 */, int categoryIndex/* 0 - 11 */,
                                            int languageCode) {
        String predString = "";
        try {
            InputStream in = context.getResources().openRawResource(
                    getPredictionFileID(rashiIndex, languageCode));
            DocumentBuilder builder = DocumentBuilderFactory.newInstance()
                    .newDocumentBuilder();
            Document doc = builder.parse(in, null);
            NodeList statements = doc.getElementsByTagName("statement");
            for (int i = 0; i < statements.getLength(); i++) {
                if (categoryIndex == i)
                    predString = statements.item(i).getChildNodes().item(0)
                            .getNodeValue();

            }
        } catch (Throwable t) {

        }
        predString = predString.trim();
        //predString = predString.replaceAll("[\\\\n\\\\t ]", "");
        predString = predString.replaceAll("\\n", "");
        predString = predString.replaceAll(" +", " ");

      /*  if (categoryIndex != 7)
            return "  " + predString;
        else {*/
        return predString;
        //}
    }

