    /**
     * this method return the boolean value if screen has kundli
     *
     * @param selectedModule
     * @param selectedSubModule
     * @return boolean
     */
    public static boolean isKundliOnScreen(int selectedModule,
                                           int selectedSubModule) {
        //Log.e(selectedModule + " " + selectedSubModule);

        boolean isKundli = false;
        switch (selectedModule) {
            case CGlobalVariables.MODULE_BASIC:
                switch (selectedSubModule) {
                    case CGlobalVariables.SUB_MODULE_BASIC_LAGNA_CHART:
                        isKundli = true;
                        break;
                    case CGlobalVariables.SUB_MODULE_BASIC_NAVAMSHA_CHART:
                        isKundli = true;
                        break;
                    case CGlobalVariables.SUB_MODULE_BASIC_MOON_CHART:
                        isKundli = true;
                        break;
                    case CGlobalVariables.SUB_MODULE_BASIC_CHALIT_CHART:
                        isKundli = true;
                        break;

                }
                break;
            case CGlobalVariables.MODULE_KP:
                switch (selectedSubModule) {
                    case CGlobalVariables.SUB_MODULE_KP_KP_CHART:
                        isKundli = true;
                        break;
                    case CGlobalVariables.SUB_MODULE_KP_RASHI_CHART:
                        isKundli = true;
                        break;
                }
                break;
            case CGlobalVariables.MODULE_VARSHAPHAL:
                if (selectedSubModule == CGlobalVariables.SUB_MODULE_TAJIK_VARSHPHAL_CHART) {
                    isKundli = true;
                }

                break;
            case CGlobalVariables.MODULE_LALKITAB:
                switch (selectedSubModule) {
                    case CGlobalVariables.SUB_MODULE_LALKITAB_LAGNA:
                        isKundli = true;
                        break;
                    case CGlobalVariables.SUB_MODULE_LALKITAB_VARSHA_CHART:
                        isKundli = true;
                        break;
                }
                break;
            case CGlobalVariables.MODULE_SHODASHVARGA:
                if (selectedSubModule != CGlobalVariables.SUB_MODULE_SHODASHVARGA_HORA) {
                    isKundli = true;
                }
                break;

        }
        return isKundli;
    }

