    public static boolean isCycleCompleted() {
        long currentTime = System.currentTimeMillis();
        long diff = currentTime - AstrosageKundliApplication.getAppContext().currentTimeMillis;
        // 120000 milliseconds means 2 min.
        if (diff > 120000) {
            AstrosageKundliApplication.getAppContext().currentTimeMillis = currentTime;
            return true;
        } else {
            return false;
        }
    }

    public static String calculateMD5Values(String key) {
        String MD5 = "MD5", calculateMD5Value = "";

        try {
            calculateMD5Value = hashString(key, MD5);

        } catch (Exception e) {
            System.out.println("ERROR   " + e.getMessage());
        }

        return calculateMD5Value;
    }

    private static String hashString(String message, String algorithm)
            throws Exception {

        try {
            MessageDigest digest = MessageDigest.getInstance(algorithm);
            byte[] hashedBytes = digest.digest(message.getBytes(StandardCharsets.UTF_8));

            return convertByteArrayToHexString(hashedBytes);
        } catch (Exception ex) {
            throw ex;
        }
    }

    private static String convertByteArrayToHexString(byte[] arrayBytes) {
        StringBuffer stringBuffer = new StringBuffer();
        for (int i = 0; i < arrayBytes.length; i++) {
            stringBuffer.append(Integer.toString(
                    (arrayBytes[i] & 0xff) + 0x100, 16).substring(1));
        }
        return stringBuffer.toString();
    }

