    /**
     * This function is used to strach list fully
     *
     * @param myListView 21-May-2015
     */
    public static void stratchListViewFullly(ListView myListView) {
        ListAdapter myListAdapter = myListView.getAdapter();
        if (myListAdapter == null) {
            return;
        }
        // set listAdapter in loop for getting final size
        int totalHeight = 0;
        for (int size = 0; size < myListAdapter.getCount(); size++) {
            View listItem = myListAdapter.getView(size, null, myListView);
            listItem.measure(0, 0);
            totalHeight += listItem.getMeasuredHeight() + 2;
        }
        // setting listview item in adapter
        ViewGroup.LayoutParams params = myListView.getLayoutParams();
        params.height = totalHeight + 60;
        myListView.setLayoutParams(params);
    }

    /**
     * This function is used to calculate security key to validate purchase on
     * server
     *
     * @param orderId
     * @return 01-Jun-2015
     * @author Bijendra
     */
    public static String getProductPurchaseSecurityKey(String orderId) {
        String key = "";
        try {
            String[] orderSplitArray;
            String delimiter = "\\.";
            orderSplitArray = orderId.split(delimiter);
            key = orderSplitArray[1];
            String subKey = key.substring(key.length() - 4);// TAKING
            // LAT
            // 4
            // DIGIT
            Calendar cal = Calendar.getInstance();
            int keyValue = cal.get(Calendar.DAY_OF_MONTH);
            keyValue += cal.get(Calendar.MONTH) + 1;// MONTH FROM 1-12
            keyValue += cal.get(Calendar.YEAR);
            keyValue += Integer.valueOf(subKey);
            key = String.valueOf(keyValue);
        } catch (Exception e) {

        }
        return key;
    }

