    /**
     * Saves place details to SharedPreferences by converting BeanPlace object to JSON
     * Uses Gson to serialize the object before saving
     *
     * @param context   Application context to access SharedPreferences
     * @param beanPlace BeanPlace object containing place details to be saved
     *                  (city name, latitude, longitude, timezone etc.)
     *                  <p>
     *                  Storage details:
     *                  - Preferences file: CGlobalVariables.APP_PREFS_NAME
     *                  - Key: "CurrentPlace"
     *                  - Format: JSON string representation of BeanPlace object
     *                  - Commit: Synchronous save to ensure immediate persistence
     */
    public static void saveCurrentPalce(Context context, BeanPlace beanPlace) {
        // Get SharedPreferences instance and editor
        SharedPreferences sharedPreferences = context.getSharedPreferences(
                CGlobalVariables.APP_PREFS_NAME, MODE_PRIVATE);
        SharedPreferences.Editor sharedPrefEditor = sharedPreferences.edit();

        // Convert BeanPlace object to JSON string using Gson
        Gson gson = new Gson();
        String jsonbeanplace = gson.toJson(beanPlace);

        // Save JSON string to SharedPreferences
        sharedPrefEditor.putString("CurrentPlace", jsonbeanplace);

        // Commit changes synchronously to ensure immediate save
        sharedPrefEditor.commit();

    }

