    public static View getCustomAdvertismentView(final Context context,
                                                 boolean needToSetPreviousView, final Typeface typeface, final String session) {
        // Activity activity = (Activity)context;
        View footerView = null;
        try {
            LayoutInflater layoutInflater = LayoutInflater.from(context);
            footerView = layoutInflater.inflate(R.layout.custom_advertisment, null);

            //verify is add should show or not
            boolean showAds = getBooleanData(context, CGlobalVariables.customAdvertisementAdsVisibility, false);
            boolean isbasic = CUtils.getUserPurchasedPlanFromPreference(context) == 1;
            if (showAds && isbasic) {
                NetworkImageView imgCustomAdvertisement = footerView
                        .findViewById(R.id.imgCustomAdvertisement);

                final String linkToOpenWeb;

                ImageLoader imageLoader = VolleySingletonForDefaultHttp.getInstance(
                        context.getApplicationContext()).getImageLoader();
                linkToOpenWeb = getStringData(context,
                        CGlobalVariables.customAdvertisementLink,
                        CGlobalVariables.defalutAdvertisementLink);
                imgCustomAdvertisement.setImageUrl(
                        getStringData(context,
                                CGlobalVariables.customAdvertisementImage, ""),
                        imageLoader);

                footerView.setOnClickListener(new OnClickListener() {
                    @Override
                    public void onClick(View v) {
                        // TODO Auto-generated method stub
                        // customAdvertisment();

                        CUtils.googleAnalyticSendWitPlayServie(((Activity) context),
                                CGlobalVariables.GOOGLE_ANALYTIC_EVENT,
                                CGlobalVariables.GOOGLE_ANALYTIC_FOOTER_ADD, null);
                        CUtils.fcmAnalyticsEvents(CGlobalVariables.GOOGLE_ANALYTIC_FOOTER_ADD, CGlobalVariables.FIREBASE_EVENT_ITEM_CLICK, "");

                        if (CUtils.isConnectedWithInternet(context)) {
                            if (session != null && !session.isEmpty()) {
                                createSession(context, session);
                            }
                            CUtils.callCustomAdvertisementLink(context,
                                    linkToOpenWeb);

                        } else {
                            MyCustomToast mct = new MyCustomToast(context,
                                    ((Activity) context).getLayoutInflater(),
                                    ((Activity) context), typeface);
                            mct.show(context.getResources().getString(
                                    R.string.no_internet));
                        }
                    }
                });

                if (needToSetPreviousView) {
                    CGlobalVariables.previousAdvertiseView = footerView;
                }
            } else {
                NetworkImageView imgCustomAdvertisement = footerView
                        .findViewById(R.id.imgCustomAdvertisement);
                imgCustomAdvertisement.setVisibility(View.GONE);
            }
        } catch (Exception ex) {
            //Log.i(ex.getMessage().toString());
        }
        return footerView;
    }

    public static boolean isShowCustomAds(Context context) {
        try {
            boolean showAds = getBooleanData(context, CGlobalVariables.customAdvertisementAdsVisibility, false);
            boolean isbasic = CUtils.getUserPurchasedPlanFromPreference(context) == 1;
            if (showAds && isbasic) {
                return true;
            }
        } catch (Exception e) {
            //
        }
        return false;
    }

    public static void saveStringData(Context context, String key, String value) {

        SharedPreferences preferences = PreferenceManager
                .getDefaultSharedPreferences(context);
        if (preferences == null)
            return;
        SharedPreferences.Editor editor = preferences.edit();
        editor.putString(key, value);
        editor.commit();

    }

    public static String getStringData(Context context, String key,
                                       String defaultValue) {
        if (context != null) {
            SharedPreferences preferences = PreferenceManager
                    .getDefaultSharedPreferences(context);
            if (preferences == null)
                return "";
            String value = preferences.getString(key, defaultValue);

            return value;
        } else {
            return "";
        }
    }

    public static void saveIntData(Context context, String key, int value) {
        SharedPreferences preferences = PreferenceManager
                .getDefaultSharedPreferences(context);
        SharedPreferences.Editor editor = preferences.edit();
        editor.putInt(key, value);
        editor.commit();
    }

    public static int getIntData(Context context, String key, int defaultValue) {
        SharedPreferences preferences = PreferenceManager
                .getDefaultSharedPreferences(context);
        int value = preferences.getInt(key, defaultValue);
        return value;
    }

    public static void saveBooleanData(Context context, String key,
                                       boolean value) {

        SharedPreferences preferences = PreferenceManager
                .getDefaultSharedPreferences(context);
        SharedPreferences.Editor editor = preferences.edit();
        editor.putBoolean(key, value);
        editor.commit();

    }

    public static boolean getBooleanData(Context context, String key,
                                         boolean defaultValue) {

        SharedPreferences preferences = PreferenceManager
                .getDefaultSharedPreferences(context);
        boolean value = preferences.getBoolean(key, defaultValue);

        return value;
    }

    public static Bitmap StringToBitMap(String encodedString) {
        try {
            byte[] encodeByte = Base64.decode(encodedString, Base64.DEFAULT);
            Bitmap bitmap = BitmapFactory.decodeByteArray(encodeByte, 0,
                    encodeByte.length);
            return bitmap;
        } catch (Exception e) {
            e.getMessage();
            return null;
        }
    }

    public static String BitMapToString(Bitmap bitmap) {
        ByteArrayOutputStream ByteStream = new ByteArrayOutputStream();
        bitmap.compress(Bitmap.CompressFormat.PNG, 100, ByteStream);
        byte[] b = ByteStream.toByteArray();
        String temp = Base64.encodeToString(b, Base64.DEFAULT);
        return temp;
    }

    public static void saveCustomObject(Context context, Object object) {
        SharedPreferences sharedPreferences = context.getSharedPreferences(
                CGlobalVariables.APP_PREFS_NAME, Context.MODE_PRIVATE);
        Editor prefsEditor = sharedPreferences.edit();
        Gson gson = new Gson();
        String json = gson.toJson(object); // myObject - instance of MyObject
        prefsEditor.putString("MyObject", json);
        prefsEditor.commit();
    }

    /**
     * This function is used to show the expiry date of user purchase plan
     *
     * @param ,ScreenId,context
     * @date 28 Dec 2015
     */
    public static String isExpiryDateAvailableToShow(Context context, String ScreenId) {
        String expirydate = null;
        int planId = CUtils.getUserPurchasedPlanFromPreference(context);
        // Id for Sliver Plan = 2, Gold Plan = 3
        if ((planId == 2 && ScreenId.equals("SilverPlanFrag"))
                || (planId == 3 && ScreenId.equals("GoldPlanFrag"))
                || (planId == 4 && ScreenId.equals("SilverPlanFrag"))
                || (planId == 6 && ScreenId.equals("GoldPlanFrag"))
                || (planId == 5 && ScreenId.equals("SilverPlanFrag"))
                || (planId == 7 && ScreenId.equals("GoldPlanFrag"))
                || (planId == 8 && ScreenId.equals("PlatinumPlanFrag"))
                || (planId == 9 && ScreenId.equals("PlatinumPlanFrag"))
                || (planId == 10 && ScreenId.equals("PlatinumPlanFrag"))
                || (planId == 11 && ScreenId.equals("KundliAiPlanFrag"))) {
            expirydate = CUtils.getStringData(context, CGlobalVariables.PREF_USER_PLAN_Expiry_DATE, "0");
            if (!expirydate.equals("0") && expirydate != null) {
                DateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss.S", Locale.US);
                DateFormat dateFormat2 = new SimpleDateFormat("EEE, MMM d, yyyy", Locale.US);

                //DateFormat dateFormat = new SimpleDateFormat("MM/dd/yyyy", Locale.US);
                //DateFormat dateFormat2 = new SimpleDateFormat("EEE, MMM d, yyyy", Locale.US);
                String dateToShow = "";
                try {
                    Date date = dateFormat.parse(expirydate);
                    dateToShow = dateFormat2.format(date);
                    //Log.e("LOGINN ", "date " + date);
                    //Log.e("LOGINN ", "dateToShow " + dateToShow);

                } catch (ParseException e) {
                    e.printStackTrace();
                }
                String heading = context.getResources().getString(R.string.expiry_date);
                expirydate = heading + " " + dateToShow;
            }
        }
        if (expirydate != null && expirydate.equals("0")) {
            expirydate = null;
        }
        return expirydate;
    }

    /**
     * @param currentdate
     * @param expiryDate
     * @date 29-dec-2015
     * @description This method is used to get the remaining days from the two
     * given days
     */
    public static int returnRemainingDaysFromTwoDates(Date currentdate,
                                                      Date expiryDate) {
        int diffInDays = 0;
        try {
            diffInDays = (int) ((expiryDate.getTime() - currentdate.getTime()) / (1000 * 60 * 60 * 24));
            // System.err.println("Difference in number of days (2) : " +
            // diffInDays);
        } catch (Exception ex) {
            //Log.i(ex.getMessage().toString());
        }
        return diffInDays;
    }

    public static Object getCustomObject(Context context) {
        try {
            SharedPreferences sharedPreferences = context.getSharedPreferences(
                    CGlobalVariables.APP_PREFS_NAME, Context.MODE_PRIVATE);
            Gson gson = new Gson();
            String json = sharedPreferences.getString("MyObject", "");
            BeanHoroPersonalInfo obj = gson.fromJson(json, BeanHoroPersonalInfo.class);
            return obj;
        } catch (Exception e) {
            CUtils.saveCustomObject(context, null);
            return null;
        }
    }

