    public static SharedPreferences getTomorrowPref(Context context, int LANGUAGE_CODE) {
        SharedPreferences tomorrowsHoroscope = context.getSharedPreferences(CGlobalVariables.dailyHoroscopeTomorrowPrefName, Context.MODE_PRIVATE);
        if (CUtils.isSupportUnicodeHindi() && LANGUAGE_CODE == CGlobalVariables.HINDI) {
            tomorrowsHoroscope = context.getSharedPreferences(CGlobalVariables.dailyHoroscopeTomorrowPrefHindiName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.TAMIL) {
            tomorrowsHoroscope = context.getSharedPreferences(CGlobalVariables.dailyHoroscopeTomorrowPrefTamilName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.MARATHI) {
            tomorrowsHoroscope = context.getSharedPreferences(CGlobalVariables.dailyHoroscopeTomorrowPrefMarathiName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.BANGALI) {
            tomorrowsHoroscope = context.getSharedPreferences(CGlobalVariables.dailyHoroscopeTomorrowPrefBangaliName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.KANNADA) {
            tomorrowsHoroscope = context.getSharedPreferences(CGlobalVariables.dailyHoroscopeTomorrowPrefkannadName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.TELUGU) {
            tomorrowsHoroscope = context.getSharedPreferences(CGlobalVariables.dailyHoroscopeTomorrowPrefTelguName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.GUJARATI) {
            tomorrowsHoroscope = context.getSharedPreferences(CGlobalVariables.dailyHoroscopeTomorrowPrefGujaratiName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.MALAYALAM) {
            tomorrowsHoroscope = context.getSharedPreferences(CGlobalVariables.dailyHoroscopeTomorrowPrefMalayalamName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == ASAMMESSE) {
            tomorrowsHoroscope = context.getSharedPreferences(CGlobalVariables.dailyHoroscopeTomorrowPrefAssammeseName, Context.MODE_PRIVATE);
        } else if (LANGUAGE_CODE == CGlobalVariables.ODIA) {
            tomorrowsHoroscope = context.getSharedPreferences(CGlobalVariables.dailyHoroscopeTomorrowPrefOdiaName, Context.MODE_PRIVATE);
        }
        return tomorrowsHoroscope;
    }

