    /**
     * Detects stale English remedies cached under Odia or Assamese so the app can force a localized refetch.
     */
    public static boolean isLocalizedRemediesEnglishFallback(int LANGUAGE_CODE, String remediesJson) {
        if (TextUtils.isEmpty(remediesJson)) {
            return false;
        }
        if (LANGUAGE_CODE != CGlobalVariables.ODIA && LANGUAGE_CODE != CGlobalVariables.ASAMMESSE) {
            return false;
        }

        String nativeScriptPattern = LANGUAGE_CODE == CGlobalVariables.ODIA
                ? ".*[\\u0B00-\\u0B7F].*"
                : ".*[\\u0980-\\u09FF].*";
        if (remediesJson.matches(nativeScriptPattern)) {
            return false;
        }

        String normalizedJson = remediesJson.toLowerCase(Locale.ENGLISH);
        return normalizedJson.contains("horoscope")
                || normalizedJson.contains("aries")
                || normalizedJson.contains("taurus")
                || normalizedJson.contains("gemini")
                || normalizedJson.contains("cancer")
                || normalizedJson.contains("leo")
                || normalizedJson.contains("virgo")
                || normalizedJson.contains("libra")
                || normalizedJson.contains("scorpio")
                || normalizedJson.contains("sagittarius")
                || normalizedJson.contains("capricorn")
                || normalizedJson.contains("aquarius")
                || normalizedJson.contains("pisces");
    }

