    /**
     * Created by Amit Rautela on 26/2/16.
     * This method is used to call HoroscopeActivity
     *
     * @param context
     * @param MODULE_TYPE_KEY
     * @param SUB_MODULE_TYPE_KEY
     */
    public static void callHoroscopeActivity(Activity context, int MODULE_TYPE_KEY, int SUB_MODULE_TYPE_KEY, int screenType) {

        int moonSign = CUtils.getMoonSignIndex(context);
        if (moonSign == -1) {
            Intent intent = new Intent(context,
                    HoroscopeHomeActivity.class);
            intent.putExtra(CGlobalVariables.MODULE_TYPE_KEY, MODULE_TYPE_KEY);
            intent.putExtra(CGlobalVariables.SUB_MODULE_TYPE_KEY, SUB_MODULE_TYPE_KEY);
            context.startActivity(intent);
        } else {
            // Check if the interstitial/home popup feature is enabled via TagManager/SharedPrefs
            boolean isPopupEnabled = com.ojassoft.astrosage.varta.utils.CUtils.getBooleanData(context, CGlobalVariables.IS_INTERSTICIAL_ENABLED, false);
            // Check if the user is already a premium subscriber (Kundli AI+ or Dhruv Plan)
            // Premium users should not see these ads
            boolean isPremiumUser = CUtils.isKundliAIPlusPlan(context) || CUtils.isDhruvPlan(context);
            // Logic: Show Ad if feature enabled + user NOT premium + time interval allows (frequency capping)
            if (isPopupEnabled && !isPremiumUser && CUtils.canShowInterstitial(context)) {
                // Redirect to the Plan Purchase screen (acting as an Ad)
                com.ojassoft.astrosage.varta.utils.CUtils.openPurchasePlanScreenForAd(
                        context,
                        false,
                        false,
                        com.ojassoft.astrosage.varta.utils.CGlobalVariables.SOURCE_FROM_HOROSCOPE_AD,
                        true,
                        BACK_FROM_PLAN_PURCHASE_AD_SCREEN
                );
            } else {
                // Otherwise, proceed directly to the Detailed Horoscope (Rashi Prediction) screen
                Intent rashiPredictionIntent = new Intent(context, DetailedHoroscope.class);
                rashiPredictionIntent.putExtra("rashiType", moonSign);
                rashiPredictionIntent.putExtra("prediction_type", SUB_MODULE_TYPE_KEY);
                rashiPredictionIntent.putExtra("screenType", screenType);
                context.startActivity(rashiPredictionIntent);
            }


        }


    }

