    public static boolean isVisisbilityGoneForSignInAndRemoveAddsMenu(int position, Activity activity) {
        boolean isSetPasswordVisible = CUtils.isAutoGeneratedPassword(activity);
        if (position == BaseInputActivity.TAG_CLOUD_SIGN_OUT && com.ojassoft.astrosage.varta.utils.CUtils.getUserLoginStatus(activity)) {
            return true;
        } else {
            if (position == BaseInputActivity.TAG_REFER_AND_EARN) {
                if (CUtils.isUserLogedIn(activity)) {
                    String referAndEarn = CUtils.getStringData(activity, CGlobalVariables.REFER_AND_EARN, "");
                    return !referAndEarn.equalsIgnoreCase(CGlobalVariables.ENABLED);
                } else {
                    return true;
                }
            }
            return (position == BaseInputActivity.TAG_MY_ACCOUNT && !com.ojassoft.astrosage.varta.utils.CUtils.getUserLoginStatus(activity)) ||
                    (position == BaseInputActivity.TAG_CLOUD_SIGN_OUT && !CUtils.isUserLogedIn(activity))
                    || (position == BaseInputActivity.TAG_REMOVE_ADS && CUtils.isUserLogedIn(activity) && CUtils.getUserPurchasedPlanFromPreference(activity) != CGlobalVariables.BASIC_PLAN_ID) || (position == BaseInputActivity.TAG_SET_PASSWORD) && !CUtils.isAutoGeneratedPassword(activity)
                    || (position == BaseInputActivity.TAG_CALL_US) && !com.ojassoft.astrosage.varta.utils.CUtils.checkForCsNumberVisibility(activity);

        }

    }

