    public static void saveKundliInPreference(Context context, BeanHoroPersonalInfo beanHoroPersonalInfo) {
        ArrayList<BeanHoroPersonalInfo> recentSearchKundli = (ArrayList) CUtils.getRecentSearchKundli(context);
        if (recentSearchKundli == null) {
            recentSearchKundli = new ArrayList<BeanHoroPersonalInfo>();
        }
        if (recentSearchKundli.size() > 0) {

            if (beanHoroPersonalInfo.getLocalChartId() == -1 && beanHoroPersonalInfo.getOnlineChartId().equals("")) {
                for (int i = 0; i < recentSearchKundli.size(); i++) {
                    if (recentSearchKundli.get(i).getRecentId() == beanHoroPersonalInfo.getRecentId()) {
                        beanHoroPersonalInfo.setRecentId(recentSearchKundli.get(i).getRecentId());
                        recentSearchKundli.remove(i);
                        break;
                    }
                }

            } else if (beanHoroPersonalInfo.getLocalChartId() != -1 && beanHoroPersonalInfo.getOnlineChartId().equals("")) {
                for (int i = 0; i < recentSearchKundli.size(); i++) {
                    if (recentSearchKundli.get(i).getLocalChartId() == beanHoroPersonalInfo.getLocalChartId() || recentSearchKundli.get(i).getRecentId() == beanHoroPersonalInfo.getRecentId()) {
                        beanHoroPersonalInfo.setRecentId(recentSearchKundli.get(i).getRecentId());
                        recentSearchKundli.remove(i);
                        break;
                    }
                }
            } else if (beanHoroPersonalInfo.getLocalChartId() == -1 && !beanHoroPersonalInfo.getOnlineChartId().equals("")) {
                for (int i = 0; i < recentSearchKundli.size(); i++) {
                    if (recentSearchKundli.get(i).getOnlineChartId().equals(beanHoroPersonalInfo.getOnlineChartId()) || recentSearchKundli.get(i).getRecentId() == beanHoroPersonalInfo.getRecentId()) {
                        beanHoroPersonalInfo.setRecentId(recentSearchKundli.get(i).getRecentId());
                        recentSearchKundli.remove(i);
                        break;
                    }
                }
            } else {
                for (int i = 0; i < recentSearchKundli.size(); i++) {
                    if (recentSearchKundli.get(i).getOnlineChartId().equals(beanHoroPersonalInfo.getOnlineChartId()) &&
                            recentSearchKundli.get(i).getLocalChartId() == beanHoroPersonalInfo.getLocalChartId() || recentSearchKundli.get(i).getRecentId() == beanHoroPersonalInfo.getRecentId()) {
                        beanHoroPersonalInfo.setRecentId(recentSearchKundli.get(i).getRecentId());
                        recentSearchKundli.remove(i);
                        break;
                    }
                }
            }
            recentSearchKundli.add(0, beanHoroPersonalInfo);
        } else {
            int recentId = getIntData(context, "Recentid", 0);
            beanHoroPersonalInfo.setRecentId(recentId);
            saveIntData(context, "Recentid", ++recentId);
            recentSearchKundli.add(0, beanHoroPersonalInfo);
        }
        if (recentSearchKundli.size() > 5) {
            recentSearchKundli.remove(5);
        }
        if (recentSearchKundli.get(0).getRecentId() == -1) {
            int recentId = getIntData(context, "Recentid", 0);
            recentSearchKundli.get(0).setRecentId(recentId);
            saveIntData(context, "Recentid", ++recentId);
        }
        CUtils.saveRecentSearchKundli(context, recentSearchKundli);
    }

    /**
     * @param context
     * @desc This method is uset to give recent id if not available in RecentSearchKundli
     */
    public static void addRecentIdsInChartIfNotAvailableInRecentSearchCharts(Context context) {
        try {
            ArrayList<BeanHoroPersonalInfo> recentSearchKundli = (ArrayList) CUtils.getRecentSearchKundli(context);
            if (recentSearchKundli != null) {
                boolean isChanged = false;
                for (int i = 0; i < recentSearchKundli.size(); i++) {
                    if (recentSearchKundli.get(i).getRecentId() == -1) {
                        int recentId = getIntData(context, "Recentid", 0);
                        recentSearchKundli.get(i).setRecentId(recentId);
                        saveIntData(context, "Recentid", ++recentId);
                        isChanged = true;
                    }
                }
                if (isChanged) {
                    CUtils.saveRecentSearchKundli(context, recentSearchKundli);
                }
            }
        } catch (Exception ex) {
            //Log.i(ex.getMessage().toString());
        }
    }

