    /**
     * @param dg
     * @created by : Amit Rautela
     * Thismethod is used to get the default edittext of DatePicker and send it to setFontEditText().
     */
    public static void setCustomDatePickerEdittext(DatePickerDialog dg) {

        try {
            Field mDatePickerField = dg.getClass().getDeclaredField("mDatePicker");
            mDatePickerField.setAccessible(true);
            DatePicker datePicker = (DatePicker) mDatePickerField.get(dg);

            if (android.os.Build.VERSION.SDK_INT >= Build.VERSION_CODES.KITKAT_WATCH) {
                try {

                    Field delegateField = datePicker.getClass().getDeclaredField("mDelegate");
                    delegateField.setAccessible(true);
                    Object delegate = new Object();
                    delegate = delegateField.get(datePicker);


                    Field mDaySpinnerInput = delegate.getClass().getDeclaredField("mDaySpinnerInput");
                    Field mMonthSpinnerInput = delegate.getClass().getDeclaredField("mMonthSpinnerInput");
                    Field mYearSpinnerInput = delegate.getClass().getDeclaredField("mYearSpinnerInput");

                    setFontEditText(delegate, mDaySpinnerInput);
                    setFontEditText(delegate, mMonthSpinnerInput);
                    setFontEditText(delegate, mYearSpinnerInput);

                } catch (Exception ex) {
                    //Log.i(ex.getMessage().toString());
                }
            } else if (android.os.Build.VERSION.SDK_INT >= Build.VERSION_CODES.ICE_CREAM_SANDWICH) {

                try {

                    Field mDaySpinnerInput = datePicker.getClass().getDeclaredField("mDaySpinnerInput");
                    Field mMonthSpinnerInput = datePicker.getClass().getDeclaredField("mMonthSpinnerInput");
                    Field mYearSpinnerInput = datePicker.getClass().getDeclaredField("mYearSpinnerInput");

                    setFontEditText(datePicker, mDaySpinnerInput);
                    setFontEditText(datePicker, mMonthSpinnerInput);
                    setFontEditText(datePicker, mYearSpinnerInput);


                } catch (Exception ex) {
                    //Log.i(ex.getMessage().toString());
                }

            }
        } catch (Exception ex) {
            //Log.i(ex.getMessage().toString());
        }

    }

