    public static String getFortyDaysBeforeDate(String startDate, String formate) {
        Date date = CUtils.convertStringToDate(startDate, formate);// "dd/MM/yy"
        Date dateBefore = new Date(date.getTime() - 40 * 24 * 3600 * 1000L);
        Format formatter = new SimpleDateFormat("dd/MM/yyyy");
        String dateStr = formatter.format(dateBefore);
        return dateStr;
    }

