    public static String getCurrentDateTime() {
        DateFormat dateFormat = new SimpleDateFormat("MMM dd yyyy hh:mma", Locale.ENGLISH);
        //get current date time with Date()
        //SimpleDateFormat dt = new SimpleDateFormat("MMM dd yyyy hh:mma");
        Date date = new Date();
        System.out.println(dateFormat.format(date));

        //get current date time with Calendar()
        Calendar cal = Calendar.getInstance();
        String currentDateTime = dateFormat.format(cal.getTime());
        return currentDateTime;
    }

    public static String formatDate(String dateString) {
        String stringDate = "";
        try {
            //Mar 11 2016 2:21PM
            if (dateString != null) {
                //SimpleDateFormat dt = new SimpleDateFormat("MM/dd/yyyy hh:mm:ss a",Locale.ENGLISH);

                SimpleDateFormat dt = new SimpleDateFormat("MMM dd yyyy hh:mma", Locale.ENGLISH);

                Date date = dt.parse(dateString);

                // *** same for the format String below
                // SimpleDateFormat dt1 = new SimpleDateFormat("EEE dd, hh:mm a", Locale.ENGLISH);
                SimpleDateFormat dt1 = new SimpleDateFormat("MMM dd, hh:mm a", Locale.ENGLISH);
                stringDate = dt1.format(date);
            }
            return stringDate;
        } catch (ParseException parseException) {
            //android.util.//Log.e("date format", "" + parseException.getMessage());
        }
        return stringDate;
    }

