    public static int getPaddingInPixel(int dpmeauser, Context context) {
        Resources r = context.getResources();
        int px = (int) TypedValue.applyDimension(
                TypedValue.COMPLEX_UNIT_DIP,
                dpmeauser,
                r.getDisplayMetrics()
        );
        return px;
    }

