    public static ArrayList<AstroShopItemDetails> getCartProducts(Context context) {
        ArrayList<AstroShopItemDetails> cartList = new ArrayList<>();
        SharedPreferences sharedPreferences = context.getSharedPreferences(
                CGlobalVariables.APP_PREFS_NAME, Context.MODE_PRIVATE);
        String str = sharedPreferences.getString(CGlobalVariables.ASTROSHOP_CART, "");
        if (!str.isEmpty()) {

            cartList = new Gson().fromJson(str,
                    new TypeToken<ArrayList<AstroShopItemDetails>>() {
                    }.getType());
        }

        return cartList;
    }

    public static Boolean addproductToCart(Context context, AstroShopItemDetails item) {
        ArrayList<AstroShopItemDetails> cartList = null;
        SharedPreferences sharedPreferences = context.getSharedPreferences(
                CGlobalVariables.APP_PREFS_NAME, Context.MODE_PRIVATE);
        String str = sharedPreferences.getString(CGlobalVariables.ASTROSHOP_CART, "");
        try {
            if (!str.isEmpty()) {

                cartList = new Gson().fromJson(str,
                        new TypeToken<ArrayList<AstroShopItemDetails>>() {
                        }.getType());
                cartList.add(item);
            } else {
                cartList = new ArrayList<AstroShopItemDetails>();
                cartList.add(item);
            }
            setCartProduct(context, new Gson().toJson(cartList));
            return true;
        } catch (Exception e) {
            return false;
        }


    }

    public static Boolean removeproductFromCart(Context context, AstroShopItemDetails item) {
        ArrayList<AstroShopItemDetails> cartList = null;
        SharedPreferences sharedPreferences = context.getSharedPreferences(
                CGlobalVariables.APP_PREFS_NAME, Context.MODE_PRIVATE);
        String str = sharedPreferences.getString(CGlobalVariables.ASTROSHOP_CART, "");
        try {
            if (!str.isEmpty()) {

                cartList = new Gson().fromJson(str,
                        new TypeToken<ArrayList<AstroShopItemDetails>>() {
                        }.getType());
                for (AstroShopItemDetails product : cartList) {
                    if (item.getPId().equalsIgnoreCase(product.getPId())) {
                        cartList.remove(product);
                        break;
                    }
                }

                setCartProduct(context, new Gson().toJson(cartList));
                return true;

            } else {
                return false;

            }
        } catch (Exception e) {
            return false;
        }


    }

    public static void setCartProduct(Context context, String cardsData) {

        Editor editor = context.getSharedPreferences(CGlobalVariables.APP_PREFS_NAME, Context.MODE_PRIVATE)
                .edit();
        editor.putString(CGlobalVariables.ASTROSHOP_CART, cardsData);
        editor.commit();

    }

    public static void openWebBrowser(Context context, Uri uri) {
        try {
            Intent i = new Intent(Intent.ACTION_VIEW);
            i.setData(uri);
            context.startActivity(i);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    /**
     * This method open the url into default installed browser.
     * If default browser not available then open url into chrome browser.
     * If chrome browser not available then open url into webview.
     *
     * @param context
     * @param uri
     */
    public static void openWebBrowserOnlyChrome(Context context, Uri uri) {
        try {
            Intent intent = new Intent(Intent.ACTION_VIEW, uri);
            intent.setData(uri);
            context.startActivity(intent);
        } catch (Exception e) {
            CUtils.sendToShowOffers(context, uri.toString());
        }
    }

    /**
     * This method returns the default installed browser package name.
     *
     * @param context
     */
    public static String getDefaultBrowserPackegeName(Context context) {
        String packageName = "";
        try {
            Intent browserIntent = new Intent("android.intent.action.VIEW", Uri.parse("http://"));
            ResolveInfo resolveInfo = context.getPackageManager().resolveActivity(browserIntent, PackageManager.MATCH_DEFAULT_ONLY);
            packageName = resolveInfo.activityInfo.packageName;
            if (packageName == null) packageName = "";
        } catch (Exception e) {
            e.printStackTrace();
        }
        return packageName;
    }

