    public static void getOrderID(final Activity activity, Typeface typeface, RequestQueue queue, final AstrologerServiceInfo info) {
        final String[] order_id = new String[1];
        String orderUrl = CGlobalVariables.GENRATE_ORDER_ASKQUE;

        //  orderUrl="http://192.168.1.180/ac/astroshop/service-order-paytm.asp";
        final IAskCallback callback = (IAskCallback) activity;
        final CustomProgressDialog pd = new CustomProgressDialog(activity, typeface);
        pd.setCancelable(false);
        pd.show();

        StringRequest stringRequest = new StringRequest(Request.Method.POST, orderUrl,
                new Response.Listener<String>() {
                    @Override
                    public void onResponse(String response) {
                        VolleyLog.d("Ask from server +" + response);
                        try {
                            JSONArray array = new JSONArray(response);
                            JSONObject obj = array.getJSONObject(0);
                            String priceInRS = "", priceInDollor = "";
                            String result = obj.getString("Result");
                            if (result.equalsIgnoreCase("1")) {

                                order_id[0] = obj.getString("OrderId");
                                if (obj.has("PriceRsToPay")) {
                                    priceInRS = obj.getString("PriceRsToPay");
                                }
                                if (obj.has("PriceToPay")) {
                                    priceInDollor = obj.getString("PriceToPay");
                                }
                                callback.getCallBack(order_id[0], callBack.GET_ORDER_ID, priceInDollor, priceInRS);

                            } else if (result.equalsIgnoreCase("3")) {
                                callback.getCallBack("3", callBack.GET_ORDER_ID, "", "");

                            } else {
                                order_id[0] = "";
                                callback.getCallBack(order_id[0], callBack.GET_ORDER_ID, "", "");

                            }

                        } catch (Exception e) {
                        }
                        hideProgressBar(pd);

                    }

                }

                , new Response.ErrorListener() {
            @Override
            public void onErrorResponse(VolleyError error) {
                order_id[0] = "";
                callback.getCallBack(order_id[0], callBack.GET_ORDER_ID, "", "");

                // //Log.e("Error Through" + error.getMessage());
                VolleyLog.d("VolleyError: " + error.getMessage());
                //   mTextView.setText("That didn't work!");
                if (error instanceof TimeoutError) {
                    VolleyLog.d("TimeoutError: " + error.getMessage());
                } else if (error instanceof NoConnectionError) {
                    VolleyLog.d("NoConnectionError: " + error.getMessage());
                } else if (error instanceof AuthFailureError) {
                    VolleyLog.d("AuthFailureError: " + error.getMessage());
                    //TODO
                } else if (error instanceof ServerError) {
                    //TODO
                    VolleyLog.d("ServerError: " + error.getMessage());
                } else if (error instanceof NetworkError) {
                    //TODO
                    VolleyLog.d("NetworkError: " + error.getMessage());
                } else if (error instanceof ParseError) {
                    //TODO
                    VolleyLog.d("ParseError: " + error.getMessage());

                }
                hideProgressBar(pd);
            }
        }
        ) {
            @Override
            public String getBodyContentType() {
                return "application/x-www-form-urlencoded;charset=UTF-8";
            }

            /**
             * Passing some request headers
             * */
            @Override
            public Map<String, String> getParams() throws AuthFailureError {

                Calendar calendar = Calendar.getInstance();
                String year = String.valueOf(calendar.get(Calendar.YEAR));
                String month = String.valueOf(calendar.get(Calendar.MONTH) + 1);
                String day = String.valueOf(calendar.get(Calendar.DAY_OF_MONTH));
                String minute = String.valueOf(calendar.get(Calendar.MINUTE));
                String hour = String.valueOf(calendar.get(Calendar.HOUR_OF_DAY));
                /**
                 * set the default value of user birth profile while unavailable
                 */

                HashMap<String, String> headers = new HashMap<String, String>();
                headers.put("key", CUtils.getApplicationSignatureHashCode(activity));
                headers.put("regName", info.getRegName() == null ? info.getEmailID().split("@")[0] : info.getRegName());
                headers.put(KEY_EMAIL_ID, replaceEmailChar(info.getEmailID()));
                headers.put("gender", info.getGender() == null ? "M" : info.getGender());
                headers.put("monthOfBirth", info.getMonthOfBirth() == null ? month : info.getMonthOfBirth());
                headers.put("minOfBirth", info.getMinOfBirth() == null ? minute : info.getMinOfBirth());
                headers.put("dateOfBirth", info.getDateOfBirth() == null ? day : info.getDateOfBirth());
                headers.put("yearOfBirth", info.getYearOfBirth() == null ? year : info.getYearOfBirth());
                headers.put("hourOfBirth", info.getHourOfBirth() == null ? hour : info.getHourOfBirth());
                headers.put("country", info.getCountry() == null ? "India" : info.getCountry());
                headers.put("state", info.getState() == null ? "" : info.getState());
                headers.put("nearCity", info.getNearCity() == null ? "" : info.getNearCity());
                headers.put("place", info.getPlace() == null ? "Agra" : info.getPlace());
                headers.put("problem", info.getProblem());
                headers.put("serviceId", info.getServiceId());
                headers.put("profileId", info.getProfileId());
                headers.put("price", info.getPrice());
                headers.put("priceRs", info.getPriceRs());
                headers.put("payMode", info.getPayMode());
                headers.put("mobileNo", info.getMobileNo());
                headers.put("KPHN", info.getKphn() == null ? "" : info.getKphn());
                headers.put("TimezoneOfBirth", info.getTimezone() == null ? "" : info.getTimezone());

                headers.put(KEY_AS_USER_ID, replaceEmailChar(CUtils.getUserName(activity)));
                headers.put("asplanid", String.valueOf(CUtils.getUserPurchasedPlanFromPreference(activity)));

                headers.put("LongDegOfBirth", info.getLongDegOfBirth() == null ? "" : info.getLongDegOfBirth());
                headers.put("LongMinOfBirth", info.getLongMinOfBirth() == null ? "" : info.getLongMinOfBirth());
                headers.put("LongEWOfBirth", info.getLongEWOfBirth() == null ? "" : info.getLongEWOfBirth());
                headers.put("LatDegOfBirth", info.getLatDegOfBirth() == null ? "" : info.getLatDegOfBirth());
                headers.put("LatMinOfBirth", info.getLatMinOfBirth() == null ? "" : info.getLatMinOfBirth());
                headers.put("LatNSOfBirth", info.getLatNSOfBirth() == null ? "" : info.getLatNSOfBirth());
                headers.put("device_id", CUtils.getMyAndroidId(activity));
                headers.put("couponcode", info.getCouponCode());

                //com.google.analytics.tracking.android.
                //Log.e("Genrateserviceorder ==", headers.toString());
                return headers;
            }

        };
        // Add the request to the RequestQueue.
        //com.google.analytics.tracking.android.//Log.e("API HIT HERE");
        int socketTimeout = 60000;//30 seconds - change to what you want
        RetryPolicy policy = new DefaultRetryPolicy(socketTimeout, DefaultRetryPolicy.DEFAULT_MAX_RETRIES, DefaultRetryPolicy.DEFAULT_BACKOFF_MULT);
        stringRequest.setRetryPolicy(policy);
        stringRequest.setShouldCache(false);
        queue.add(stringRequest);


    }


