    /**
     * function used to create session on server to measure the ravenue from various ad
     *
     * @param ctx
     * @param partnerId
     */
    public static void createSession(final Context ctx, final String partnerId) {
        Log.e("PartnerId", "createSession partnerId=" + partnerId);
        Log.e("PartnerId", "createSession currentPId=" + currentPId);
        if (!TextUtils.isEmpty(currentPId)) {
            Log.e("PartnerId", "return");
            return;
        }

        if (!CGlobalVariables.currentSession.equalsIgnoreCase(CGlobalVariables.ASTRO_PARTNER_ID)) { //if current session is not Astro
            if (CGlobalVariables.currentSessionTime > 0) {
                long diffTime = System.currentTimeMillis() - CGlobalVariables.currentSessionTime;
                if (diffTime <= 15 * 60 * 1000) { // if difference time is <= 15 minutes the avoid api hit.
                    Log.e("PartnerId", "Return <=15");
                    return;
                }
            }
        }

        //Log.e("PartnerId","partnerId->"+partnerId + "<-> context->"+ctx.getClass().getSimpleName());
        RequestQueue queue = VolleySingleton.getInstance(ctx).getRequestQueue();

        StringRequest stringRequest = new StringRequest(Request.Method.POST, CGlobalVariables.POST_PARTNER_ID,
                new Response.Listener<String>() {
                    @Override
                    public void onResponse(String response) {
                        Log.d("PartnerId resp asp=", response);
                    }

                }

                , new Response.ErrorListener() {
            @Override
            public void onErrorResponse(VolleyError error) {

            }
        }
        ) {
            @Override
            public String getBodyContentType() {
                return "application/x-www-form-urlencoded;charset=UTF-8";
            }

            /**
             * Passing some request headers
             * */
            @Override
            public Map<String, String> getParams() throws AuthFailureError {

                HashMap<String, String> headers = new HashMap<String, String>();
                headers.put("key", CUtils.getApplicationSignatureHashCode(ctx));
                headers.put("prtnr_id", partnerId);
                //Log.e("PartnerId headers=" , headers.toString());
                return headers;
            }

        };

        int socketTimeout = 60000;//30 seconds - change to what you want
        RetryPolicy policy = new DefaultRetryPolicy(socketTimeout, DefaultRetryPolicy.DEFAULT_MAX_RETRIES, DefaultRetryPolicy.DEFAULT_BACKOFF_MULT);
        stringRequest.setRetryPolicy(policy);
        stringRequest.setShouldCache(false);
        if (isCreateFirstSession) {
            new Handler().postDelayed(new Runnable() {
                @Override
                public void run() {
                    Log.e("PartnerId", "1");
                    queue.add(stringRequest);
                    // call java api async
                    callCreateSessionApi(ctx, partnerId);
                    isCreateFirstSession = false;
                }
            }, 5000);
        } else {
            Log.e("PartnerId", "2");
            queue.add(stringRequest);
            // call java api async
            callCreateSessionApi(ctx, partnerId);
        }

        if (!partnerId.contains(CGlobalVariables.ASTRO_PARTNER_ID)) {
            currentPId = partnerId;
        }
    }

    private static void callCreateSessionApi(Context ctx, String partnerId) {
        ApiList api = RetrofitClient.getInstance().create(ApiList.class);
        Call<ResponseBody> call = api.createSession(com.ojassoft.astrosage.varta.utils.CUtils.getApplicationSignatureHashCode(ctx), partnerId);
        call.enqueue(new Callback<ResponseBody>() {
            @Override
            public void onResponse(Call<ResponseBody> call, retrofit2.Response<ResponseBody> response) {
                try {
                    currentPId = "";
                    String myResponse = response.body().string();
                    Log.e("PartnerId", "callCreateSessionApi myResponse=" + myResponse);

                    JSONArray jsonArray = new JSONArray(myResponse);
                    JSONObject jsonObject = jsonArray.getJSONObject(0);
                    String result = jsonObject.getString("Result");
                    if (result.equals("1")) {
                        JSONObject sessionJsonObject = jsonArray.getJSONObject(1);
                        CGlobalVariables.currentSession = sessionJsonObject.getString("PartnerId");
                        Log.e("PartnerId", "currentSession=" + CGlobalVariables.currentSession);
                        CGlobalVariables.currentSessionTime = System.currentTimeMillis();
                    }
                } catch (Exception e) {
                    Log.e("PartnerId", "callCreateSessionApi Exception1=" + e);
                }
            }

            @Override
            public void onFailure(Call<ResponseBody> call, Throwable t) {
                Log.e("PartnerId", "callCreateSessionApi onFailure=" + t);
                currentPId = "";
            }
        });
    }

