    public static String getLanguageBasedUrl(String data, String key) {

        String url = "";
        try {
            JSONObject object = new JSONObject(data);
            if (object.has(key)) {
                url = object.getString(key).trim();
                if (url.equals("")) {
                    url = object.getString("en");
                }
            } else {
                url = object.getString("en");
            }
        } catch (Exception ex) {
            //Log.i(ex.getMessage().toString());
        }

        return url;
    }


