    /**
     * @param context                  -Activity context
     * @param datasaved                - prefrence List of services
     * @param articleIdLastPathSegment - articleId (path)
     * @param sourceActivity           - calling from which activity
     * @param isFromAstroShopService   - true if calling from astroshop service
     */
    public static void goToServiceDescription(Context context, List<ServicelistModal> datasaved, String articleIdLastPathSegment, String sourceActivity, boolean isFromAstroShopService) {

        String result = "";
        boolean isDataFound = false;

        Uri articleIdInUri = Uri.parse(articleIdLastPathSegment);
        String articleIdInUriLAstSegment = articleIdInUri.getLastPathSegment();

        for (ServicelistModal modal : datasaved) {
            result = modal.getServiceDeepLinkURL();

            if (result != null) {
                Uri resultInUri = Uri.parse(result);
                String resultInUriLAstSegment = resultInUri.getLastPathSegment();

                if (resultInUriLAstSegment != null && resultInUriLAstSegment.equalsIgnoreCase(articleIdInUriLAstSegment)) {
                    Intent i = new Intent(context, AstroServiceDownloader.class);
                    context.startService(i);
                    isDataFound = true;
                    Intent itemdescriptionIntent = new Intent(context, ActAstrologerDescription.class);
                    Bundle bundle = new Bundle();
                    bundle.putSerializable("key", modal);
                    bundle.putString("astrologerId", "");
                    CUtils.BRIHAT_KUNDALI_PURCHASE_SOURCE = sourceActivity;
                    itemdescriptionIntent.putExtras(bundle);
                    context.startActivity(itemdescriptionIntent);
                    break;
                }
            }
        }

        if (!isDataFound && !isFromAstroShopService) {
            final int LANGUAGE_CODE = ((AstrosageKundliApplication) (((Activity) context).getApplication())).getLanguageCode();
            CUtils.saveStringData(context, CGlobalVariables.Astroshop_Service_Data + LANGUAGE_CODE, "");
            CUtils.callActAstroServices(context, articleIdLastPathSegment, sourceActivity);
        }
    }


