    public static String getKundliInfo(AstroShopItemDetails itemdetails, int lang) {

        String finalString = "";
        try {
            if (itemdetails != null) {
                String str = itemdetails.getKdetail();
                if (str != null && !str.isEmpty()) {
                    BeanHoroPersonalInfo info = new Gson().fromJson(str, BeanHoroPersonalInfo.class);
                    if (info != null) {
                        Float tz = 0.0f;
                        //Mohit,12/12/2007,15:32:22,Agra,78E27,27N45,5.5
                        String name = info.getName();
                        int date = info.getDateTime().getDay();
                        int month = info.getDateTime().getMonth() + 1;
                        int year = info.getDateTime().getYear();
                        int hour = info.getDateTime().getHour();
                        int min = info.getDateTime().getMin();
                        int sec = info.getDateTime().getSecond();
                        float dst = info.getDST();
                        String gender = info.getGender();

                        String city = info.getPlace().getCityName();
                        String lat = info.getPlace().getLatDeg() + info.getPlace().getLatDir() + info.getPlace().getLatMin();
                        String _long = info.getPlace().getLongDeg() + info.getPlace().getLongDir() + info.getPlace().getLongMin();
                        String timezone = "";

                        if (info.getPlace().getTimeZone() != null && !info.getPlace().getTimeZone().isEmpty()) {
                            timezone = info.getPlace().getTimeZone();
                        } else {
                            timezone = "5.5";
                        }
                        try {
                            tz = Float.parseFloat(timezone) + dst;

                        } catch (Exception e) {
                            e.printStackTrace();
                        }

                        //android.util.//Log.e("Kundli", finalString);

                        finalString = "#" + name + ", " + gender + ", " + date + "/" + month + "/" + year + ", " + hour + ":" + min + ":" + sec + ", " + city + ", " + lat + ", " + _long + ", " + tz + "," + " Lang: " + getLanguageKey(lang);
                    }
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }


        return finalString;
    }

    public static float getAdjustedTimezone(String dst, String timezone) {
        Float tz = 0.0f;
        try {
            if (timezone != null && !timezone.isEmpty()) {
                timezone = timezone;
            } else {
                timezone = "5.5";
            }

            tz = Float.parseFloat(timezone) + Float.parseFloat(dst);


        } catch (Exception e) {
            e.printStackTrace();
        }
        return tz;
    }

    public static Map<String, String> splitQuery(URL url) throws UnsupportedEncodingException {
        Map<String, String> query_pairs = new LinkedHashMap<String, String>();
        String query = url.getQuery();
        String[] pairs = query.split("&");
        for (String pair : pairs) {
            int idx = pair.indexOf("=");
            query_pairs.put(URLDecoder.decode(pair.substring(0, idx), "UTF-8"), URLDecoder.decode(pair.substring(idx + 1), "UTF-8"));
        }
        return query_pairs;
    }

