    /**
     * Queues the selected language topic so background recovery can subscribe once FCM registration is available.
     */
    public static void queueLanguageTopicForRetry(Context context, int languageCode) {
        if (context == null) {
            return;
        }

        try {
            String topicName = getTopicName(languageCode);
            if (!TextUtils.isEmpty(topicName)) {
                saveStringData(context, CGlobalVariables.LANGUAGE_TOPIC_NEED_TO_SEND_TO_GOOGLE_SERVER, topicName);
            }
        } catch (Exception ex) {
            //Log.e("Exception", ex.getMessage());
        }
    }

    /**
     * Subscribe to any GCM topics of interest, as defined by the TOPICS constant.
     *
     * @param token   GCM token
     * @param topic
     * @param context
     * @throws IOException if unable to reach the GCM PubSub service
     */
    // [START subscribe_topics]
    public static synchronized void subscribeTopics(String token, String topic, Context context) throws IOException {
        AstrosageKundliApplication.notificationIssueLogs = "\n" + AstrosageKundliApplication.notificationIssueLogs + "\n" + "subscribeTopics() = " + topic;

        try {
            if (topic.contains("_NEW")) {
                String topicToUnsubscribe = topic.substring(0, (topic.length() - 4));
                unSubscribeTopics(token, topicToUnsubscribe, context);
            }
            //FirebaseMessaging.getInstance().subscribeToTopic(topic);

            FirebaseMessaging.getInstance().subscribeToTopic(topic).addOnSuccessListener(unused -> {
                AstrosageKundliApplication.notificationIssueLogs = "\n" + AstrosageKundliApplication.notificationIssueLogs + "\n" + "subscribeTopics() sucess=" + topic;
            }).addOnFailureListener(e -> {
                AstrosageKundliApplication.notificationIssueLogs = "\n" + AstrosageKundliApplication.notificationIssueLogs + "\n" + "subscribeTopics() failed=" + topic;
                saveTopicsForSubscribe(topic);
            });
        } catch (Exception ex) {
            AstrosageKundliApplication.notificationIssueLogs = "\n" + AstrosageKundliApplication.notificationIssueLogs + "\n" + "subscribeTopics() exp=" + ex;
            saveTopicsForSubscribe(topic);
            // Log.e("Exception", ex.getMessage());
        }
    }
    // [END subscribe_topics]

    /**
     * Unsubscribe to GCM topics
     *
     * @param token
     * @param topic
     * @param context
     * @throws IOException
     */
    // [START unsubscribe_topics]
    public static synchronized void unSubscribeTopics(String token, String topic, Context context) throws IOException {
        try {
            FirebaseMessaging.getInstance().unsubscribeFromTopic(topic);
        } catch (Exception ex) {
            //Log.e("Exception", ex.getMessage());
        }
    }
    // [END unsubscribe_topics]

    /**
     * Persists failed topic subscriptions under the correct retry bucket so background recovery can replay them.
     */
    private static void saveTopicsForSubscribe(String topic) {
        try {
            if (topic.equals(CGlobalVariables.TOPIC_ALL)) {
                CUtils.saveStringData(AstrosageKundliApplication.getAppContext(), CGlobalVariables.TOPIC_ALL_NEED_TO_SEND_TO_GOOGLE_SERVER, topic);
            } else if (topic.equals(CGlobalVariables.TOPIC_VERSION + BuildConfig.VERSION_CODE)) {
                CUtils.saveStringData(AstrosageKundliApplication.getAppContext(), CGlobalVariables.VERSION_TOPIC_NEED_TO_SEND_TO_GOOGLE_SERVER, topic);
            } else if (topic.equals(CGlobalVariables.TOPIC_PRODUCTS) || topic.equals(CGlobalVariables.TOPIC_SERVICES) || topic.equals(CGlobalVariables.TOPIC_ASKAQUESTION) || topic.equals(CGlobalVariables.TOPIC_CLOUDPLAN)) {
                CUtils.saveStringData(AstrosageKundliApplication.getAppContext(), CGlobalVariables.OTHER_TOPIC_NEED_TO_SEND_TO_GOOGLE_SERVER, topic);
            } else if (isLanguageNotificationTopic(topic)) {
                CUtils.saveStringData(AstrosageKundliApplication.getAppContext(), CGlobalVariables.LANGUAGE_TOPIC_NEED_TO_SEND_TO_GOOGLE_SERVER, topic);
            } else {
                CUtils.saveStringData(AstrosageKundliApplication.getAppContext(), CGlobalVariables.EXTRA_TOPIC_NEED_TO_SEND_TO_GOOGLE_SERVER, topic);
            }
        } catch (Exception ex) {
            //Log.e("Exception", ex.getMessage());
        }
    }

    /**
     * Identifies language-specific notification topics so retry storage does not mix them with non-language topics.
     */
    private static boolean isLanguageNotificationTopic(String topic) {
        return topic.equals(CGlobalVariables.TOPIC_ENGLISH)
                || topic.equals(CGlobalVariables.TOPIC_HINDI)
                || topic.equals(CGlobalVariables.TOPIC_TAMIL)
                || topic.equals(CGlobalVariables.TOPIC_BANGALI)
                || topic.equals(CGlobalVariables.TOPIC_MARATHI)
                || topic.equals(CGlobalVariables.TOPIC_KANNADA)
                || topic.equals(CGlobalVariables.TOPIC_TELUGU)
                || topic.equals(CGlobalVariables.TOPIC_MALAYALAM)
                || topic.equals(CGlobalVariables.TOPIC_GUJARATI)
                || topic.equals(CGlobalVariables.TOPIC_ODIA)
                || topic.equals(CGlobalVariables.TOPIC_ASAMMESSE)
                || topic.equals(CGlobalVariables.TOPIC_SPANISH)
                || topic.equals(CGlobalVariables.TOPIC_CHINESE)
                || topic.equals(CGlobalVariables.TOPIC_JAPANESE)
                || topic.equals(CGlobalVariables.TOPIC_PORTUGUESE)
                || topic.equals(CGlobalVariables.TOPIC_GERMAN)
                || topic.equals(CGlobalVariables.TOPIC_ITALIAN)
                || topic.equals(CGlobalVariables.TOPIC_FRENCH);
    }

    public static void fetchProductsOffer(final Activity activity, RequestQueue queue, final String type, final String language) {
        final IAstroOffersData callback = (IAstroOffersData) activity;
        String url = CGlobalVariables.astrosage_offer_details_url;

        StringRequest stringRequest = new StringRequest(Request.Method.POST, url,
                new Response.Listener<String>() {
                    @Override
                    public void onResponse(String response) {

                        try {
                            String str = new String(response.getBytes(StandardCharsets.ISO_8859_1), StandardCharsets.UTF_8);
                            JSONArray array = new JSONArray(str);
                            JSONObject obj = array.getJSONObject(0);
                            String result = obj.getString("Description");

                            callback.getResult(result);

                        } catch (Exception e) {
                        }

                    }

                }

                , new Response.ErrorListener() {
            @Override
            public void onErrorResponse(VolleyError error) {
                // Log.e("Error Through" + error.getMessage());
                VolleyLog.d("VolleyError: " + error.getMessage());
                //   mTextView.setText("That didn't work!");
                if (error instanceof TimeoutError) {
                    VolleyLog.d("TimeoutError: " + error.getMessage());
                } else if (error instanceof NoConnectionError) {
                    VolleyLog.d("NoConnectionError: " + error.getMessage());
                } else if (error instanceof AuthFailureError) {
                    VolleyLog.d("AuthFailureError: " + error.getMessage());
                    //TODO
                } else if (error instanceof ServerError) {
                    //TODO
                    VolleyLog.d("ServerError: " + error.getMessage());
                } else if (error instanceof NetworkError) {
                    //TODO
                    VolleyLog.d("NetworkError: " + error.getMessage());
                } else if (error instanceof ParseError) {
                    //TODO
                    VolleyLog.d("ParseError: " + error.getMessage());

                }
            }
        }
        ) {
            @Override
            public String getBodyContentType() {
                return "application/x-www-form-urlencoded;charset=UTF-8";
            }

            /**
             * Passing some request headers
             * */
            @Override
            public Map<String, String> getParams() throws AuthFailureError {
                HashMap<String, String> headers = new HashMap<String, String>();
                headers.put("key", CUtils.getApplicationSignatureHashCode(activity));
                headers.put("type", type);
                headers.put("languagecode", language);

                return headers;
            }

        };

        int socketTimeout = 60000;//30 seconds - change to what you want
        RetryPolicy policy = new DefaultRetryPolicy(socketTimeout, DefaultRetryPolicy.DEFAULT_MAX_RETRIES, DefaultRetryPolicy.DEFAULT_BACKOFF_MULT);
        stringRequest.setRetryPolicy(policy);
        stringRequest.setShouldCache(false);
        queue.add(stringRequest);
    }

