    public static void updatePaidStatus(Context ctx, int position, String orderID, String ispaid, String chatID, AstrologerServiceInfo astrologerServiceInfo) {
        //Log.e("updatePaidStatus", "enter");
        try {
            //Log.e("updatePaidStatus", "position " + position);
            ArrayList<MessageDecode> list = getDataFromPrefrence(ctx);
            MessageDecode msg = list.get(position);
            msg.setOrderId(orderID);
            msg.setNotPaidLayoutShow(ispaid);
            if (ispaid.equalsIgnoreCase("0")) {
                msg.setNotPaidLayoutShow("True");
            } else {
                msg.setNotPaidLayoutShow("False");
            }
            msg.setChatId(chatID);
            if (astrologerServiceInfo != null) {
                msg.setAstrologerServiceInfo(astrologerServiceInfo);
            }
            list.set(position, msg);
            InternalStorage.writeObject(ctx, list);
        } catch (Exception e) {
            e.printStackTrace();
            //Log.e("updatePaidStatus exp ", e.toString());
        }
        //Log.e("updatePaidStatus", "exit");
    }

