    /**
     * @param data
     * @param lanKey
     * @param horoscopeKey
     * @return
     * @author Amit Rautela
     * @desc This method is used to parse static notification horoscope data from JSON.
     */
    private static String[] fetchHoroscopeNotificationDataFromJson(String data, String lanKey, String horoscopeKey) {
        String[] arr = new String[2];
        try {
            JSONObject object = new JSONObject(data);
            if (object.has(horoscopeKey)) {

                String horoData = object.getString(horoscopeKey);
                JSONObject innerObject = new JSONObject(horoData);

                if (innerObject.has(lanKey)) {
                    String horoscopeData = innerObject.getString(lanKey);
                    JSONObject innerObject1 = new JSONObject(horoscopeData);

                    if (innerObject1.has("title") && innerObject1.has("desc")) {
                        String title = innerObject1.getString("title");
                        String desc = innerObject1.getString("desc");

                        if (title == null || title.equals("")) {
                            arr[0] = "";
                            arr[1] = "";
                        } else {
                            arr[0] = title.trim();
                            arr[1] = desc.trim();
                        }
                    } else {
                        arr[0] = "";
                        arr[1] = "";
                    }
                } else {
                    arr[0] = "";
                    arr[1] = "";
                }

            } else {
                arr[0] = "";
                arr[1] = "";
            }
        } catch (Exception ex) {
            arr[0] = "";
            arr[1] = "";
        }
        return arr;
    }

    /**
     * @param data
     * @param lanKey
     * @param horoscopeKey
     * @return
     * @author Amit Rautela
     * @desc This method is used to check, data is available or not of static notification horoscope for specific language. If not, will get data of english language.
     */
    public synchronized static String[] getLanguageBasedHoroscopeNotificationData(String data, String lanKey, String horoscopeKey) {
        String[] arr = null;
        try {
            arr = fetchHoroscopeNotificationDataFromJson(data, lanKey, horoscopeKey);
            if (arr[0] != null && arr[0].equals("")) {
                arr = fetchHoroscopeNotificationDataFromJson(data, "en", horoscopeKey);
            }
        } catch (Exception ex) {
            //Log.i(ex.getMessage().toString());
        }

        return arr;
    }


    /**
     * Method to apply coupon code on service
     *
     * @param activity
     * @param typeface
     * @param queue
     * @param couponCode
     * @param serviceId
     */

    public static void applyCoupon(final Activity activity, Typeface typeface, RequestQueue queue, final String couponCode, final String serviceId) {
        String orderUrl = CGlobalVariables.APPLY_COUPON;

        //  orderUrl="http://192.168.1.180/ac/astroshop/service-order-paytm.asp";
        final IAskCallback callback = (IAskCallback) activity;
        final CustomProgressDialog pd = new CustomProgressDialog(activity, typeface);
        pd.setCancelable(false);
        pd.show();

        StringRequest stringRequest = new StringRequest(Request.Method.POST, orderUrl,
                new Response.Listener<String>() {
                    @Override
                    public void onResponse(String response) {
                        //com.google.analytics.tracking.android.
                        //Log.e("Ask from server +", response.toString());
                        callback.getCallBack(response, callBack.APPLY_SERVICE_COUPON, "", "");
                        hideProgressBar(pd);

                    }

                }

                , new Response.ErrorListener() {
            @Override
            public void onErrorResponse(VolleyError error) {
                callback.getCallBack("", callBack.APPLY_SERVICE_COUPON, "", "");

                // //Log.e("Error Through" + error.getMessage());
                VolleyLog.d("VolleyError: " + error.getMessage());
                //   mTextView.setText("That didn't work!");
                hideProgressBar(pd);
            }
        }
        ) {
            @Override
            public String getBodyContentType() {
                return "application/x-www-form-urlencoded;charset=UTF-8";
            }

            /**
             * Passing some request headers
             * */
            @Override
            public Map<String, String> getParams() throws AuthFailureError {


                HashMap<String, String> headers = new HashMap<String, String>();
                headers.put("key", CUtils.getApplicationSignatureHashCode(activity));
                headers.put("ServiceId", serviceId);
                headers.put("couponcode", couponCode);
                //headers.put("asuserid", CUtils.getUserName(activity));
                headers.put(CGlobalVariables.KEY_AS_USER_ID, CUtils.replaceEmailChar(CUtils.getUserName(activity)));
                headers.put("asplanid", String.valueOf(CUtils.getUserPurchasedPlanFromPreference(activity)));

                //com.google.analytics.tracking.android.//Log.e("Request hit==" + headers.toString());
                return headers;
            }

        };
        // Add the request to the RequestQueue.
        //com.google.analytics.tracking.android.//Log.e("API HIT HERE");
        int socketTimeout = 60000;//30 seconds - change to what you want
        RetryPolicy policy = new DefaultRetryPolicy(socketTimeout, DefaultRetryPolicy.DEFAULT_MAX_RETRIES, DefaultRetryPolicy.DEFAULT_BACKOFF_MULT);
        stringRequest.setRetryPolicy(policy);
        stringRequest.setShouldCache(false);
        queue.add(stringRequest);


    }

    public static ArrayList<Integer> returDayandMonth(String festivalDate) {


        ArrayList<Integer> arrayList = new ArrayList<>();

        try {
            Date obj = new SimpleDateFormat("dd/MM/yyyy").parse(festivalDate);
            Calendar calendar = Calendar.getInstance();
            calendar.setTime(obj);
            arrayList.add(calendar.get(Calendar.DAY_OF_WEEK));
            arrayList.add(calendar.get(Calendar.MONTH));
        } catch (ParseException e) {
            e.printStackTrace();
        }
        return arrayList;
    }

    public static void onAddEventClicked(Context context, String festName, Calendar startDate, Calendar endDate) {
        try {
            Intent intent = new Intent(Intent.ACTION_INSERT);
            intent.setType("vnd.android.cursor.item/event");

            intent.putExtra(CalendarContract.EXTRA_EVENT_BEGIN_TIME, startDate.getTimeInMillis());
            intent.putExtra(CalendarContract.EXTRA_EVENT_END_TIME, endDate.getTimeInMillis());
            intent.putExtra(CalendarContract.EXTRA_EVENT_ALL_DAY, true);

            intent.putExtra(CalendarContract.Events.TITLE, festName);
            intent.putExtra(CalendarContract.Events.DESCRIPTION, "");
            intent.putExtra(CalendarContract.Events.EVENT_LOCATION, "");
            intent.putExtra(CalendarContract.Events.RRULE, "FREQ=YEARLY");

            context.startActivity(intent);
        } catch (Exception e) {
            e.printStackTrace();
        }

    }

