    /*method to send analytics*/

    public static void googleAnalyticSendWitPlayServieForPurchased(Activity activity,
                                                                   String action, String label, String screenName,
                                                                   double priceValue, String purchaseSource) {
        try {
            String labell = "";
            if (action != null && !action.isEmpty()) {
                if (action.equalsIgnoreCase(CGlobalVariables.GOOGLE_ANALYTIC_CLOUD)) {
                    labell = CGlobalVariables.GOOGLE_ANALYTIC_CLOUD + "_" + label;

                } else if (action.equalsIgnoreCase(CGlobalVariables.GOOGLE_ANALYTIC_ASTROSHOP_SERVICE)) {
                    if (label.toLowerCase().contains(CGlobalVariables.GOOGLE_ANALYTIC_ASTROSHOP_SERVICE.toLowerCase())) {
                        labell = label;
                    } else {
                        labell = CGlobalVariables.GOOGLE_ANALYTIC_ASTROSHOP_SERVICE + "_" + label;
                    }
                } else if (action.equalsIgnoreCase(CGlobalVariables.GOOGLE_ANALYTIC_PRODUCT)) {
                    if (label.toLowerCase().contains(CGlobalVariables.GOOGLE_ANALYTIC_PRODUCT.toLowerCase())) {
                        labell = label;
                    } else {
                        labell = CGlobalVariables.GOOGLE_ANALYTIC_PRODUCT + "_" + label;
                    }
                }
            }

            CUtils.fcmAnalyticsEcommerceEvents(labell, FirebaseAnalytics.Event.PURCHASE, priceValue, CGlobalVariables.CURRENCY_INDIA, purchaseSource);
        } catch (Exception e) {
            //Log.e("Tracker ", e.getMessage());
        }

    }

