    public static void getOrderIDAndChatId(final Activity activity, Typeface typeface, RequestQueue queue, final ServicelistModal servicelistModal, final String fullJsonDataObj, final AstrologerServiceInfo info, final String chatId) {
        final String[] order_id = new String[2];
        String orderUrl = CGlobalVariables.GET_ASTROCHAT_ORDERID_PAYTM;

        //  orderUrl="http://192.168.1.180/ac/astroshop/service-order-paytm.asp";
        final IAskCallback callback = (IAskCallback) activity;
        final CustomProgressDialog pd = new CustomProgressDialog(activity, typeface);
        pd.setCancelable(false);
        pd.show();

        StringRequest stringRequest = new StringRequest(Request.Method.POST, orderUrl,
                new Response.Listener<String>() {
                    @Override
                    public void onResponse(String response) {
                        //com.google.analytics.tracking.android.//Log.e("Ask from server +" + response.toString());
                        //Log.e("Genrateserviceorder1", response.toString());
                        try {
                            JSONArray array = new JSONArray(response);
                            JSONObject obj = array.getJSONObject(0);
                            String priceInRS = "", priceInDollor = "";
                            String result = obj.getString("Result");

                            if (result.equalsIgnoreCase("1")) {

                                order_id[0] = obj.getString("GeneratedOrderId");
                                order_id[1] = obj.getString("ChatId");
                                if (obj.has("PriceRsToPay")) {
                                    priceInRS = obj.getString("PriceRsToPay");
                                }
                                if (obj.has("PriceToPay")) {
                                    priceInDollor = obj.getString("PriceToPay");
                                }
                                callback.getCallBackForChat(order_id, callBack.GET_ORDER_ID, priceInDollor, priceInRS);

                            } else {
                                order_id[0] = "";
                                order_id[1] = "";
                                callback.getCallBackForChat(order_id, callBack.GET_ORDER_ID, "", "");

                            }

                        } catch (Exception e) {
                        }
                        hideProgressBar(pd);

                    }

                }

                , new Response.ErrorListener() {
            @Override
            public void onErrorResponse(VolleyError error) {
                order_id[0] = "";
                order_id[1] = "";
                callback.getCallBackForChat(order_id, callBack.GET_ORDER_ID, "", "");

                // //Log.e("Error Through" + error.getMessage());
                VolleyLog.d("VolleyError: " + error.getMessage());
                //   mTextView.setText("That didn't work!");
                if (error instanceof TimeoutError) {
                    VolleyLog.d("TimeoutError: " + error.getMessage());
                } else if (error instanceof NoConnectionError) {
                    VolleyLog.d("NoConnectionError: " + error.getMessage());
                } else if (error instanceof AuthFailureError) {
                    VolleyLog.d("AuthFailureError: " + error.getMessage());
                    //TODO
                } else if (error instanceof ServerError) {
                    //TODO
                    VolleyLog.d("ServerError: " + error.getMessage());
                } else if (error instanceof NetworkError) {
                    //TODO
                    VolleyLog.d("NetworkError: " + error.getMessage());
                } else if (error instanceof ParseError) {
                    //TODO
                    VolleyLog.d("ParseError: " + error.getMessage());

                }
                hideProgressBar(pd);
            }
        }
        ) {
            @Override
            public String getBodyContentType() {
                return "application/x-www-form-urlencoded;charset=UTF-8";
            }

            /**
             * Passing some request headers
             * */
            @Override
            public Map<String, String> getParams() throws AuthFailureError {


                String appVerName = LibCUtils.getApplicationVersionToShow(activity);
                HashMap<String, String> headers = new HashMap();
                headers.put("Key", CUtils.getApplicationSignatureHashCode(activity));
                headers.put("type", "insert");
                headers.put("apkversion", appVerName);

                headers.put("astrologerchatfulldata", replaceEmailFromJson(fullJsonDataObj, "emailID"));
                headers.put("problem", info.getProblem());
              /*  if (messageDecodeSend.getChatId() == null) {
                    messageDecodeSend.setChatId("");
                }*/
                headers.put("chatid", chatId);
                headers.put("payMode", "Paytm");
                headers.put("priceRs", servicelistModal.getPriceInRS());
                headers.put("price", servicelistModal.getPriceInDollor());

                //new parameter
                headers.put("ordersource", "astroSage_Kundli");
                headers.put("chattitle", "");
                headers.put("androidid", CUtils.getMyAndroidId(activity));

                headers.put(KEY_AS_USER_ID, CUtils.replaceEmailChar(CUtils.getUserName(activity)));
                headers.put("asuserplanid", String.valueOf(CUtils.getUserPurchasedPlanFromPreference(activity)));

                headers.put("pricebeforeclouddiscount", servicelistModal.getPriceInDollorBeforeCloudPlanDiscount());
                headers.put("pricersbeforeclouddiscount", servicelistModal.getPriceInRSBeforeCloudPlanDiscount());

                //////////
                headers.put("regName", info.getRegName());
                headers.put(KEY_EMAIL_ID, CUtils.replaceEmailChar(info.getEmailID()));
                headers.put("gender", info.getGender());
                headers.put("monthOfBirth", info.getMonthOfBirth());
                headers.put("minOfBirth", info.getMinOfBirth());
                headers.put("dateOfBirth", info.getDateOfBirth());
                headers.put("yearOfBirth", info.getYearOfBirth());
                headers.put("hourOfBirth", info.getHourOfBirth());
                headers.put("country", info.getCountry());
                headers.put("state", info.getState());
                headers.put("nearCity", info.getNearCity());
                headers.put("place", info.getPlace());
                headers.put("problem", info.getProblem());
                headers.put("serviceId", info.getServiceId());
                headers.put("profileId", info.getProfileId());
               /* headers.put("price", info.getPrice());
                headers.put("priceRs", info.getPriceRs());*/
                headers.put("payMode", info.getPayMode());
                headers.put("mobileNo", info.getMobileNo());
                headers.put("KPHN", info.getKphn());
                headers.put("TimezoneOfBirth", info.getTimezone());

                headers.put("LongDegOfBirth", info.getLongDegOfBirth());
                headers.put("LongMinOfBirth", info.getLongMinOfBirth());
                headers.put("LongEWOfBirth", info.getLongEWOfBirth());
                headers.put("LatDegOfBirth", info.getLatDegOfBirth());
                headers.put("LatMinOfBirth", info.getLatMinOfBirth());
                headers.put("LatNSOfBirth", info.getLatNSOfBirth());
                headers.put("device_id", CUtils.getMyAndroidId(activity));
                headers.put("couponcode", info.getCouponCode());
                //////////////

                return headers;
            }

        };
        int socketTimeout = 60000;//30 seconds - change to what you want
        RetryPolicy policy = new DefaultRetryPolicy(socketTimeout, DefaultRetryPolicy.DEFAULT_MAX_RETRIES, DefaultRetryPolicy.DEFAULT_BACKOFF_MULT);
        stringRequest.setRetryPolicy(policy);
        stringRequest.setShouldCache(false);
        queue.add(stringRequest);
    }


    /**
     * @param itemDetails
     * @return list of same group item
     */
    public static ArrayList<AstroShopItemDetails> getAllchilditems(AstroShopItemDetails itemDetails, List<AstroShopItemDetails> allData) {
        ArrayList<AstroShopItemDetails> itemList = new ArrayList<>();
    /* @param itemDetails
     @return list of same group item*/

        if (itemDetails.getHaschild().equalsIgnoreCase("True")) {
            for (AstroShopItemDetails item : allData) {
                if (itemDetails.getP_ParentId().equalsIgnoreCase(item.getP_ParentId())) {
                    itemList.add(item);
                }
            }
        } else {
            itemList.add(itemDetails);
        }

        return itemList;
    }

    //save topics in share preference
    public static void storeTopics(Context context, ArrayList<TopicDetail> topicList) {
// used for store arrayList in json format
        try {
            SharedPreferences settings;
            SharedPreferences.Editor editor;
            settings = context.getSharedPreferences(CGlobalVariables.PREFS_NAME, Context.MODE_PRIVATE);
            editor = settings.edit();
            Gson gson = new Gson();
            String jsonTopics = gson.toJson(topicList);
            editor.putString(CGlobalVariables.topicListKey, jsonTopics);
            editor.commit();
        } catch (Exception e) {

        }
    }

    //Load all topics in list
    public static ArrayList<TopicDetail> loadTopics(Context context) {
// used for retrieving arraylist from json formatted string
        try {
            SharedPreferences settings;
            List topicDetailList;
            settings = context.getSharedPreferences(CGlobalVariables.PREFS_NAME, Context.MODE_PRIVATE);
            if (settings.contains(CGlobalVariables.topicListKey)) {
                String jsonFavorites = settings.getString(CGlobalVariables.topicListKey, null);
                Gson gson = new Gson();
                TopicDetail[] topicDetails = gson.fromJson(jsonFavorites, TopicDetail[].class);
                topicDetailList = Arrays.asList(topicDetails);
                topicDetailList = new ArrayList(topicDetailList);
                return (ArrayList<TopicDetail>) topicDetailList;
            } else {
                return null;
            }
        } catch (Exception e) {
            return null;
        }
    }

    //Add topics in list
    public static ArrayList<TopicDetail> addTopicsInList(Context context) {
        TopicDetail topicDetail1 = new TopicDetail();
        topicDetail1.setTopicName("Cricket");
        topicDetail1.setTopicId(CGlobalVariables.TOPIC_CRICKET);
        topicDetail1.setSubscribed(false);

        TopicDetail topicDetail2 = new TopicDetail();
        topicDetail2.setTopicName("Share Market");
        topicDetail2.setTopicId(CGlobalVariables.TOPIC_SHARE_MARKET);
        topicDetail2.setSubscribed(false);

        TopicDetail topicDetail3 = new TopicDetail();
        topicDetail3.setTopicName("Bollywood");
        topicDetail3.setTopicId(CGlobalVariables.TOPIC_BOLLYWOOD);
        topicDetail3.setSubscribed(false);

        TopicDetail topicDetail4 = new TopicDetail();
        topicDetail4.setTopicName("New Magazine");
        topicDetail4.setTopicId(CGlobalVariables.TOPIC_NEW_MAGAZINE);
        topicDetail4.setSubscribed(false);

        //added by abhishek to subscribe the politics topic
        TopicDetail topicDetail5 = new TopicDetail();
        topicDetail5.setTopicName("Politics");
        topicDetail5.setTopicId(CGlobalVariables.TOPIC_POLITICS);
        topicDetail5.setSubscribed(false);

        ArrayList<TopicDetail> topicList = loadTopics(context);
        if (topicList == null) {
            topicList = new ArrayList<TopicDetail>();
        }
        if (!topicList.contains(topicDetail1)) {
            topicList.add(topicDetail1);
        }
        if (!topicList.contains(topicDetail2)) {
            topicList.add(topicDetail2);
        }
        if (!topicList.contains(topicDetail3)) {
            topicList.add(topicDetail3);
        }
        if (!topicList.contains(topicDetail4)) {
            topicList.add(topicDetail4);
        }
        if (!topicList.contains(topicDetail5)) {
            topicList.add(topicDetail5);
        }
        return topicList;

    }


