    public static void saveArrayListStringForHoroscope(Context context, ArrayList<String> stringArrayList, String savePrefKey) {
        try {
            SharedPreferences sharedPrefs = PreferenceManager.getDefaultSharedPreferences(context);
            SharedPreferences.Editor editor = sharedPrefs.edit();
            Gson gson = new Gson();
            String json = gson.toJson(stringArrayList);
            editor.putString(savePrefKey, json);
            editor.commit();
        } catch (Exception e) {
            e.printStackTrace();
        }

    }

    public static ArrayList<String> getArrayListStringForHoroscope(Context context, String savePrefKey) {
        ArrayList<String> arrayList = null;
        try {
            SharedPreferences sharedPrefs = PreferenceManager.getDefaultSharedPreferences(context);
            Gson gson = new Gson();
            String json = sharedPrefs.getString(savePrefKey, "");
            Type type = new TypeToken<ArrayList<String>>() {
            }.getType();
            arrayList = gson.fromJson(json, type);
        } catch (Exception e) {
            e.printStackTrace();
        }
        if (arrayList == null) {
            arrayList = new ArrayList<>();
        }
        return arrayList;
    }


