    public static String formatDateForShipingDetail(String dateString) {
        String stringDate = "";
        try {
//Mar 11 2016 2:21PM
            if (dateString != null) {
//SimpleDateFormat dt = new SimpleDateFormat("MM/dd/yyyy hh:mm:ss a",Locale.ENGLISH);

                SimpleDateFormat dt = new SimpleDateFormat("yyyy-MM-dd hh:mm", Locale.ENGLISH);

                Date date = dt.parse(dateString);

// *** same for the format String below
                SimpleDateFormat dt1 = new SimpleDateFormat("dd-MMM-yyyy hh:mm a", Locale.ENGLISH);
                stringDate = dt1.format(date);
            }
            return stringDate;
        } catch (ParseException parseException) {
//android.util.//Log.e("date format", "" + parseException.getMessage());
        }
        return stringDate;
    }

