    public static int convertDpToPx(Context context, int dip) {
        Resources r = context.getResources();
        float px = TypedValue.applyDimension(
                TypedValue.COMPLEX_UNIT_DIP,
                dip,
                r.getDisplayMetrics()
        );
        return (int) px;
    }

    public static String extractYTId(String ytUrl) {
        String pattern = "(?<=youtu.be/|watch\\?v=|/videos/|embed\\/)[^#\\&\\?]*";
        Pattern compiledPattern = Pattern.compile(pattern);
        Matcher matcher = compiledPattern.matcher(ytUrl);
        if (matcher.find()) {
            return matcher.group();
        } else {
            return null;
        }
    }


    public static void postProductRazorPayDetail(final Activity activity, Typeface typeface, RequestQueue queue, final String orderId, final String statusCode, final String totalAmount, final String payId, final String response) {
        final IAskCallback callback = (IAskCallback) activity;

        String orderUrl = CGlobalVariables.UPDATE_STATUS_PRODUCT_RAZOR_PAY;
        final CustomProgressDialog pd = new CustomProgressDialog(activity, typeface);
        pd.setCancelable(false);
        pd.show();

        StringRequest stringRequest = new StringRequest(Request.Method.POST, orderUrl,
                new Response.Listener<String>() {
                    @Override
                    public void onResponse(String response) {
                        hideProgressBar(pd);
                        //com.google.analytics.tracking.android.//Log.e("OrderResponse from server +" + response.toString());
                        try {
                            JSONArray array = new JSONArray(response);
                            JSONObject obj = array.getJSONObject(0);
                            String result = obj.getString("Result");
                            if (result.equalsIgnoreCase("1")) {
                                callback.getCallBack("1", callBack.POST_PRODUCT_RAZORPAYSTATUS, "", "");
                            } else {
                                callback.getCallBack("0", callBack.POST_PRODUCT_RAZORPAYSTATUS, "", "");
                            }

                        } catch (Exception e) {
                        }

                    }

                }

                , new Response.ErrorListener() {
            @Override
            public void onErrorResponse(VolleyError error) {
                hideProgressBar(pd);
                callback.getCallBack("0", callBack.POST_PRODUCT_RAZORPAYSTATUS, "", "");

                // //Log.e("Error Through" + error.getMessage());
                VolleyLog.d("VolleyError: " + error.getMessage());
                //   mTextView.setText("That didn't work!");

            }
        }
        ) {
            @Override
            public String getBodyContentType() {
                return "application/x-www-form-urlencoded;charset=UTF-8";
            }

            /**
             * Passing some request headers
             * */
            @Override
            public Map<String, String> getParams() throws AuthFailureError {
//                key,name,emailid,address,city,landmark,state,country,paymode,prId,pincode
//                mobileno,prCatId,shippingcost,productcost,makeitdefault
                HashMap<String, String> headers = new HashMap<String, String>();
                headers.put("key", CUtils.getApplicationSignatureHashCode(activity));
                headers.put("amount", totalAmount);
                headers.put("orderid", orderId);
                headers.put("paycurr", "INR");
                headers.put("status", statusCode);
                headers.put("profile_Id", "");
                headers.put("paymentid", payId);
                headers.put("razorpayresponse", response);

                //Log.i(TAG, "razor: " + headers.toString());
                //com.google.analytics.tracking.android.//Log.e("Request post hit==" + headers.toString());
                return headers;
            }

        };
        // Add the request to the RequestQueue.
        //com.google.analytics.tracking.android.//Log.e("API HIT HERE");
        int socketTimeout = 60000;//30 seconds - change to what you want
        RetryPolicy policy = new DefaultRetryPolicy(socketTimeout, DefaultRetryPolicy.DEFAULT_MAX_RETRIES, DefaultRetryPolicy.DEFAULT_BACKOFF_MULT);
        stringRequest.setRetryPolicy(policy);
        stringRequest.setShouldCache(false);
        queue.add(stringRequest);
    }


