    public static String getLuckyColor(Context context, int luckyNumber) {
        String[][] luckyColor = {{context.getResources().getString(R.string.purple), context.getResources().getString(R.string.smoke)},
                {context.getResources().getString(R.string.orange), context.getResources().getString(R.string.gold)},
                {context.getResources().getString(R.string.silver), context.getResources().getString(R.string.white)},
                {context.getResources().getString(R.string.saffron), context.getResources().getString(R.string.yellow)},
                {context.getResources().getString(R.string.brown), context.getResources().getString(R.string.grey)},
                {context.getResources().getString(R.string.green), context.getResources().getString(R.string.turquoise)},
                {context.getResources().getString(R.string.transparent), context.getResources().getString(R.string.pink)},
                {context.getResources().getString(R.string.cream), context.getResources().getString(R.string.white)},
                {context.getResources().getString(R.string.black), context.getResources().getString(R.string.blue)},
                {context.getResources().getString(R.string.red), context.getResources().getString(R.string.maroon)}};

        String color1 = "", color2 = "", finalColor = "";
        color1 = luckyColor[luckyNumber][0];
        color2 = luckyColor[luckyNumber][1];

        finalColor = color1 + ", " + color2;
        return finalColor;
    }


    public static int getRandomNumber() {
        Random r = new Random();
        Calendar calendar = Calendar.getInstance();
        int date = calendar.get(Calendar.DATE);
        r.setSeed(date);

        //minimum number to generate as random number
        int minNumber = 0;

        //maximum number to generate as random number
        int maxNumber = 1;

        //get the next random number within range
        // Inclusive both minimum and maximum value
        int randomNumber = r.nextInt((maxNumber - minNumber) + 1) + minNumber;
        return randomNumber;
    }

