    public static int[] getVerga(Context context) {
        String result = "";
        String resultStr = CUtils.getStringData(context, "defaultKundliData", "");
        try {
            if (resultStr != null && !resultStr.isEmpty()) {
                JSONObject jsonObject = new JSONObject(resultStr);
                JSONArray jsonArray = jsonObject.getJSONArray("GetVarga");
                JSONObject innerJsonObject = jsonArray.getJSONObject(0);
                result = innerJsonObject.getString("LagArray");
            }

        } catch (Exception e) {

        }
        return getIntArrayfromStingArray(result.split(","));

    }

    public static int[] getIntArrayfromStingArray(String[] strArray) {
        int size = strArray.length;
        if (size == 13) {
            int[] arr = new int[size];

            for (int i = 0; i < size; i++) {
                arr[i] = Integer.parseInt(strArray[i]);
            }
            return arr;
        } else {
            return null;
        }

    }

