    private static double[] HoraEndTime(int year, int month, int day, String latitude, String longitude, String timezone) {
        int jd = (int) Masa.toJulian(year, month + 1, day);
        // System.out.println("LAT LNG TMZNE" + year + month + 1 + day);
        try {

            if (objPanchangUtil == null) {
                objPanchangUtil = new PanchangUtil();
            }

            lat = Double.parseDouble(latitude);
            lng = Double.parseDouble(longitude);
            tzone = Double.parseDouble(timezone);
        } catch (NumberFormatException ex) {
            //MyLogger.errorLog("MainActivity 28 - " + ex.getMessage());
        } catch (Exception e) {
            //MyLogger.errorLog("MainActivity 29 - " + e.getMessage());
            // TODO: handle exception
        }

        //added by Ankit on 3-9-2019
        if (objPanchangUtil.isDst(String.valueOf(tzone), Calendar.getInstance().getTime())) {
            tzone = tzone + 1;
        }

        if (lat == 0 || lng == 0) {
            lat = 28.36;
            lng = 77.12;
            tzone = +5.5;
        }

        // System.out.println("LAT LNG TMZNE" + lat + lng + tzone);
        Place place = new Place(lat, lng, tzone);

        for (i = 0; i < 13; i++) {

            HoraMetadata hora = new HoraMetadata();
            if (i <= 11) {

                hora.setEntertimedata(CUtils
                        .FormatDMSIn2DigitStringWithSignForhora(
                                Muhurta.getDayDivisons(jd, place,
                                        Masa.getSunRise(jd, place), 12)[i], 0));

                Muhurta.getDayDivisons(jd, place, Masa.getSunRise(jd, place), 8);

                datatimestart.add(hora);

            }
            if (i > 0) {
                hora.setExittimedata(CUtils
                        .FormatDMSIn2DigitStringWithSignForhora(
                                Muhurta.getDayDivisons(jd, place,
                                        Masa.getSunRise(jd, place), 12)[i], 0));
                datatimeexit.add(hora);

            }

        }
        for (int j = 0; j < 13; j++) {

            HoraMetadata hora1 = new HoraMetadata();
            if (j <= 11) {
                hora1.setEntertimedata(CUtils
                        .FormatDMSIn2DigitStringWithSignForhora(
                                Muhurta.getNightDivisons(jd, place,
                                        Masa.getSunSet(jd, place), 12)[j], 0));

                datatimestart.add(hora1);

            }
            if (j > 0) {
                hora1.setExittimedata(CUtils
                        .FormatDMSIn2DigitStringWithSignForhora(
                                Muhurta.getNightDivisons(jd, place,
                                        Masa.getSunSet(jd, place), 12)[j], 0));
                datatimeexit.add(hora1);

            }

        }

        return Muhurta
                .getDayDivisons(jd, place, Masa.getSunRise(jd, place), 12);
    }

    public static int[] HoraLordName(int day_of_month) {
        int[] dayLordForDayHora = new int[24];

        String[] PlanetName = mContext.getResources().getStringArray(
                R.array.hora_planets);
        String[] PlanetNameMeaning = mContext.getResources().getStringArray(
                R.array.hora_planets_meaning);
        String[] PlanetNameMeaningforcurrentHora = mContext.getResources()
                .getStringArray(R.array.pla_mean);

        /*
         * Calendar ca = Calendar.getInstance(); int day_of_month =
         * ca.get(Calendar.DAY_OF_WEEK) - 1;
         */
        // int day_of_month = day+1;

        for (int i = 0; i < 24; i++) {
            dayLordForDayHora[i] = (day_of_month + (i * 5)) % 7;
            HoraMetadata hora = new HoraMetadata();
            // System.out.println("PlanetName[dayLordForDayHora[i]]"+PlanetName[dayLordForDayHora[i]]);
            hora.setPlanetdata(PlanetName[dayLordForDayHora[i]]);
            hora.setPlanetmeaning(PlanetNameMeaning[dayLordForDayHora[i]]);
            hora.setPlanetCurrentHorameaning(PlanetNameMeaningforcurrentHora[dayLordForDayHora[i]]);
            data.add(hora);

        }

        return dayLordForDayHora;

    }

    public static void saveLongData(Context context, String key, long value) {

        SharedPreferences preferences = PreferenceManager
                .getDefaultSharedPreferences(context);
        SharedPreferences.Editor editor = preferences.edit();
        editor.putLong(key, value);
        editor.commit();

    }

    public static String removeSecond(String timeStr) {
        try {
            if (timeStr == null)
                return "";

            if (timeStr.contains(":")) {
                String[] timeStrArr = timeStr.split(",");
                String timeStrWithoutSecond = "";
                for (int i = 0; i < timeStrArr.length; i++) {
                    int lastIndex = timeStrArr[i].lastIndexOf(":");
                    timeStrWithoutSecond = timeStrWithoutSecond + timeStrArr[i].substring(0, lastIndex);
                }
                return timeStrWithoutSecond;
            }

            return timeStr;
        } catch (Exception ex) {
            //
            return timeStr;
        }
    }

    public static long getLongData(Context context, String key,
                                   long defaultValue) {

        SharedPreferences preferences = PreferenceManager
                .getDefaultSharedPreferences(context);
        long value = preferences.getLong(key, defaultValue);

        return value;
    }

    public static boolean isTimeBeforeSunRise(String[] sunRiseArr) {
        boolean boolVal = false;
        Calendar calendar = Calendar.getInstance();
        int hour = calendar.get(Calendar.HOUR);
        int minute = calendar.get(Calendar.MINUTE);
        int second = calendar.get(Calendar.SECOND);
        int am_pm = calendar.get(Calendar.AM_PM);
        if (am_pm == 1) {
            hour = 12 + hour;
        }
        if (hour < Integer.parseInt(sunRiseArr[0])) {
            boolVal = true;
        } else if (hour == Integer.parseInt(sunRiseArr[0])) {
            if (minute < Integer.parseInt(sunRiseArr[1])) {
                boolVal = true;
            } else if (minute < Integer.parseInt(sunRiseArr[1])) {
                if (second < Integer.parseInt(sunRiseArr[2])) {
                    boolVal = true;
                }
            }
        }
        return boolVal;
    }

    public static int getDeviceDencity(Context context) {
        int densityDpi = 0;
        try {
            DisplayMetrics metrics = context.getResources().getDisplayMetrics();
            densityDpi = (int) (metrics.density * 160f);
        } catch (Exception e) {
            e.printStackTrace();
            e.printStackTrace();
        }
        return densityDpi;
    }

    /**
     * show dialog when text to speech not supported by device.
     *
     * @param context
     * @param LANGUAGE_CODE
     */
    public static void showAlertDialog(final Context context, int LANGUAGE_CODE) {//2 hindi
        AlertDialog.Builder alertDialogBuilder = new AlertDialog.Builder(context);
        alertDialogBuilder.setTitle(context.getString(R.string.dialogue_title));
        alertDialogBuilder.setMessage(context.getString(R.string.dialogue_message));
//        alertDialogBuilder.setCancelable(false);
        alertDialogBuilder.setPositiveButton(context.getString(R.string.ok),
                new DialogInterface.OnClickListener() {
                    @Override
                    public void onClick(DialogInterface arg0, int arg1) {

                        final String appPackageName = "com.google.android.tts"; // getPackageName() from Context or Activity object
                        try {
                            context.startActivity(new Intent(Intent.ACTION_VIEW, Uri.parse("market://details?id=" + appPackageName)));
                        } catch (android.content.ActivityNotFoundException anfe) {
                            context.startActivity(new Intent(Intent.ACTION_VIEW, Uri.parse("https://play.google.com/store/apps/details?id=" + appPackageName)));
                        }
                    }
                });

        AlertDialog alertDialog = alertDialogBuilder.create();
        alertDialog.show();
    }

