    /**
     * This method convert milliseconds time to string format
     *
     * @param timestamp
     * @return time in string like one day ago
     */
    public static String convertTimeInString(Context adapterContext, long timestamp) {
        String time = "", time_text = "";
        try {
            Date past = new Date(timestamp);

            Date now = new Date();

            long seconds = TimeUnit.MILLISECONDS.toSeconds(now.getTime() - past.getTime());
            long minutes = TimeUnit.MILLISECONDS.toMinutes(now.getTime() - past.getTime());
            long hours = TimeUnit.MILLISECONDS.toHours(now.getTime() - past.getTime());
            long days = TimeUnit.MILLISECONDS.toDays(now.getTime() - past.getTime());

            if (seconds < 60) {
                if (seconds == 0) {
                    time_text = adapterContext.getResources().getString(R.string.text_now);
                    time = (time_text);
                } else if (seconds > 1) {
                    time_text = adapterContext.getResources().getString(R.string.text_seconds_ago);
                    time = (seconds + " " + time_text);
                } else {
                    time_text = adapterContext.getResources().getString(R.string.text_second_ago);
                    time = (seconds + " " + time_text);
                }
            } else if (minutes < 60) {

                if (minutes > 1) {
                    time_text = adapterContext.getResources().getString(R.string.text_minutes_ago);
                    time = (minutes + " " + time_text);
                } else {
                    time_text = adapterContext.getResources().getString(R.string.text_minute_ago);
                    time = (minutes + " " + time_text);
                }
            } else if (hours < 24) {

                if (hours > 1) {
                    time_text = adapterContext.getResources().getString(R.string.text_hours_ago);
                    time = (hours + " " + time_text);
                } else {
                    time_text = adapterContext.getResources().getString(R.string.text_hour_ago);
                    time = (hours + " " + time_text);
                }
            } else {
                if (days > 1) {
                    //time = (days + " days ago");
                    time = DateTimeUtils.getDateByTimestamp(timestamp + "") + " " +
                            DateTimeUtils.getTimeByTimestamp(timestamp + "");
                } else {
                    time_text = adapterContext.getResources().getString(R.string.text_day_ago);
                    time = (days + " " + time_text);
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
        return time;
    }


    public static boolean checkAndRequestPermissions(Activity context) {
        int access_fine_location = ContextCompat.checkSelfPermission(context,
                android.Manifest.permission.ACCESS_FINE_LOCATION);
        int record_audio = ContextCompat.checkSelfPermission(context,
                android.Manifest.permission.RECORD_AUDIO);
        int access_coarse_location = ContextCompat.checkSelfPermission(context,
                android.Manifest.permission.ACCESS_COARSE_LOCATION);
        int read_external_storage = ContextCompat.checkSelfPermission(context,
                android.Manifest.permission.READ_EXTERNAL_STORAGE);
        int write_external_storage = ContextCompat.checkSelfPermission(context,
                android.Manifest.permission.WRITE_EXTERNAL_STORAGE);
        int call_phone = ContextCompat.checkSelfPermission(context,
                android.Manifest.permission.CALL_PHONE);
        int modify_audio_settings = ContextCompat.checkSelfPermission(context,
                android.Manifest.permission.MODIFY_AUDIO_SETTINGS);
        int get_accounts = ContextCompat.checkSelfPermission(context,
                Manifest.permission.GET_ACCOUNTS);


        List<String> listPermissionsNeeded = new ArrayList<>();

        if (access_fine_location != PackageManager.PERMISSION_GRANTED) {
            listPermissionsNeeded.add(android.Manifest.permission.ACCESS_FINE_LOCATION);
        }

        if (record_audio != PackageManager.PERMISSION_GRANTED) {
            listPermissionsNeeded.add(android.Manifest.permission.RECORD_AUDIO);
        }
        if (access_coarse_location != PackageManager.PERMISSION_GRANTED) {
            listPermissionsNeeded.add(android.Manifest.permission.ACCESS_COARSE_LOCATION);
        }

        if (read_external_storage != PackageManager.PERMISSION_GRANTED) {
            listPermissionsNeeded.add(android.Manifest.permission.READ_EXTERNAL_STORAGE);
        }
        if (write_external_storage != PackageManager.PERMISSION_GRANTED) {
            listPermissionsNeeded.add(android.Manifest.permission.WRITE_EXTERNAL_STORAGE);
        }

        if (call_phone != PackageManager.PERMISSION_GRANTED) {
            listPermissionsNeeded.add(android.Manifest.permission.CALL_PHONE);
        }
        if (modify_audio_settings != PackageManager.PERMISSION_GRANTED) {
            listPermissionsNeeded.add(android.Manifest.permission.MODIFY_AUDIO_SETTINGS);
        }
        /*if (get_accounts != PackageManager.PERMISSION_GRANTED) {
            listPermissionsNeeded.add(android.Manifest.permission.GET_ACCOUNTS);
        }*/

        if (!listPermissionsNeeded.isEmpty()) {
            ActivityCompat.requestPermissions(context, listPermissionsNeeded.toArray(new String[listPermissionsNeeded.size()]), 1);
            return false;
        }
        return true;

    }

