    public static boolean isStartListening(List<String> stringList, String word) {
        boolean boolVal = false;
        if (stringList != null && word != null) {
            for (int i = 0; i < stringList.size(); i++) {
                if (stringList.get(i).equalsIgnoreCase(word)) {
                    boolVal = true;
                    break;
                }
            }
        }
        return boolVal;
    }

