    public static int getCurrentHoraNumber(List<HoraMetadata> datatime2,
                                           List<HoraMetadata> datatimeexit2) {
        String[] resultEntryTime = null;
        String[] resultExitTime = null;
        int currentHoraNumber = 0;
        try {
            Calendar calendar = Calendar.getInstance();

            Calendar horaEntryTime = Calendar.getInstance();
            Calendar horaExitTime = Calendar.getInstance();

            for (int i = 0; i <= datatime2.size(); i++) {
                resultEntryTime = datatime2.get(i).getEntertimedata()
                        .split(":");
                resultExitTime = datatimeexit2.get(i).getExittimedata()
                        .split(":");

                if (Integer.parseInt(resultExitTime[0]) >= 24) {
                    if (Integer.parseInt(resultExitTime[0]) == 24) {
                        resultExitTime[0] = "00";
                    }
                    if (Integer.parseInt(resultExitTime[0]) == 25) {
                        resultExitTime[0] = "01";
                    }
                    if (Integer.parseInt(resultExitTime[0]) == 26) {
                        resultExitTime[0] = "02";
                    }
                    if (Integer.parseInt(resultExitTime[0]) == 27) {
                        resultExitTime[0] = "03";
                    }
                    if (Integer.parseInt(resultExitTime[0]) == 28) {
                        resultExitTime[0] = "04";
                    }
                    if (Integer.parseInt(resultExitTime[0]) == 29) {
                        resultExitTime[0] = "05";
                    }
                    if (Integer.parseInt(resultExitTime[0]) == 30) {
                        resultExitTime[0] = "06";
                    }
                }
                if (Integer.parseInt(resultEntryTime[0]) >= 24) {
                    if (Integer.parseInt(resultEntryTime[0]) == 24) {
                        resultEntryTime[0] = "00";
                    }
                    if (Integer.parseInt(resultEntryTime[0]) == 25) {
                        resultEntryTime[0] = "01";
                    }
                    if (Integer.parseInt(resultEntryTime[0]) == 26) {
                        resultEntryTime[0] = "02";
                    }
                    if (Integer.parseInt(resultEntryTime[0]) == 27) {
                        resultEntryTime[0] = "03";
                    }
                    if (Integer.parseInt(resultEntryTime[0]) == 28) {
                        resultEntryTime[0] = "04";
                    }
                    if (Integer.parseInt(resultEntryTime[0]) == 29) {
                        resultEntryTime[0] = "05";
                    }
                    if (Integer.parseInt(resultEntryTime[0]) == 30) {
                        resultEntryTime[0] = "06";
                    }
                }

                long currentTimeMilliSeconds = calendar.getTimeInMillis();

                horaEntryTime.set(Calendar.HOUR_OF_DAY,
                        Integer.parseInt(resultEntryTime[0]));
                horaEntryTime.set(Calendar.MINUTE,
                        Integer.parseInt(resultEntryTime[1]));
                horaEntryTime.set(Calendar.SECOND,
                        Integer.parseInt(resultEntryTime[2]));
                long horaEntryTimeMilliSeconds = horaEntryTime
                        .getTimeInMillis();

                horaExitTime.set(Calendar.HOUR_OF_DAY,
                        Integer.parseInt(resultExitTime[0]));

                horaExitTime.set(Calendar.MINUTE,
                        Integer.parseInt(resultExitTime[1]));
                horaExitTime.set(Calendar.SECOND,
                        Integer.parseInt(resultExitTime[2]));
                long horaExitTimeMilliSeconds = horaExitTime.getTimeInMillis();
                if (horaEntryTimeMilliSeconds > horaExitTimeMilliSeconds) {
                    horaExitTimeMilliSeconds = horaExitTimeMilliSeconds + 24
                            * 60 * 60 * 1000;
                }
                if (currentTimeMilliSeconds < horaEntryTimeMilliSeconds) {
                    currentTimeMilliSeconds = currentTimeMilliSeconds + 24 * 60
                            * 60 * 1000;
                }

                if (currentTimeMilliSeconds >= horaEntryTimeMilliSeconds
                        && currentTimeMilliSeconds <= horaExitTimeMilliSeconds) {

                    currentHoraNumber = i;
                    break;
                }

            }
        } catch (Exception e) {
            //Log.e("", e.getMessage().toString());
            System.out.println(e.getMessage());

        }

        return currentHoraNumber;
    }

    public static List<HoraMetadata> HoraExitTime(int year, int month, int day, String latitude, String longitude, String timezone) {

        List<HoraMetadata> horaExitTime = new ArrayList<HoraMetadata>();

        int jd = (int) Masa.toJulian(year, month + 1, day);
        double lat = 0.0;
        double lng = 0.0;
        double tzone = 0.0;

        try {
            lat = Double.parseDouble(latitude);
            lng = Double.parseDouble(longitude);
            tzone = Double.parseDouble(timezone);
        } catch (Exception ex) {
            //Log.e("Exception ", ex.getMessage().toString());
        }

        Place place = new Place(lat, lng, tzone);

        for (int i = 0; i < 13; i++) {

            HoraMetadata hora = new HoraMetadata();
            if (i > 0) {
                hora.setExittimedata(CUtils
                        .FormatDMSIn2DigitStringWithSignForhora(
                                Muhurta.getDayDivisons(jd, place,
                                        Masa.getSunRise(jd, place), 12)[i], 0));
                horaExitTime.add(hora);

            }
        }

        for (int j = 0; j < 13; j++) {

            HoraMetadata hora1 = new HoraMetadata();
            if (j > 0) {
                hora1.setExittimedata(CUtils
                        .FormatDMSIn2DigitStringWithSignForhora(
                                Muhurta.getNightDivisons(jd, place,
                                        Masa.getSunSet(jd, place), 12)[j], 0));
                horaExitTime.add(hora1);

            }
        }

        return horaExitTime;
    }

    public static List<HoraMetadata> HoraEntryTime(int year, int month, int day, String latitude, String longitude, String timezone) {

        List<HoraMetadata> horaEntryTime = new ArrayList<HoraMetadata>();

        int jd = (int) Masa.toJulian(year, month + 1, day);
        double lat = 0.0;
        double lng = 0.0;
        double tzone = 0.0;

        try {
            lat = Double.parseDouble(latitude);
            lng = Double.parseDouble(longitude);
            tzone = Double.parseDouble(timezone);
        } catch (Exception ex) {
            //Log.e("Exception ", ex.getMessage().toString());
        }

        Place place = new Place(lat, lng, tzone);

        for (int i = 0; i < 13; i++) {

            HoraMetadata hora = new HoraMetadata();
            if (i <= 11) {

                hora.setEntertimedata(CUtils
                        .FormatDMSIn2DigitStringWithSignForhora(
                                Muhurta.getDayDivisons(jd, place,
                                        Masa.getSunRise(jd, place), 12)[i], 0));

                Muhurta.getDayDivisons(jd, place, Masa.getSunRise(jd, place), 8);

                horaEntryTime.add(hora);

            }
        }

        for (int j = 0; j < 13; j++) {

            HoraMetadata hora1 = new HoraMetadata();
            if (j <= 11) {
                hora1.setEntertimedata(CUtils
                        .FormatDMSIn2DigitStringWithSignForhora(
                                Muhurta.getNightDivisons(jd, place,
                                        Masa.getSunSet(jd, place), 12)[j], 0));

                horaEntryTime.add(hora1);

            }
        }

        return horaEntryTime;
    }

    public static List<HoraMetadata> HoraLordName(Context context, int day_of_month) {

        List<HoraMetadata> data = new ArrayList<HoraMetadata>();
        int[] dayLordForDayHora = new int[24];

        String[] PlanetName = context.getResources().getStringArray(
                R.array.hora_planets);
        String[] PlanetNameMeaning = context.getResources().getStringArray(
                R.array.hora_planets_meaning);
        String[] PlanetNameMeaningforcurrentHora = context.getResources()
                .getStringArray(R.array.pla_mean);

        for (int i = 0; i < 24; i++) {
            dayLordForDayHora[i] = (day_of_month + (i * 5)) % 7;
            HoraMetadata hora = new HoraMetadata();
            hora.setPlanetdata(PlanetName[dayLordForDayHora[i]]);
            hora.setPlanetmeaning(PlanetNameMeaning[dayLordForDayHora[i]]);
            hora.setPlanetCurrentHorameaning(PlanetNameMeaningforcurrentHora[dayLordForDayHora[i]]);
            data.add(hora);
        }

        return data;
    }

    public static Bitmap getBitmapFromPreference(Context context) {
        Bitmap bitmap = null;
        SharedPreferences shre = PreferenceManager.getDefaultSharedPreferences(context);
        String previouslyEncodedImage = shre.getString(CGlobalVariables.IMAGEKEY, "");

        if (!previouslyEncodedImage.equalsIgnoreCase("")) {
            byte[] b = Base64.decode(previouslyEncodedImage, Base64.DEFAULT);
            bitmap = BitmapFactory.decodeByteArray(b, 0, b.length);
        }
        return bitmap;
    }

    public static Typeface getUserSelectedLanguageFontType(Context context, int language, String fontType) {
        Typeface typeface = null;
        if (fontType.equals("Regular")) {
            typeface = Typeface.createFromAsset(context.getAssets(),
                    "fonts/Roboto-Regular.ttf");
        } else if (fontType.equals("Medium")) {
            typeface = Typeface.createFromAsset(context.getAssets(),
                    "fonts/Roboto-Medium.ttf");
        }
        Locale locale = Locale.ENGLISH;
        switch (language) {
            case CGlobalVariables.HINDI:
                locale = new Locale("hi");
                break;
            case CGlobalVariables.TAMIL:
                locale = new Locale("ta");
                break;
            case CGlobalVariables.MARATHI:
                locale = new Locale("mr");
                break;
            case CGlobalVariables.BANGALI:
                locale = new Locale("bn");
                break;
            case CGlobalVariables.TELUGU:
                locale = new Locale("te");
                break;
            case CGlobalVariables.MALAYALAM:
                locale = new Locale("ml");
                break;
            case CGlobalVariables.KANNADA:
                locale = new Locale("kn");
                break;
            case ODIA:
                locale = new Locale("or");
                break;

        }

        Locale.setDefault(locale);
        Configuration config = new Configuration();
        config.locale = locale;
        context.getResources().updateConfiguration(config,
                context.getResources().getDisplayMetrics());

        return typeface;
    }

    /**
     * This method is used to return language by checking its characters
     *
     * @param checkString
     * @return
     */
    public static int getLanguageByStringCheck(String checkString, int languageCode) {
        try {
            if (checkString != null && !checkString.equals("")) {
                char firstChar = checkString.trim().charAt(0);
                int castAscii = firstChar;

                if ((castAscii >= 97 && castAscii <= 122) || (castAscii >= 65 && castAscii <= 90)) {
                    return CGlobalVariables.ENGLISH;
                } else {
                    return CGlobalVariables.HINDI;
                }
            } else {
                return languageCode;
            }
        } catch (Exception ex) {
            return languageCode;
        }
    }

    /**
     * convert Time To Am Pm
     *
     * @param time
     * @return
     */
    public static String convertTimeToAmPm(String time) {

        int hr = 0, min = 0;
        String TimeWithMeradian = "";
        String[] SplitTime = time.split(":");
        try {
            hr = Integer.parseInt(SplitTime[0]);
            min = Integer.parseInt(SplitTime[1]);

            //am
            if (hr < 12) {
                TimeWithMeradian = appendZeroOnSingleDigit(hr) + ":" + appendZeroOnSingleDigit(min) + " AM";
            } else if (hr >= 12 && hr < 24) {   //pm
                hr = hr == 12 ? 12 : hr - 12;
                TimeWithMeradian = appendZeroOnSingleDigit(hr) + ":" + appendZeroOnSingleDigit(min) + " PM";
            } else if (hr >= 24) {  // more than 24
                hr = hr - 24;
                TimeWithMeradian = "+" + appendZeroOnSingleDigit(hr) + ":" + appendZeroOnSingleDigit(min) + " AM";
            }
        } catch (Exception e) {
            TimeWithMeradian = time;
        }
        return TimeWithMeradian;
    }

    /**
     * append Zero On Single Digit
     *
     * @param time
     * @return
     */
    public static String appendZeroOnSingleDigit(int time) {
        String rTime = String.valueOf(time);
        if (time < 10) {
            rTime = "0" + time;
        }
        return rTime;
    }

    public static HashMap<String, String> getNakCharan(String name) {
        String rashi = "";
        int nakshatra = 0;
        int counter = 0;
        int charan = 0;
        int actCharan = 0;
        String keyofname = name;

        String[][] ashwiniNak = {{"chu", "choo"}, {"che", "chai"}, {"cho", "chau"}, {"la", "caa"}};
        String[][] bharaniNak = {{"ci", "cee"}, {"cu", "loo"}, {"ce", "cai"}, {"co", "cau"}};
        String[][] kritikaNak = {{"a", "aa"}, {"i", "ee"}, {"u", "oo"}, {"e", "ai"}};
        String[][] rohiniNak = {{"o", "o"}, {"va", "vaa", "ba", "baa"}, {"vi", "vee", "bi", "bee"}, {"vu", "voo", "bu", "boo"}};
        String[][] mrigshirNak = {{"ve", "vai", "be", "bai"}, {"vo", "vao", "bo", "bao"}, {"ka"}, {"ki", "kee"}};
        String[][] ardraNak = {{"ku", "koo"}, {"gha", "ghaa"}, {"nga"}, {"chha", "chh"}};
        String[][] punarvasuNak = {{"ke", "kae"}, {"ko", "kau"}, {"ha"}, {"hi", "hee"}};
        String[][] pushyamiNak = {{"hu", "hoo"}, {"he", "hr"}, {"ho", "hao"}, {"da", "daa"}};
        String[][] ashleshaNak = {{"di", "dai"}, {"du", "doo"}, {"de", "dee"}, {"do", "dau"}};
        String[][] maghaNak = {{"ma"}, {"mi", "mee"}, {"mu", "moo"}, {"me", "me"}};
        String[][] pubbaNak = {{"mo", "mao"}, {"ta"}, {"ti", "tee"}, {"tu", "too"}};
        String[][] uttaraNak = {{"te", "te"}, {"to", "teo"}, {"pa",}, {"pi", "pr"}};
        String[][] hasthaNak = {{"pu", "poo"}, {"sha", "sha"}, {"na"}, {"tha"}};
        String[][] chitraNak = {{"pe", "pae"}, {"po", "pao"}, {"ra"}, {"ri", "ree"}};
        String[][] swatiNak = {{"ru", "roo"}, {"re", "rae"}, {"ro", "rao"}, {"ta"}};
        String[][] vishakhaNak = {{"tee", "ti"}, {"tu", "too"}, {"te", "tae"}, {"to", "tao"}};
        String[][] anuradhaNak = {{"na"}, {"ni", "nee"}, {"nu", "noo"}, {"ne", "ne"}};
        String[][] jyeshthaNak = {{"no", "nao"}, {"ya"}, {"yi", "yee"}, {"yu", "yoo"}};
        String[][] moolaNak = {{"ye", "yae"}, {"yo", "yao"}, {"bha"}, {"bhi", "bhee"}};
        String[][] poorvashaadaNak = {{"bhu", "bhoo"}, {"dha"}, {"pha", "pha"}, {"rha"}};
        String[][] uttarashaadaNak = {{"bhe", "bhe"}, {"bho", "bho"}, {"ja", "za"}, {"ji", "jee"}};
        String[][] shravanNak = {{"khee", "khi"}, {"khu", "khoo"}, {"khe", "khai"}, {"kho", "kho"}};
        String[][] dhanishthaNak = {{"ga"}, {"gi", "gee"}, {"gu", "goo"}, {"ge", "gay"}};
        String[][] shathabhishaNak = {{"go", "go"}, {"sa", "sha"}, {"si", "see", "shee", "shi"}, {"su", "soo", "shu", "shoo"}};
        String[][] poorvabhadraNak = {{"se", "sai", "she", "shai"}, {"so", "so", "sho", "shau"}, {"daa"}, {"dai", "dee"}};
        String[][] uttarabhadraNak = {{"du", "doo"}, {"tha"}, {"jh"}, {"nja"}};
        String[][] revatiNak = {{"dae", "de"}, {"dao", "do"}, {"cha"}, {"chi", "chee"}};

        String[][][] allNakshatras = {ashwiniNak, bharaniNak, kritikaNak, rohiniNak, mrigshirNak, ardraNak, punarvasuNak,
                pushyamiNak, ashleshaNak, maghaNak, pubbaNak, uttaraNak, hasthaNak, chitraNak, swatiNak, vishakhaNak,
                anuradhaNak, jyeshthaNak, moolaNak, poorvashaadaNak, uttarashaadaNak, shravanNak, dhanishthaNak,
                shathabhishaNak, poorvabhadraNak, uttarabhadraNak, revatiNak};

        for (int i = 0; i < 27; i++) {
            for (int j = 0; j < 4; j++) {
                counter++;
                for (int k = 0; k < allNakshatras[i][j].length; k++) {
                    if (name.toLowerCase().startsWith(allNakshatras[i][j][k])) {
                        rashi = getRashi(counter);
                        nakshatra = i + 1;
                        charan = counter;
                        actCharan = j + 1;
                        break;
                    }
                }
                if (!rashi.equals(""))
                    break;
            }
            if (!rashi.equals(""))
                break;
        }

        HashMap<String, String> hashMap = new HashMap<String, String>();

        if (rashi.equals("")) {
            hashMap.put("RashiNotFound", "1");
        } else {
            String[] rashiNoName = rashi.split("##");

            hashMap.put("RashiNo", rashiNoName[0]);
            hashMap.put("RashiName", rashiNoName[1]);
            hashMap.put("Nakshatra", nakshatra + "");
            hashMap.put("Charan", charan + "");
            hashMap.put("ActCharan", actCharan + "");
            hashMap.put("NameWord", keyofname);
        }
        return hashMap;

    }

    /**
     * This method returns the rashi based on the passed in charan.
     * Each rashi has 9 charans. Total 108 charans are divided into 12 rashi.
     * Based on the charan number, the rashi is returned.
     * Default Rashi returned is 'मेष'.
     *
     * @param charan
     * @return Rashi as String.
     */
    private static String getRashi(int charan) {
        String rashiNoName = "1##Aries";
        if (charan > 9 && charan <= 18)
            rashiNoName = "2##Taurus";
        else if (charan > 18 && charan <= 27)
            rashiNoName = "3##Gemini";
        else if (charan > 27 && charan <= 36)
            rashiNoName = "4##Cancer";
        else if (charan > 36 && charan <= 45)
            rashiNoName = "5##Leo";
        else if (charan > 45 && charan <= 54)
            rashiNoName = "6##Virgo";
        else if (charan > 54 && charan <= 63)
            rashiNoName = "7##Libra";
        else if (charan > 63 && charan <= 72)
            rashiNoName = "8##Scorpio";
        else if (charan > 72 && charan <= 81)
            rashiNoName = "9##Sagittarius";
        else if (charan > 81 && charan <= 90)
            rashiNoName = "10##Capricorn";
        else if (charan > 90 && charan <= 99)
            rashiNoName = "11##Aquarius";
        else if (charan > 99 && charan <= 108)
            rashiNoName = "12##Pisces";

        return rashiNoName;
    }

    /**
     * @param festStartDate
     * @return
     */
    public static String getDateInFormate(String festStartDate, String[] weekArray, String[] monthArray) {
        SimpleDateFormat sdf = new SimpleDateFormat("dd/MM/yyyy");
        Date date = null;
        try {
            date = sdf.parse(festStartDate);
        } catch (ParseException e) {
            e.printStackTrace();
        }
        Calendar cal = Calendar.getInstance();
        cal.setTime(date);

        String dateFormate = weekArray[cal.get(Calendar.DAY_OF_WEEK) - 1] + ", " + cal.get(Calendar.DATE) + " " + monthArray[cal.get(Calendar.MONTH)];
        return dateFormate;
    }

