    public static AajKaPanchangModel getPanchangObject(Context context, String key) {
        SharedPreferences sharedPreferences = context.getSharedPreferences(
                CGlobalVariables.PANCHANG_PREF, Context.MODE_PRIVATE);
        Gson gson = new Gson();
        String json = sharedPreferences.getString(key, "");
        try {
            AajKaPanchangModel obj = gson.fromJson(json, AajKaPanchangModel.class);
            if (obj.getRahuKaalVelaFrom() == null) {
                obj = null;
                SharedPreferences.Editor sharedPrefEditor = sharedPreferences.edit();
                sharedPrefEditor.putString(key, "");
                sharedPrefEditor.commit();
            }
            return obj;
        } catch (Exception e) {
            //Log.e("ForPanchang1", "getPanchangObject Exception=" + e);
        }
        return null;
    }

    public static void savePanchangObject(Context context, String key, Object object) {
        SharedPreferences sharedPreferences = context.getSharedPreferences(
                CGlobalVariables.PANCHANG_PREF, Context.MODE_PRIVATE);
        Editor prefsEditor = sharedPreferences.edit();
        Gson gson = new Gson();
        String json = gson.toJson(object); // myObject - instance of MyObject
        prefsEditor.putString(key, json);
        prefsEditor.commit();
    }

