    /*
     *
     * For post the ask a question service data to server using razorpay
     * */
    public static void postAskQuestionRazorpayDataToServer(final Activity activity, Typeface typeface,
                                                           RequestQueue queue, final String orderId,
                                                           final String chatId, final String statusCode,
                                                           final AstrologerServiceInfo astrologerServiceInfo,
                                                           String url, final String payID, final String razorResponse) {
        final IAskCallback callback = (IAskCallback) activity;
        // String orderUrl = "https://api2.astrosage.com/ac/astroshop/service-paytm-paymentupdate-with-verification.asp";
        String orderUrl = url;
        //String orderUrl="http://192.168.1.113/ac/astroshop/service-paytm-paymentupdate-with-verification.asp";
        final CustomProgressDialog pd = new CustomProgressDialog(activity, typeface);
        pd.setCancelable(false);
        pd.show();

        StringRequest stringRequest = new StringRequest(Request.Method.POST, orderUrl,
                new Response.Listener<String>() {
                    @Override
                    public void onResponse(String response) {
                        hideProgressBar(pd);
                        //com.google.analytics.tracking.android.
                        // Log.e("OrderResponse from server +" , response.toString());
                        try {
                            JSONArray array = new JSONArray(response);
                            JSONObject obj = array.getJSONObject(0);
                            String result = obj.getString("Result");
                            //1 success or fail update & 5 when s2s update server api
                            if (result.equalsIgnoreCase("1") || result.equalsIgnoreCase("5")) {

                                callback.getCallBack("1", callBack.POST_RAZORPAYSTATUS, "", "");

                            } else {
                                callback.getCallBack("0", callBack.POST_RAZORPAYSTATUS, "", "");
                            }

                        } catch (Exception e) {
                        }
                    }
                }

                , new Response.ErrorListener() {
            @Override
            public void onErrorResponse(VolleyError error) {
                hideProgressBar(pd);
                callback.getCallBack("0", callBack.POST_RAZORPAYSTATUS, "", "");

                // //Log.e("Error Through" + error.getMessage());
                VolleyLog.d("VolleyError: " + error.getMessage());
                //   mTextView.setText("That didn't work!");
                if (error instanceof TimeoutError) {
                    VolleyLog.d("TimeoutError: " + error.getMessage());
                } else if (error instanceof NoConnectionError) {
                    VolleyLog.d("NoConnectionError: " + error.getMessage());
                } else if (error instanceof AuthFailureError) {
                    VolleyLog.d("AuthFailureError: " + error.getMessage());
                    //TODO
                } else if (error instanceof ServerError) {
                    //TODO
                    VolleyLog.d("ServerError: " + error.getMessage());
                } else if (error instanceof NetworkError) {
                    //TODO
                    VolleyLog.d("NetworkError: " + error.getMessage());
                } else if (error instanceof ParseError) {
                    //TODO
                    VolleyLog.d("ParseError: " + error.getMessage());

                }
            }
        }
        ) {
            @Override
            public String getBodyContentType() {
                return "application/x-www-form-urlencoded;charset=UTF-8";
            }

            /**
             * Passing some request headers
             * */
            @Override
            public Map<String, String> getParams() throws AuthFailureError {
                HashMap<String, String> headers = new HashMap<String, String>();
                headers.put("key", CUtils.getApplicationSignatureHashCode(activity));
                headers.put("amount", astrologerServiceInfo.getPriceRs());
                headers.put("orderid", orderId);
                headers.put("paycurr", "INR");
                headers.put("status", statusCode);
                headers.put("profile_Id", astrologerServiceInfo.getProfileId());
                headers.put("chatid", chatId);
                headers.put("razorpayresponse", razorResponse);
                headers.put("paymentid", payID);

                //com.google.analytics.tracking.android.//Log.e("Request post hit==" + headers.toString());
                return headers;
            }

        };
        // Add the request to the RequestQueue.
        //com.google.analytics.tracking.android.//Log.e("API HIT HERE");
        int socketTimeout = 60000;//30 seconds - change to what you want
        RetryPolicy policy = new DefaultRetryPolicy(socketTimeout, DefaultRetryPolicy.DEFAULT_MAX_RETRIES, DefaultRetryPolicy.DEFAULT_BACKOFF_MULT);
        stringRequest.setRetryPolicy(policy);
        stringRequest.setShouldCache(false);
        queue.add(stringRequest);
    }

