    /*
     * Get Plan Subscription open dialog date
     * Added by Monika
     * */
    public static String getDialogDate(int days) {
        String strDate = "", newDate = "";

        Calendar calendar = Calendar.getInstance();
        //Number of Days to add
        calendar.add(Calendar.DAY_OF_MONTH, days);
        SimpleDateFormat mdformat = new SimpleDateFormat("yyyy/MM/dd ");

        //Date after adding the days to the given date
        newDate = mdformat.format(calendar.getTime());

        //Log.e("SILVER_DIALOG ", "newDate " + newDate);

        return newDate;
    }

    /*
     * Check the current date is same with dialog open date
     * Added by Monika
     * */
    public static boolean checkDatesSame(String dialogOpenDate) {
        String currentDate = "";
        boolean isSameDate = false;
        Calendar calendar = Calendar.getInstance();

        SimpleDateFormat mdformat = new SimpleDateFormat("yyyy/MM/dd ");
        currentDate = mdformat.format(calendar.getTime());


        /*
         * currentDate is a present date and dialogOpenDate is dialog date
         * 0 comes when two date are same,
         * 1 comes when currentDate is higher then dialogOpenDate
         * -1 comes when currentDate is lower then dialogOpenDate
         * */
        int dateCompareValue = currentDate.compareTo(dialogOpenDate);
        if (dateCompareValue == 0) {
            isSameDate = true;
        }

        return isSameDate;
    }

