    public static void vollyPostRequest(VolleyResponse volleyResponse, String url, Map<String, String> params, int method) {
        RequestQueue queue = VolleySingleton.getInstance(AstrosageKundliApplication.getAppContext()).getRequestQueue();
        StringRequest stringRequest = new VolleyServiceHandler(Request.Method.POST, url, volleyResponse, true, params, method).getMyStringRequest();
        queue.add(stringRequest);
    }

    public static void vollyGetRequest(VolleyResponse volleyResponse, String url, int method) {
        HashMap<String, String> headerParams = new HashMap();
        headerParams.put("X-Android-Package", AstrosageKundliApplication.getAppContext().getPackageName());
        headerParams.put("X-Android-Cert", CUtils.getKeyHash(AstrosageKundliApplication.getAppContext()));


        HashMap<String, String> params = new HashMap<String, String>();
        RequestQueue queue = VolleySingleton.getInstance(AstrosageKundliApplication.getAppContext()).getRequestQueue();
        StringRequest stringRequest = new VolleyServiceHandler(Request.Method.GET, url, volleyResponse, true, params, headerParams, method).getMyStringRequest();
        queue.add(stringRequest);

    }

    public static String[] setSignUpDetails(String signUpValue) {
        String[] iStatus = new String[]{"0", "0"};
        try {
            Document doc = CXMLOperations.XMLfromString(signUpValue);
            int numResults = doc.getChildNodes().getLength();
            if ((numResults <= 0)) {
                //
            } else {

                if (Build.VERSION.SDK_INT > Build.VERSION_CODES.GINGERBREAD) {
                    try {

                        XPath xpath = XPathFactory.newInstance().newXPath();
                        String expression = "/product/msgcode"; // first book
                        Node logValue = (Node) xpath.evaluate(expression, doc, XPathConstants.NODE);
                        if (logValue != null)
                            iStatus[0] = logValue.getTextContent();

                        String expressionmsgId = "/product/msg"; // first book
                        Node msgId = (Node) xpath.evaluate(expressionmsgId, doc, XPathConstants.NODE);
                        if (msgId != null)
                            iStatus[1] = msgId.getTextContent();

                    } catch (Exception e) {

                    }
                } else {
                    NodeList nodes = doc.getElementsByTagName("msgcode");
                    for (int i = 0; i < nodes.getLength(); i++) {
                        Element e = (Element) nodes.item(i);
                        iStatus[0] = CXMLOperations.getValue(e, "msgcode");
                    }

                    NodeList nodesMsgId = doc.getElementsByTagName("msg");
                    for (int i = 0; i < nodesMsgId.getLength(); i++) {
                        Element e = (Element) nodesMsgId.item(i);
                        iStatus[1] = CXMLOperations.getValue(e, "msg");
                    }
                }

            }
        } catch (Exception e) {
            iStatus[0] = "0";
        }

        return iStatus;

    }

