    /**
     * Method to encode String With Ascii Value
     *
     * @param stringToEncode
     * @param XAheadCharacter
     * @return
     */
    static String encodeWithAsciiValue(String stringToEncode, int XAheadCharacter) {
        // changed string
        String newString = "";
        // iterate for every characters
        for (int iterator = 0; iterator < stringToEncode.length(); ++iterator) {
            // ASCII value
            int val = stringToEncode.charAt(iterator);
            // store the duplicate
            newString += (char) (val + XAheadCharacter);
        }
        // return the new string
        return newString;
    }

    /**
     * get Day Of Month
     */
    public static int getDayOfMonth(MyDatePicker view, int dayOfMonth, int monthOfYear, int year) {
        int day;
        if (monthOfYear == 1) {
            day = dayOfMonth > 28 ? view.getMaxValue(monthOfYear, year) : dayOfMonth;
        } else {
            day = dayOfMonth > 30 ? view.getMaxValue(monthOfYear, year) : dayOfMonth;
        }
        return day;
    }

    public static String replaceEmailChar(String emailId) {

        try {
            int xCharacterAhead = 1;
            emailId = encodeWithAsciiValue(emailId, xCharacterAhead);
        } catch (Exception e) {
            e.printStackTrace();
        }

        return emailId;
    }

    public static String replaceEmailFromJson(String fullJsonDataObj, String key) {
        try {
            JSONObject fullDataObj = new JSONObject(fullJsonDataObj);
            String email = fullDataObj.getString(key);
            email = replaceEmailChar(email);
            fullDataObj.put(KEY_EMAIL_ID, email);
            fullDataObj.remove(key);
            return fullDataObj.toString().replace("\\/", "/");
        } catch (Exception e) {
            e.printStackTrace();
        }
        return fullJsonDataObj;
    }

