    public static HashMap<String, String> parseLoginSignupJson(JSONObject dataObject) {
        HashMap<String, String> dataHash = new HashMap<>();

        String userName = "", mobile = "", occupation = "", maritalStatus = "",
                companyName = "", address1 = "", address2 = "", userPlanExpiryDate = "",
                userPlanPurchaseDate = "", userPlanId = "", msgCode = "", msgStr = "", userId = "",
                password = "", isDhruvPlanAvail = "", phoneNumber = "", countryCode = "";

        try {

            if (dataObject.has("msgcode")) {
                msgCode = dataObject.getString("msgcode");
            }
            if (dataObject.has("msg")) {
                msgStr = dataObject.getString("msg");
            }
            if (dataObject.has("userid")) {
                userId = dataObject.getString("userid");
            }
            if (dataObject.has("userfirstname")) {
                userName = dataObject.getString("userfirstname");
            }
            if (dataObject.has("mobile")) {
                mobile = dataObject.getString("mobile");
            }
            if (dataObject.has("occupation")) {
                occupation = dataObject.getString("occupation");
            }
            if (dataObject.has("maritalstatus")) {
                maritalStatus = dataObject.getString("maritalstatus");
            }
            if (dataObject.has("companyName")) {
                companyName = dataObject.getString("companyName");
            }
            if (dataObject.has("addressLine1")) {
                address1 = dataObject.getString("addressLine1");
            }
            if (dataObject.has("addressLine2")) {
                address2 = dataObject.getString("addressLine2");
            }
            if (dataObject.has("userplanid")) {
                userPlanId = dataObject.getString("userplanid");
            }
            if (dataObject.has("userplanexpirydate")) {
                userPlanExpiryDate = dataObject.getString("userplanexpirydate");
            }
            if (dataObject.has("userplanpurchasedate")) {
                userPlanPurchaseDate = dataObject.getString("userplanpurchasedate");
            }

            if (dataObject.has("userpassword")) {
                password = dataObject.getString("userpassword");
            }
            if (dataObject.has(CGlobalVariables.IS_DHRUV_PLAN_AVAIL)) {
                isDhruvPlanAvail = dataObject.getString(CGlobalVariables.IS_DHRUV_PLAN_AVAIL);
            }
            if (dataObject.has("mobile")) {
                phoneNumber = dataObject.getString("mobile");
            }
            if (dataObject.has("countrycode")) {
                countryCode = dataObject.getString("countrycode");
            }


            dataHash.put(CGlobalVariables.MSGCODE, msgCode);
            dataHash.put(CGlobalVariables.MSGSTR, msgStr);
            dataHash.put(CGlobalVariables.USERID, userId);
            dataHash.put(CGlobalVariables.USERPLAN_ID, userPlanId);
            dataHash.put(CGlobalVariables.USER_PLAN_EXPIRY_DATE, userPlanExpiryDate);
            dataHash.put(CGlobalVariables.USER_PLAN_PURCHASE_DATE, userPlanPurchaseDate);
            dataHash.put(CGlobalVariables.MOBILE, mobile);
            dataHash.put(CGlobalVariables.OCCUPATION, occupation);
            dataHash.put(CGlobalVariables.MARITALSTATUS, maritalStatus);
            dataHash.put(CGlobalVariables.ADDRESS1, address1);
            dataHash.put(CGlobalVariables.ADDRESS2, address2);
            dataHash.put(CGlobalVariables.USER_FIRSTNAME, userName);
            dataHash.put(CGlobalVariables.USER_PASSWORD, password);
            dataHash.put(CGlobalVariables.IS_DHRUV_PLAN_AVAIL, isDhruvPlanAvail);

            saveStringData(AstrosageKundliApplication.getAppContext(), CGlobalVariables.KEY_PREF_MOBILE_NO, phoneNumber);
            saveStringData(AstrosageKundliApplication.getAppContext(), CGlobalVariables.KEY_PREF_COUNTRY_CODE, countryCode);
        } catch (Exception e) {
            e.printStackTrace();
        }
        return dataHash;
    }

