    /**
     * this method parse birth place from url
     *
     * @param data
     * @return BeanPlace
     */
    public static BeanPlace getUserBirthPlace(Uri data) {
        BeanPlace place = new BeanPlace();
        String timeZone = data.getQueryParameter("time-zone");
        String latDir = data.getQueryParameter("lat-dir");
        String longDir = data.getQueryParameter("long-dir");
        if (TextUtils.isEmpty(timeZone) || TextUtils.isEmpty(latDir) || TextUtils.isEmpty(longDir)) {
            return null;
        }
        place.setCityId(-1);
        place.setCityName(data.getQueryParameter("place"));

        place.setLatDeg(data.getQueryParameter("lat-deg"));
        place.setLatMin(data.getQueryParameter("lat-min"));
        place.setLatDir(latDir);

        place.setLongDeg(data.getQueryParameter("long-deg"));
        place.setLongMin(data.getQueryParameter("long-min"));
        place.setLongDir(longDir);

        place.setTimeZoneValue(Float.valueOf(timeZone));

        return place;
    }

    /**
     * this method parse birth date-time from url
     *
     * @param data
     * @return BeanDateTime
     */
    public static BeanDateTime getUserBirthDateTime(Uri data) {
        BeanDateTime beanDateTime = new BeanDateTime();
        beanDateTime.setYear(Integer.parseInt(data.getQueryParameter("year")));
        beanDateTime.setMonth(Integer.parseInt(data.getQueryParameter("month")) - 1);
        beanDateTime.setDay(Integer.parseInt(data.getQueryParameter("day")));

        beanDateTime.setHour(Integer.parseInt(data.getQueryParameter("hour")));
        beanDateTime.setMin(Integer.parseInt(data.getQueryParameter("minute")));
        beanDateTime.setSecond(Integer.parseInt(data.getQueryParameter("second")));

        return beanDateTime;
    }

