    public static void handleFabOnActivities(Context context, FloatingActionButton mFab, TextView navLive) {
        try {
            boolean liveAstroEnabledForAstrosageHomeScreen = CUtils.getBooleanData(context, CGlobalVariables.liveAstrologerEnabledForAstrosageHomeScreen, false);
            if (!liveAstroEnabledForAstrosageHomeScreen) {
                mFab.setBackgroundTintList(ColorStateList.valueOf(ContextCompat.getColor(context, R.color.white)));
                if (LANGUAGE_CODE == com.ojassoft.astrosage.utils.CGlobalVariables.TELUGU || LANGUAGE_CODE == com.ojassoft.astrosage.utils.CGlobalVariables.TAMIL ||
                        LANGUAGE_CODE == com.ojassoft.astrosage.utils.CGlobalVariables.KANNADA || LANGUAGE_CODE == com.ojassoft.astrosage.utils.CGlobalVariables.MALAYALAM) {
                    mFab.setImageDrawable(ContextCompat.getDrawable(context, R.drawable.ic_kundali));
                } else if (LANGUAGE_CODE == com.ojassoft.astrosage.utils.CGlobalVariables.BANGALI) {
                    mFab.setImageDrawable(ContextCompat.getDrawable(context, R.drawable.ic_kundali_east));
                } else {
                    mFab.setImageDrawable(ContextCompat.getDrawable(context, R.drawable.kundli_icon_96));
                }
                navLive.setText(context.getResources().getStringArray(R.array.kundliModulesList)[0]);
            } else {
                mFab.setColorFilter(ContextCompat.getColor(context, R.color.white), android.graphics.PorterDuff.Mode.MULTIPLY);
                mFab.setBackgroundTintList(ColorStateList.valueOf(ContextCompat.getColor(context, R.color.orange_color)));
                mFab.setImageDrawable(ContextCompat.getDrawable(context, R.drawable.ic_live_unmute_video));
                navLive.setText(context.getResources().getString(R.string.live));
            }
        } catch (Exception e) {
            //
        }

    }


    public static void postDumpDataToServer(final Activity activity, final String dumpDataString) {

        String orderUrl = "https://api2.astrosage.com/ac/astroshop/google-order-troubleshoot.asp";


        StringRequest stringRequest = new StringRequest(Request.Method.POST, orderUrl,
                new Response.Listener<String>() {
                    @Override
                    public void onResponse(String response) {
                        Log.e("postDumpData", "response=" + response);
                    }

                }

                , new Response.ErrorListener() {
            @Override
            public void onErrorResponse(VolleyError error) {
                Log.e("postDumpData", "error=" + error.toString());
            }
        }
        ) {
            @Override
            public String getBodyContentType() {
                return "application/x-www-form-urlencoded;charset=UTF-8";
            }

            /**
             * Passing some request headers
             * */
            @Override
            public Map<String, String> getParams() throws AuthFailureError {
                HashMap<String, String> headers = new HashMap<String, String>();
                headers.put("key", CUtils.getApplicationSignatureHashCode(activity));
                headers.put("DeviceId", CUtils.getMyAndroidId(activity));
                headers.put("DumpData", dumpDataString);

                //Log.e("postDumpData", "headers="+headers.toString());
                return headers;
            }

        };
        // Add the request to the RequestQueue.
        RequestQueue queue = VolleySingleton.getInstance(activity).getRequestQueue();
        int socketTimeout = 60000;//30 seconds - change to what you want
        RetryPolicy policy = new DefaultRetryPolicy(socketTimeout, DefaultRetryPolicy.DEFAULT_MAX_RETRIES, DefaultRetryPolicy.DEFAULT_BACKOFF_MULT);
        stringRequest.setRetryPolicy(policy);
        stringRequest.setShouldCache(false);
        queue.add(stringRequest);
    }

    public static boolean isDisplayNotification(Context context) {
        boolean displayNotification = false;
        try {
            int userChoice = LibCUtils.getUserChoiceFromSDCard(context);
            String savedDate = getStringData(context, "savedDate", "");
            int savedCount = getIntData(context, "notifyCount", 0);
            String currentDate = getCurrentDate();

            if (userChoice == LibCGlobalVariables.ONCE_IN_A_DAY) {
                if (!savedDate.equals(currentDate)) {
                    saveIntData(context, "notifyCount", 1);
                    saveStringData(context, "savedDate", currentDate);
                    displayNotification = true;
                }
            } else if (userChoice == LibCGlobalVariables.TWICE_IN_A_DAY) {
                if (savedDate.equals(currentDate)) {
                    if (savedCount == 1) {
                        saveIntData(context, "notifyCount", savedCount + 1);
                        displayNotification = true;
                    }
                } else {
                    saveIntData(context, "notifyCount", 1);
                    saveStringData(context, "savedDate", currentDate);
                    displayNotification = true;
                }
            } else if (userChoice == LibCGlobalVariables.AS_MANY_TIME_IT_COMES) {
                displayNotification = true;
            } else if (userChoice == LibCGlobalVariables.NEVER) {
                displayNotification = false;
            }
        } catch (Exception e) {
            displayNotification = true;
        }
        return displayNotification;
    }

    public static String getCurrentDate() {
        DateFormat dateFormat = new SimpleDateFormat("dd-MM-yyyy", Locale.ENGLISH);
        //get current date time with Date()
        //SimpleDateFormat dt = new SimpleDateFormat("MMM dd yyyy hh:mma");
        Date date = new Date();
        System.out.println(dateFormat.format(date));

        //get current date time with Calendar()
        Calendar cal = Calendar.getInstance();
        String currentDateTime = dateFormat.format(cal.getTime());
        return currentDateTime;
    }

