    public static boolean isAIChatDisplayed(Context context) {
        boolean isDisplayed = true;
        try {
            String aIChatSupportedLanguages = CUtils.getStringData(context, CGlobalVariables.AIChatSupportedLanguages, "");
            //Log.e("TestAI", "aIChatSupportedLanguages="+aIChatSupportedLanguages);
            int currentLanguage = getLanguageCode(context);
            if (!TextUtils.isEmpty(aIChatSupportedLanguages)) {
                String[] supportedLanguages = aIChatSupportedLanguages.split(",");
                for (String supportedLanguage : supportedLanguages) {
                    if (currentLanguage == Integer.parseInt(supportedLanguage)) {
                        isDisplayed = true;
                        break;
                    }
                }
            }
        } catch (Exception e) {
            Log.e("TestAI", "Exp=" + e);
        }
        return isDisplayed;
    }

