    public static boolean isNotDevanagari(String sentence) {
        for (char ch : sentence.toCharArray()) {
            Character.UnicodeBlock block = Character.UnicodeBlock.of(ch);

            // Check if the character belongs to Devanagari or Bengali (East Nagri)
            if (block == Character.UnicodeBlock.DEVANAGARI ||
                    block == Character.UnicodeBlock.BENGALI) {
                return false;  // Sentence contains Devanagari or East Nagri script
            }
        }
        return true;  // No Devanagari or East Nagri characters found
    }

    public static String changeToMinSec(long millis) {
        try {
            String ms = String.format("%02d:%02d",
                    TimeUnit.MILLISECONDS.toMinutes(millis),
                    TimeUnit.MILLISECONDS.toSeconds(millis) - TimeUnit.MINUTES.toSeconds(TimeUnit.MILLISECONDS.toMinutes(millis)));
            Log.d("TestChatRemainingTime", "changeToMinSec ===>>" + ms);
            return ms;
        } catch (Exception e) {
            return "00:00";
        }

    }

