    /**
     * this method is used to superscript + symbol from Kundli AI+ text.
     */
    public static SpannableString getKundliAIPlusSpannableText(Context context, String kundliAIPlusText) {
        SpannableString spannableString = new SpannableString(kundliAIPlusText);
        // Style "+"
        int plusIndex = kundliAIPlusText.indexOf("+");
        if (plusIndex != -1) {
            spannableString.setSpan(
                    new SuperscriptSpan(), // Superscript to position "+" above
                    plusIndex, plusIndex + 1,
                    Spannable.SPAN_EXCLUSIVE_EXCLUSIVE
            );
//            spannableString.setSpan(
//                    new RelativeSizeSpan(1f), // Make "+" slightly smaller
//                    plusIndex, plusIndex + 1,
//                    Spannable.SPAN_EXCLUSIVE_EXCLUSIVE
//            );
            spannableString.setSpan(
                    new ForegroundColorSpan(context.getColor(R.color.black)),
                    plusIndex, plusIndex + 1,
                    Spannable.SPAN_EXCLUSIVE_EXCLUSIVE
            );
        }
        return spannableString;
    }

    /**
     * This method take UserProfileData as @prams and parse as BeanHoroPersonalInfo objet
     */
    public static BeanHoroPersonalInfo getUserBirthDetailBean(UserProfileData userProfileData) {
        BeanHoroPersonalInfo beanHoroPersonalInfo = new BeanHoroPersonalInfo();
        beanHoroPersonalInfo.setName(userProfileData.getName());
        //birth place
        BeanPlace beanPlace = new BeanPlace();
        //beanPlace.setLatitude("25.78333");
        beanPlace.setLatDeg(userProfileData.getLatdeg());
        beanPlace.setLatMin(userProfileData.getLatmin());
        beanPlace.setLatDir(userProfileData.getLatns());
        //beanPlace.setLongitude("84.66667");
        beanPlace.setLongDeg(userProfileData.getLongdeg());
        beanPlace.setLongMin(userProfileData.getLongmin());
        beanPlace.setLongDir(userProfileData.getLongew());
        //beanPlace.setTimeZone(userProfileData.getTimezone());
        if (!TextUtils.isEmpty(userProfileData.getTimezone())) {
            beanPlace.setTimeZoneValue(Float.parseFloat(userProfileData.getTimezone()));
        }
        //beanPlace.setTimeZoneName("GMT+5.5");
        beanPlace.setCountryId(-1);
        beanPlace.setCityId(-1);
        beanPlace.setTimeZoneId(-1);
        String userPlace = userProfileData.getPlace();
        if (!TextUtils.isEmpty(userPlace)) {
            String[] placeArr = userPlace.split(",");
            if (placeArr.length == 1) {
                beanPlace.setCityName(userPlace);
            } else if (placeArr.length >= 2) {
                beanPlace.setCityName(placeArr[0]);
                beanPlace.setState(placeArr[1]);
            }
        }
        beanHoroPersonalInfo.setPlace(beanPlace);

        //birth date and time
        BeanDateTime beanDateTime = new BeanDateTime();
        beanDateTime.setDay(Integer.parseInt(userProfileData.getDay()));
        beanDateTime.setMonth(Integer.parseInt(userProfileData.getMonth()) - 1);
        beanDateTime.setYear(Integer.parseInt(userProfileData.getYear()));
        beanDateTime.setHour(Integer.parseInt(userProfileData.getHour()));
        beanDateTime.setMin(Integer.parseInt(userProfileData.getMinute()));
        beanDateTime.setSecond(Integer.parseInt(userProfileData.getSecond()));
        beanHoroPersonalInfo.setDateTime(beanDateTime);
        //gender
        beanHoroPersonalInfo.setGender(userProfileData.getGender());
        //Extras
        beanHoroPersonalInfo.setHoraryNumber(0);
        beanHoroPersonalInfo.setAyanIndex(0);
        beanHoroPersonalInfo.setDST(0);

        return beanHoroPersonalInfo;
    }


    public static UserProfileData getUserProfileObjFromUserKundliData(BeanHoroPersonalInfo beanHoroPersonalInfo) {
        try {
            BeanDateTime beanDateTime = beanHoroPersonalInfo.getDateTime();
            BeanPlace beanPlace = beanHoroPersonalInfo.getPlace();

            UserProfileData userProfileData = new UserProfileData();

            userProfileData.setName(beanHoroPersonalInfo.getName());
            userProfileData.setGender(beanHoroPersonalInfo.getGender());

            userProfileData.setDay(String.valueOf(beanDateTime.getDay()));
            userProfileData.setMonth(String.valueOf(beanDateTime.getMonth() + 1));
            userProfileData.setYear(String.valueOf(beanDateTime.getYear()));
            userProfileData.setHour(String.valueOf(beanDateTime.getHour()));
            userProfileData.setMinute(String.valueOf(beanDateTime.getMin()));
            userProfileData.setSecond(String.valueOf(beanDateTime.getSecond()));
            userProfileData.setOccupation("");
            userProfileData.setMaritalStatus("");

            String place = beanPlace.getCityName();
            if (beanPlace.getState() != null && !beanPlace.getState().trim().isEmpty()) {
                if (!place.contains(",")) {
                    place = place + ", " + beanPlace.getState();
                }
            }

            userProfileData.setPlace(place);
            userProfileData.setLongdeg(beanPlace.getLongDeg());
            userProfileData.setLongmin(beanPlace.getLongMin());
            userProfileData.setLongew(beanPlace.getLongDir());
            userProfileData.setLatdeg(beanPlace.getLatDeg());
            userProfileData.setLatmin(beanPlace.getLatMin());
            userProfileData.setLatns(beanPlace.getLatDir());
            userProfileData.setTimezone(beanPlace.getTimeZoneValue() + "");
            return userProfileData;
        } catch (Exception e) {
            return null;
        }
    }

    public static String addParamsForDarkInURL(Context context, String url) {
        int nightModeFlags = context.getResources().getConfiguration().uiMode & Configuration.UI_MODE_NIGHT_MASK;

        if (nightModeFlags == Configuration.UI_MODE_NIGHT_YES) {
            url = url + "?data-theme-mode=dark";
        } else if (nightModeFlags == Configuration.UI_MODE_NIGHT_NO) {
            url = url + "?data-theme-mode=light";
        }
        return url;
    }

