    /**
     * Fetches the remaining PDF report count for the current user from the server.
     * <p>
     * This method makes an asynchronous network call to retrieve the number of PDF reports
     * the user can still generate/download, based on their plan and credentials. It handles
     * both success and error responses, including the specific error: {"status":"error","message":"Invalid user credentials"}.
     *
     * @param context                  The context used to access user credentials and app info.
     * @param pdfCountResponseListener Callback interface to receive the result or error.
     * @author Gaurav kumar Das
     */
    public static void getRemainingReportCountFromServer(Context context, PdfCountResponseListener pdfCountResponseListener) {
        ApiList api = RetrofitClient.getInstance().create(ApiList.class);
        Call<ResponseBody> call = api.getRemainingReportCount(CGlobalVariables.REMAINING_REPORT_COUNT_URL, getRemainingReportCountParams(context));
        call.enqueue(new Callback<ResponseBody>() {
            @Override
            public void onResponse(Call<ResponseBody> call, retrofit2.Response<ResponseBody> response) {
                try {
                    if (response.isSuccessful() && response.body() != null) {
                        String respString = response.body().string();
                        JSONObject json = new JSONObject(respString);
                        // Handle error response: {"status":"error","message":"Invalid user credentials"}
                        if (json.has("status") && json.getString("status").equals("error")) {
                            pdfCountResponseListener.onPdfCountError();
                            return;
                        }
                        if (json.has("remainingCount")) {
                            int remainingCount = json.getInt("remainingCount");
                            pdfCountResponseListener.onPdfCountReceived(remainingCount);
                        } else {
                            // If no remainingCount field, treat as error
                            pdfCountResponseListener.onPdfCountError();
                        }
                    } else {
                        pdfCountResponseListener.onPdfCountError();
                    }
                } catch (Exception e) {
                    pdfCountResponseListener.onPdfCountError();
                }
            }

            @Override
            public void onFailure(Call<ResponseBody> call, Throwable throwable) {
                pdfCountResponseListener.onPdfCountError();
            }
        });
    }

    /**
     * Constructs the parameters required for the remaining report count API call.
     * <p>
     * Includes user ID, plan ID, password, API key, device ID, package name, and app version.
     * User ID and password are encoded for security.
     *
     * @param context The context used to access user and app information.
     * @return A map of parameters for the API request.
     * @author Gaurav kumar Das
     */
    private static Map<String, String> getRemainingReportCountParams(Context context) {
        HashMap<String, String> params = new HashMap<>();
        params.put(KEY_USER_ID, replaceEmailChar(CUtils.getUserName(context)));
        params.put(CGlobalVariables.KEY_PLAN_ID, String.valueOf(CUtils.getUserPurchasedPlanFromPreference(context)));
        params.put(KEY_PASSWORD, replaceEmailChar(CUtils.getUserPassword(context)));
        params.put(com.ojassoft.astrosage.varta.utils.CGlobalVariables.KEY_API, com.ojassoft.astrosage.varta.utils.CUtils.getApplicationSignatureHashCode(context));
        params.put(DEVICE_ID, com.ojassoft.astrosage.varta.utils.CUtils.getMyAndroidId(context));
        params.put(com.ojassoft.astrosage.varta.utils.CGlobalVariables.PACKAGE_NAME, BuildConfig.APPLICATION_ID);
        params.put(com.ojassoft.astrosage.varta.utils.CGlobalVariables.PROPERTY_APP_VERSION, BuildConfig.VERSION_NAME);

        return params;
    }

    /**
     * Listener interface for receiving the result of the PDF count API call.
     * Implement this interface to handle both success and error cases.
     *
     * @author Gaurav kumar Das
     */
    public interface PdfCountResponseListener {
        /**
         * Called when the remaining PDF count is successfully retrieved.
         *
         * @param count The number of remaining PDF reports for the user.
         */
        void onPdfCountReceived(int count);

        /**
         * Called when there is an error retrieving the PDF count (network, server, or credentials).
         */
        void onPdfCountError();
    }

