    /**
     * Fetches the latitude, longitude, and city from the user's IP address using the ipinfo.io service.
     * Saves the retrieved data in shared preferences for later use.
     *
     * @param context The context used to access shared preferences and initiate network requests.
     */
    public static void getLatLangCityFromIPDetails(Context context) {
        String url = "https://ipinfo.io/json";
        StringRequest stringRequest = new StringRequest(Request.Method.GET, url,
                new Response.Listener<String>() {
                    @Override
                    public void onResponse(String response) {
                        try {
                            JSONObject jsonObject = new JSONObject(response);
                            String loc = jsonObject.optString("loc");
                            if (!TextUtils.isEmpty(loc)) {
                                String[] latLong = loc.split(",");
                                if (latLong.length == 2) {
                                    CUtils.saveStringData(context, CGlobalVariables.KEY_LATITUDE, latLong[0]);
                                    CUtils.saveStringData(context, CGlobalVariables.KEY_LONGITUDE, latLong[1]);
                                    //Log.d("testcity", "latLong[0]: " + latLong[0]);
                                    //Log.d("testcity", "latLong[1]: " + latLong[1]);
                                }
                            }
                            String city = jsonObject.optString("city");
                            if (!TextUtils.isEmpty(city)) {
                                //Log.d("testcity", "city: " + city);
                                CUtils.saveStringData(context, CGlobalVariables.KEY_CITY, city);
                            }
                        } catch (Exception e) {
                            e.printStackTrace();
                        }
                    }
                },
                new Response.ErrorListener() {
                    @Override
                    public void onErrorResponse(VolleyError error) {

                    }
                });

        // Add the request to the RequestQueue.
        RequestQueue queue = VolleySingleton.getInstance(context).getRequestQueue();
        int socketTimeout = 60000;//30 seconds - change to what you want
        RetryPolicy policy = new DefaultRetryPolicy(socketTimeout, DefaultRetryPolicy.DEFAULT_MAX_RETRIES, DefaultRetryPolicy.DEFAULT_BACKOFF_MULT);
        stringRequest.setRetryPolicy(policy);
        stringRequest.setShouldCache(false);
        queue.add(stringRequest);
    }


    /**
     * Applies edge-to-edge insets to the activity's decor view.
     * This method sets up a listener to adjust padding based on system bars and IME visibility.
     * On Android 11 (API 30) and above, it considers both system bars and IME insets,
     * using the larger of the two for the bottom padding to accommodate the keyboard.
     * For versions below Android 11, it falls back to using system window insets,
     * relying on `adjustResize` for IME handling.
     * Any exceptions during this process are caught and ignored to prevent crashes.
     */
    public static void applyEdgeToEdgeInsets(Activity activity) {
        try {
            // Tell the system that this Activity will handle fitting system windows manually
            // (status bar, nav bar, keyboard) instead of letting the system do it
            WindowCompat.setDecorFitsSystemWindows(activity.getWindow(), false);

            ViewCompat.setOnApplyWindowInsetsListener(
                    activity.getWindow().getDecorView(),
                    (v, insets) -> {
                        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
                            // Android 11+ (API 30+)
                            Insets systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars());
                            Insets ime = insets.getInsets(WindowInsetsCompat.Type.ime());

                            // If keyboard is visible, use its bottom inset
                            int bottomInset = Math.max(systemBars.bottom, ime.bottom);

                            v.setPadding(
                                    systemBars.left,
                                    systemBars.top,
                                    systemBars.right,
                                    bottomInset
                            );
                        } else {
                            // Fallback for API < 30
                            android.view.WindowInsets systemInsets = insets.toWindowInsets();
                            if (systemInsets != null) {
                                int bottomInset = systemInsets.getSystemWindowInsetBottom();

                                // On <30, WindowInsets does not distinguish IME, so rely on adjustResize
                                v.setPadding(
                                        systemInsets.getSystemWindowInsetLeft(),
                                        systemInsets.getSystemWindowInsetTop(),
                                        systemInsets.getSystemWindowInsetRight(),
                                        bottomInset
                                );
                            }
                        }
                        return insets;
                    }
            );

            // Set status bar color
            activity.getWindow().setStatusBarColor(ContextCompat.getColor(activity, R.color.toolbarBGColor));

            // Set navigation bar color// Set navigation bar color
            activity.getWindow().setNavigationBarColor(ContextCompat.getColor(activity, R.color.toolbarBGColor));
        } catch (Exception e) {
            //
        }
    }

