    public static boolean canShowInterstitial(Context context) {
        long lastTime = CUtils.getLongData(context, CGlobalVariables.INTERSTITIAL_SESSION_TIME, 0);
        long currentTime = System.currentTimeMillis();
        long diff = currentTime - lastTime;
        return diff >= 120000; // 2 minutes
    }


    /**
     * Calculates the user's Kundli (birth chart) in a background thread.
     * This method takes the user's birth details and uses the {@link CalculateKundli} class
     * to perform the astrological calculations. The calculation is done on a separate thread
     * to avoid blocking the main UI thread.
     *
     * @param context              The context of the application.
     * @param beanHoroPersonalInfo An object containing the user's birth details.
     */
    public static void calculateKundli(Activity context, BeanHoroPersonalInfo beanHoroPersonalInfo) {
        Typeface regularTypeface = com.ojassoft.astrosage.utils.CUtils.getRobotoFont(context, LANGUAGE_CODE, com.ojassoft.astrosage.utils.CGlobalVariables.regular);
        ExecutorService executor = Executors.newSingleThreadExecutor();
        executor.execute(() -> {
            try {
                CGlobal.getCGlobalObject().setHoroPersonalInfoObject(beanHoroPersonalInfo);

                CalculateKundli kundli = new CalculateKundli(beanHoroPersonalInfo, false, context, regularTypeface, com.ojassoft.astrosage.utils.CGlobalVariables.MODULE_BASIC, com.ojassoft.astrosage.utils.CGlobalVariables.HOME_INPUT_SCREEN, false, 0, 0, 0);
                kundli.calculate();
                Log.e("CreateKundli", "calculateKundli done");
            } catch (Exception e) {
                Log.e("CreateKundli", "calculateKundli Exception=" + e);
            }
        });
    }

