    /**
     * Saves the Kundli synced status for a specific user ID in shared preferences.
     *
     * @param context  The application context.
     * @param userId   The unique identifier for the user.
     * @param isSynced The synced status to save (true if synced, false otherwise).
     */
    public static void saveKundliSyncedStatus(Context context, String userId, boolean isSynced) {
        //Log.e("TestSyncChart", "saveKundliSyncedStatus: userId= "+userId);
        try {
            if(getKundliSyncedStatus(context,userId)){
                //Log.e("TestSyncChart", "saveKundliSyncedStatus: return as same status ");
                return;
            }

            SharedPreferences sharedPreferences = context.getSharedPreferences(com.ojassoft.astrosage.varta.utils.CGlobalVariables.APP_PREFS_SYNC_KUNDLI_STATUS_DATA, MODE_PRIVATE);
            String kundliSyncData = sharedPreferences.getString(com.ojassoft.astrosage.varta.utils.CGlobalVariables.KUNDLI_SYNC_DATA, "");

            JSONObject jsonObject;
            if (TextUtils.isEmpty(kundliSyncData)) {
                jsonObject = new JSONObject();
            } else {
                jsonObject = new JSONObject(kundliSyncData);
            }
            jsonObject.put(userId, isSynced);

            SharedPreferences.Editor sharedPrefEditor = sharedPreferences.edit();
            sharedPrefEditor.putString(com.ojassoft.astrosage.varta.utils.CGlobalVariables.KUNDLI_SYNC_DATA, jsonObject.toString());
            sharedPrefEditor.apply();
        } catch (Exception e) {
            //
        }
    }

    /**
     * Retrieves the synced status for a specific user ID from shared preferences.
     *
     * @param context The application context.
     * @param userId  The unique identifier for the user.
     * @return The synced status (true if synced, false otherwise).
     */
    public static boolean getKundliSyncedStatus(Context context, String userId) {
        //Log.e("TestSyncChart", "getKundliSyncedStatus: userId= "+userId);
        boolean isSynced = false;
        try {
            SharedPreferences sharedPreferences = context.getSharedPreferences(com.ojassoft.astrosage.varta.utils.CGlobalVariables.APP_PREFS_SYNC_KUNDLI_STATUS_DATA, MODE_PRIVATE);
            String kundliSyncData = sharedPreferences.getString(com.ojassoft.astrosage.varta.utils.CGlobalVariables.KUNDLI_SYNC_DATA, "");

            JSONObject jsonObject;
            if (!TextUtils.isEmpty(kundliSyncData)) {
                jsonObject = new JSONObject(kundliSyncData);
                isSynced = jsonObject.optBoolean(userId);
            }
        } catch (Exception e) {
            //
        }
        //Log.e("TestSyncChart", "getKundliSyncedStatus: isSynced= "+isSynced);
        return isSynced;
    }

    /**
     * Initiates the synchronization of the user's Kundli (birth chart) data with the cloud server.
     * This method checks if the user is logged in, whether auto-sync is enabled from tagmanager,
     * and if there is an active internet connection before starting the sync service.
     * If the sync service is already running, it logs a message instead of starting a new one.
     *
     * @param context    The application context.
     * @param isAutoSync A boolean indicating whether the sync is automatic or manual.
     */
    public static void syncChartWithCloud(Context context, boolean isAutoSync) {
        try {
            if (CUtils.isUserLogedIn(context)) {
                if (isAutoSync) {// for auto sync check kundli already synced or not
                    boolean isAutoSyncChartEnabled = CUtils.getBooleanData(context, CGlobalVariables.IS_AUTO_SYNC_CHART_ENABLED, false);
                    //Log.e("TestSyncChart", "syncChartWithCloud: isAutoSyncChartEnabled = "+isAutoSyncChartEnabled);
                    if(!isAutoSyncChartEnabled) return;// in case of desabled from tagmanager then return
                    boolean isSynced = CUtils.getKundliSyncedStatus(context, CUtils.getUserName(context));
                    if (isSynced) return;
                }
                if (CUtils.isConnectedWithInternet(context)) {
                    if (!isSyncKundliServiceRunning(context)) {
                        //Log.e("TestSyncChart", "syncChartWithCloud: service called ");
                        Intent intent = new Intent(context, SyncKundliService.class);
                        intent.putExtra("isAutoSync", isAutoSync);
                        context.startService(intent);

                        if (isAutoSync) {
                            CUtils.fcmAnalyticsEvents(CGlobalVariables.GOOGLE_ANALYTIC_AUTO_SYNC_CHART, CGlobalVariables.GOOGLE_ANALYTIC_EVENT_AUTO_SYNC, "");
                        } else {
                            CUtils.fcmAnalyticsEvents(CGlobalVariables.GOOGLE_ANALYTIC_SYNC_CHART, CGlobalVariables.FIREBASE_EVENT_ITEM_CLICK, "");
                        }
                    } else {
                        Log.e("TestSyncChart", "MyServiceRunning");
                    }

                } else {
                    Toast.makeText(context, context.getResources().getString(R.string.internet_is_not_working), Toast.LENGTH_SHORT).show();
                }
            }
        } catch (Exception e) {
            //
        }
    }

    public static boolean isSyncKundliServiceRunning(Context context) {
        try {
            ActivityManager manager = (ActivityManager) context.getSystemService(ACTIVITY_SERVICE);
            for (ActivityManager.RunningServiceInfo service : manager.getRunningServices(Integer.MAX_VALUE)) {
                if ("com.ojassoft.astrosage.misc.SyncKundliService".equals(service.service.getClassName())) {
                    return true;
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
        return false;
    }


