    /**
     * Constructs a complete URL string with query parameters from a map.
     * This is useful for logging POST requests as if they were GET requests.
     *
     * @param baseUrl The base URL without any query parameters.
     * @param params  A map of key-value pairs representing the parameters.
     * @return A URL string with parameters appended (e.g., http://example.com?key1=val1&key2=val2).
     */
    public static String buildUrlWithParams(String baseUrl, Map<String, String> params) {
        if (params == null || params.isEmpty()) {
            return baseUrl;
        }

        StringBuilder urlBuilder = new StringBuilder(baseUrl);
        // Add a question mark only if the base URL doesn't already have one
        if (!baseUrl.contains("?")) {
            urlBuilder.append("?");
        }

        boolean firstParam = true;
        for (Map.Entry<String, String> entry : params.entrySet()) {
            if (!firstParam) {
                urlBuilder.append("&");
            }
            try {
                // Encode both the key and the value to handle special characters safely
                urlBuilder.append(URLEncoder.encode(entry.getKey(), "UTF-8"));
                urlBuilder.append("=");
                urlBuilder.append(URLEncoder.encode(entry.getValue(), "UTF-8"));
            } catch (UnsupportedEncodingException e) {
                // This should not happen with "UTF-8"
                e.printStackTrace();
            }
            firstParam = false;
        }

        return urlBuilder.toString();
    }


